INSERT INTO documentation_files VALUES(1,'Document P. Ponorul Suspendat #1','Plan de explorare - obiectiv 90. Am identificat 471 galerii laterale neexplorate. Lungimea estimata: 132 metri pe fiecare. Sunt necesare 90 zile de explorare. Echipa recomandata: 71 persoane. Echipament vertical necesar pentru 30 puturi. Am pregatit 348 kilograme de echipament. Rezerva de carbid: 7 kilograme. Punctul de plecare este statia topografica 2. Comunicarea radio va fi testata la 56 puncte. Am obtinut 176 autorizatii necesare. Data planificata: peste 487 saptamani. Bugetul estimat: 137 lei.','doc_existing_c1_1.txt',504,NULL,'text_document',1775820082,NULL,NULL);
