INSERT INTO documentation_files VALUES(20,'Document P. Ponorul Nou #1','Raport conservare patrimoniu - obiectiv 86. Am evaluat starea a 103 inscriptii istorice. Dintre acestea, 137 necesita interventie urgenta. Am curatat 444 metri patrati de graffiti modern. Am instalat 39 panouri informative la intrare. Bariera de protectie acopera 133 metri liniari. Am documentat 407 urme de vandalism. Raportul a fost transmis autoritatilor locale in 317 exemplare. Am propus clasificarea a 351 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 262 persoane simultan. Am instruit 223 ghizi locali. Costul estimat al lucrarilor: 356 lei. Termenul de finalizare: 194 luni.','doc_existing_c2_1.txt',604,NULL,'text_document',1775820082,NULL,NULL);
INSERT INTO documentation_files VALUES(21,'Document P. Ponorul Nou #2','Raport formare speologica - curs nr. 251. Am instruit 196 cursanti. Durata cursului: 308 zile. Am efectuat 316 sesiuni practice in pestera. Fiecare cursant a parcurs 202 metri de galerie. Am acoperit 174 module teoretice. Examenul final a fost promovat de 50 participanti. Am distribuit 71 seturi de echipament pentru practica. Feedback-ul mediu: 32 din 10. Urmatorul curs incepe in 181 saptamani.','doc_existing_c2_2.txt',397,NULL,'text_document',1775820082,NULL,NULL);
INSERT INTO documentation_files VALUES(22,'Document P. Ponorul Nou #3','Raport conservare patrimoniu - obiectiv 269. Am evaluat starea a 89 inscriptii istorice. Dintre acestea, 269 necesita interventie urgenta. Am curatat 191 metri patrati de graffiti modern. Am instalat 180 panouri informative la intrare. Bariera de protectie acopera 68 metri liniari. Am documentat 387 urme de vandalism. Raportul a fost transmis autoritatilor locale in 271 exemplare. Am propus clasificarea a 201 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 227 persoane simultan. Am instruit 333 ghizi locali. Costul estimat al lucrarilor: 155 lei. Termenul de finalizare: 327 luni.','doc_existing_c2_3.txt',604,NULL,'text_document',1775820082,NULL,NULL);
INSERT INTO documentation_files VALUES(23,'Document P. Ponorul Nou #4','Inventar echipament - depozit subteran 152. Total corzi disponibile: 180 metri. Dintre acestea, 281 metri necesita inlocuire. Am verificat 360 carabiniere si 9 plachete. Corzi statice diametru 10mm: 143 bucati. Am adaugat 111 saci de transport noi. Lampi de rezerva: 23 bucati cu baterii pline. Stocul de carbid: 282 kilograme. Truse de prim ajutor: 12 complete, verificate. Echipamentul este depozitat la 20 metri de intrare. Urmatoarea verificare programata peste 272 saptamani. Am retras din uz 481 echipamente expirate. Bugetul anual de echipament: 268 lei.','doc_existing_c2_4.txt',561,NULL,'text_document',1775820082,NULL,NULL);
INSERT INTO documentation_files VALUES(24,'Document P. Ponorul Nou #5','Raport climatologic subteran - statia 156. Senzorul a inregistrat 36 cicluri complete de temperatura. Temperatura medie anuala: 94 grade Celsius. Amplitudinea termica maxima: 431 grade. Umiditatea relativa medie: 381 procente. Concentratia de CO2: 188 ppm. Curentul de aer maxim masurat: 232 metri pe secunda. Directia predominanta a curentului: sector 411. Datalogerul a functionat 126 zile fara intrerupere. Am descarcat 468 megabytes de date brute. Presiunea barometrica la intrare: 51 mbar. Evaporarea masurata: 8 milimetri pe luna. Am comparat datele cu 88 statii meteorologice de suprafata. Raportul complet include 180 grafice si tabele. Monitorizarea continua de 264 luni confirma stabilitatea climatica.','doc_existing_c2_5.txt',712,NULL,'text_document',1775820082,NULL,NULL);
