INSERT INTO documentation_files VALUES(51,'Document PeÈ™tera AscendentÄƒ din Guguiova #8','Observatii topografice - tura nr. 34. Am efectuat 43 vizari cu busola si clinometrul. Lungimea poligonalei este de 424 metri. Diferenta de nivel totala: 29 metri. Am folosit statia nr. 294 ca baza. Eroarea de inchidere a poligonalei a fost sub 500 procente. Galeria prezinta un azimut predominant de 214 grade. Panta medie a galeriei este de 69 grade. Latimea variaza intre 443 si aproximativ dublu. Inaltimea maxima a sectiunii este de 41 metri. Am setat 349 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 180. Estimare galerie nemasurata: 273 metri. Am notat 299 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:246. Informam administratia ariei protejate despre descoperirea de la sectorul 484.','doc_existing_c4_8.txt',748,NULL,'text_document',1775820083,NULL,NULL);
