INSERT INTO documentation_files VALUES(54,'Document PeÈ™tera AscendentÄƒ din Guguiova #11','Raport climatologic subteran - statia 421. Senzorul a inregistrat 469 cicluri complete de temperatura. Temperatura medie anuala: 398 grade Celsius. Amplitudinea termica maxima: 81 grade. Umiditatea relativa medie: 149 procente. Concentratia de CO2: 203 ppm. Curentul de aer maxim masurat: 341 metri pe secunda. Directia predominanta a curentului: sector 165. Datalogerul a functionat 441 zile fara intrerupere. Am descarcat 302 megabytes de date brute. Presiunea barometrica la intrare: 401 mbar. Evaporarea masurata: 124 milimetri pe luna. Am comparat datele cu 113 statii meteorologice de suprafata. Raportul complet include 44 grafice si tabele. Monitorizarea continua de 91 luni confirma stabilitatea climatica.','doc_existing_c4_11.txt',715,NULL,'text_document',1775820083,NULL,NULL);
