INSERT INTO documentation_files VALUES(110,'Document PeÈ™tera B1 din Piatra Lupului #1','Raport conservare patrimoniu - obiectiv 44. Am evaluat starea a 150 inscriptii istorice. Dintre acestea, 445 necesita interventie urgenta. Am curatat 249 metri patrati de graffiti modern. Am instalat 352 panouri informative la intrare. Bariera de protectie acopera 234 metri liniari. Am documentat 17 urme de vandalism. Raportul a fost transmis autoritatilor locale in 464 exemplare. Am propus clasificarea a 12 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 159 persoane simultan. Am instruit 278 ghizi locali. Costul estimat al lucrarilor: 191 lei. Termenul de finalizare: 360 luni.','doc_existing_c7_1.txt',603,NULL,'text_document',1775820083,NULL,NULL);
