INSERT INTO documentation_files VALUES(112,'Document PeÈ™tera B1 din Piatra Lupului #3','Raport conservare patrimoniu - obiectiv 460. Am evaluat starea a 368 inscriptii istorice. Dintre acestea, 347 necesita interventie urgenta. Am curatat 135 metri patrati de graffiti modern. Am instalat 394 panouri informative la intrare. Bariera de protectie acopera 255 metri liniari. Am documentat 254 urme de vandalism. Raportul a fost transmis autoritatilor locale in 225 exemplare. Am propus clasificarea a 4 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 111 persoane simultan. Am instruit 423 ghizi locali. Costul estimat al lucrarilor: 449 lei. Termenul de finalizare: 31 luni.','doc_existing_c7_3.txt',603,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(113,'Document PeÈ™tera B1 din Piatra Lupului #4','Jurnal de expeditie subterana - ziua 378. Am intrat in pestera la ora 357. Parcursul pana la tabara subterana a durat 274 ore. Am transportat 481 kilograme de echipament. La tabara temperatura era de 163 grade. Am montat 241 corturi in sala mare. Rezerva de apa potabila este de 338 litri. Am planificat 105 obiective de explorat. Primul obiectiv se afla la 226 metri de tabara. Comunicarea radio functioneaza pe o distanta de 9 metri. Am verificat starea corzilor pe 268 puturi. Am acumulat 77 ore de topografie. Fotodocumentarea a produs 394 imagini RAW. Urmatoarea tura de explorare incepe in 70 ore. Echipa este formata acum din 46 persoane active. Atmosfera din galeria inferioara contine 339 procente CO2. Am stabilit o limita de siguranta la 339 metri distanta. Stocul de baterii este suficient pentru 465 ore de functionare. Moralul echipei este excelent dupa 92 zile sub pamant.','doc_existing_c7_4.txt',887,NULL,'text_document',1775820083,NULL,NULL);
