INSERT INTO documentation_files VALUES(116,'Document PeÈ™tera B2 din Piatra Lupului #1','Observatii topografice - tura nr. 254. Am efectuat 314 vizari cu busola si clinometrul. Lungimea poligonalei este de 12 metri. Diferenta de nivel totala: 75 metri. Am folosit statia nr. 281 ca baza. Eroarea de inchidere a poligonalei a fost sub 169 procente. Galeria prezinta un azimut predominant de 397 grade. Panta medie a galeriei este de 283 grade. Latimea variaza intre 272 si aproximativ dublu. Inaltimea maxima a sectiunii este de 7 metri. Am setat 55 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 318. Estimare galerie nemasurata: 458 metri. Am notat 486 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:256. Informam administratia ariei protejate despre descoperirea de la sectorul 325.','doc_existing_c8_1.txt',748,NULL,'text_document',1775820083,NULL,NULL);
