INSERT INTO documentation_files VALUES(145,'Document PeÈ™tera B3 din Piatra Lupului #5','Plan de explorare - obiectiv 147. Am identificat 384 galerii laterale neexplorate. Lungimea estimata: 435 metri pe fiecare. Sunt necesare 172 zile de explorare. Echipa recomandata: 378 persoane. Echipament vertical necesar pentru 353 puturi. Am pregatit 354 kilograme de echipament. Rezerva de carbid: 267 kilograme. Punctul de plecare este statia topografica 152. Comunicarea radio va fi testata la 461 puncte. Am obtinut 420 autorizatii necesare. Data planificata: peste 272 saptamani. Bugetul estimat: 492 lei.','doc_existing_c9_5.txt',513,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(146,'Document PeÈ™tera B3 din Piatra Lupului #6','Observatii topografice - tura nr. 91. Am efectuat 156 vizari cu busola si clinometrul. Lungimea poligonalei este de 403 metri. Diferenta de nivel totala: 37 metri. Am folosit statia nr. 141 ca baza. Eroarea de inchidere a poligonalei a fost sub 471 procente. Galeria prezinta un azimut predominant de 362 grade. Panta medie a galeriei este de 499 grade. Latimea variaza intre 188 si aproximativ dublu. Inaltimea maxima a sectiunii este de 227 metri. Am setat 289 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 368. Estimare galerie nemasurata: 209 metri. Am notat 175 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:328. Informam administratia ariei protejate despre descoperirea de la sectorul 116.','doc_existing_c9_6.txt',751,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(147,'Document PeÈ™tera B3 din Piatra Lupului #7','Raport climatologic subteran - statia 269. Senzorul a inregistrat 174 cicluri complete de temperatura. Temperatura medie anuala: 295 grade Celsius. Amplitudinea termica maxima: 490 grade. Umiditatea relativa medie: 70 procente. Concentratia de CO2: 249 ppm. Curentul de aer maxim masurat: 334 metri pe secunda. Directia predominanta a curentului: sector 459. Datalogerul a functionat 22 zile fara intrerupere. Am descarcat 35 megabytes de date brute. Presiunea barometrica la intrare: 41 mbar. Evaporarea masurata: 386 milimetri pe luna. Am comparat datele cu 140 statii meteorologice de suprafata. Raportul complet include 291 grafice si tabele. Monitorizarea continua de 405 luni confirma stabilitatea climatica.','doc_existing_c9_7.txt',714,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(148,'Document PeÈ™tera B3 din Piatra Lupului #8','Observatii topografice - tura nr. 379. Am efectuat 436 vizari cu busola si clinometrul. Lungimea poligonalei este de 483 metri. Diferenta de nivel totala: 150 metri. Am folosit statia nr. 228 ca baza. Eroarea de inchidere a poligonalei a fost sub 448 procente. Galeria prezinta un azimut predominant de 305 grade. Panta medie a galeriei este de 263 grade. Latimea variaza intre 459 si aproximativ dublu. Inaltimea maxima a sectiunii este de 130 metri. Am setat 386 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 458. Estimare galerie nemasurata: 52 metri. Am notat 396 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:46. Informam administratia ariei protejate despre descoperirea de la sectorul 304.','doc_existing_c9_8.txt',751,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(149,'Document PeÈ™tera B3 din Piatra Lupului #9','Inventar echipament - depozit subteran 342. Total corzi disponibile: 442 metri. Dintre acestea, 289 metri necesita inlocuire. Am verificat 23 carabiniere si 441 plachete. Corzi statice diametru 10mm: 360 bucati. Am adaugat 207 saci de transport noi. Lampi de rezerva: 19 bucati cu baterii pline. Stocul de carbid: 325 kilograme. Truse de prim ajutor: 64 complete, verificate. Echipamentul este depozitat la 438 metri de intrare. Urmatoarea verificare programata peste 180 saptamani. Am retras din uz 222 echipamente expirate. Bugetul anual de echipament: 164 lei.','doc_existing_c9_9.txt',563,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(150,'Document PeÈ™tera B3 din Piatra Lupului #10','Fisa tehnica echipare put - verticala nr. 402. Adancimea: 136 metri. Am instalat 73 spituri din otel inoxidabil. Distanta intre spituri: 310 metri. Lungimea corzii principale: 474 metri. Coarda de siguranta: 235 metri. Am montat 272 protectoare de franghie. Fractionarea se face la 65 metri de buza putului. Deviatia este la 10 metri sub fractionare. Am testat echiparea cu 284 coborari. Ultimul control al spiturilor: acum 78 luni.','doc_existing_c9_10.txt',432,NULL,'text_document',1775820083,NULL,NULL);
