INSERT INTO documentation_files VALUES(163,'Document PeÈ™tera B4 din Piatra Lupului #1','Registru vizitatori - luna 27. Total vizitatori inregistrati: 266. Dintre acestia, 36 au participat la ture ghidate. Am organizat 3 ture pentru grupuri scolare. Media participantilor per tura: 17 persoane. Am distribuit 307 pliante informative. Am colectat 285 chestionare de feedback. Nota medie acordata: 88 din 10. Am inregistrat 306 incidente minore. Veniturile din taxe: 345 lei. Am angajat 4 ghizi suplimentari. Programul de vizitare a fost extins cu 52 ore pe saptamana.','doc_existing_c10_1.txt',477,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(164,'Document PeÈ™tera B4 din Piatra Lupului #2','Raport climatologic subteran - statia 71. Senzorul a inregistrat 194 cicluri complete de temperatura. Temperatura medie anuala: 445 grade Celsius. Amplitudinea termica maxima: 490 grade. Umiditatea relativa medie: 314 procente. Concentratia de CO2: 364 ppm. Curentul de aer maxim masurat: 147 metri pe secunda. Directia predominanta a curentului: sector 392. Datalogerul a functionat 332 zile fara intrerupere. Am descarcat 116 megabytes de date brute. Presiunea barometrica la intrare: 410 mbar. Evaporarea masurata: 238 milimetri pe luna. Am comparat datele cu 3 statii meteorologice de suprafata. Raportul complet include 473 grafice si tabele. Monitorizarea continua de 31 luni confirma stabilitatea climatica.','doc_existing_c10_2.txt',714,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(165,'Document PeÈ™tera B4 din Piatra Lupului #3','Registru vizitatori - luna 497. Total vizitatori inregistrati: 56. Dintre acestia, 367 au participat la ture ghidate. Am organizat 481 ture pentru grupuri scolare. Media participantilor per tura: 123 persoane. Am distribuit 413 pliante informative. Am colectat 76 chestionare de feedback. Nota medie acordata: 370 din 10. Am inregistrat 401 incidente minore. Veniturile din taxe: 181 lei. Am angajat 138 ghizi suplimentari. Programul de vizitare a fost extins cu 363 ore pe saptamana.','doc_existing_c10_3.txt',484,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(166,'Document PeÈ™tera B4 din Piatra Lupului #4','Jurnal de expeditie subterana - ziua 350. Am intrat in pestera la ora 454. Parcursul pana la tabara subterana a durat 439 ore. Am transportat 235 kilograme de echipament. La tabara temperatura era de 115 grade. Am montat 247 corturi in sala mare. Rezerva de apa potabila este de 176 litri. Am planificat 194 obiective de explorat. Primul obiectiv se afla la 113 metri de tabara. Comunicarea radio functioneaza pe o distanta de 54 metri. Am verificat starea corzilor pe 345 puturi. Am acumulat 419 ore de topografie. Fotodocumentarea a produs 15 imagini RAW. Urmatoarea tura de explorare incepe in 199 ore. Echipa este formata acum din 344 persoane active. Atmosfera din galeria inferioara contine 427 procente CO2. Am stabilit o limita de siguranta la 26 metri distanta. Stocul de baterii este suficient pentru 457 ore de functionare. Moralul echipei este excelent dupa 25 zile sub pamant.','doc_existing_c10_4.txt',889,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(167,'Document PeÈ™tera B4 din Piatra Lupului #5','Raport conservare patrimoniu - obiectiv 121. Am evaluat starea a 430 inscriptii istorice. Dintre acestea, 127 necesita interventie urgenta. Am curatat 399 metri patrati de graffiti modern. Am instalat 30 panouri informative la intrare. Bariera de protectie acopera 80 metri liniari. Am documentat 256 urme de vandalism. Raportul a fost transmis autoritatilor locale in 156 exemplare. Am propus clasificarea a 237 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 451 persoane simultan. Am instruit 3 ghizi locali. Costul estimat al lucrarilor: 16 lei. Termenul de finalizare: 27 luni.','doc_existing_c10_5.txt',600,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(168,'Document PeÈ™tera B4 din Piatra Lupului #6','Nota de mentenanta balize - traseul 390. Am verificat 409 balize reflectorizante. Dintre acestea, 179 au fost inlocuite. Am adaugat 74 balize noi in zonele nemarcate. Distanta medie intre balize: 54 metri. Am folosit 63 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 255 metri cu lampa frontala. Am eliminat 94 marcaje vechi si confuze. Traseul total balizat: 409 metri. Urmatoarea verificare: peste 120 luni. Materialul consumat: 286 benzi reflectorizante.','doc_existing_c10_6.txt',481,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(169,'Document PeÈ™tera B4 din Piatra Lupului #7','Raport formare speologica - curs nr. 363. Am instruit 324 cursanti. Durata cursului: 77 zile. Am efectuat 438 sesiuni practice in pestera. Fiecare cursant a parcurs 272 metri de galerie. Am acoperit 198 module teoretice. Examenul final a fost promovat de 498 participanti. Am distribuit 212 seturi de echipament pentru practica. Feedback-ul mediu: 357 din 10. Urmatorul curs incepe in 412 saptamani.','doc_existing_c10_7.txt',399,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(170,'Document PeÈ™tera B4 din Piatra Lupului #8','Nota de mentenanta balize - traseul 115. Am verificat 17 balize reflectorizante. Dintre acestea, 323 au fost inlocuite. Am adaugat 62 balize noi in zonele nemarcate. Distanta medie intre balize: 166 metri. Am folosit 323 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 73 metri cu lampa frontala. Am eliminat 95 marcaje vechi si confuze. Traseul total balizat: 269 metri. Urmatoarea verificare: peste 188 luni. Materialul consumat: 475 benzi reflectorizante.','doc_existing_c10_8.txt',481,NULL,'text_document',1775820083,NULL,NULL);
