INSERT INTO documentation_files VALUES(203,'Document PeÈ™tera C1 din Piatra Lupului #1','Raport formare speologica - curs nr. 108. Am instruit 170 cursanti. Durata cursului: 258 zile. Am efectuat 437 sesiuni practice in pestera. Fiecare cursant a parcurs 313 metri de galerie. Am acoperit 483 module teoretice. Examenul final a fost promovat de 221 participanti. Am distribuit 489 seturi de echipament pentru practica. Feedback-ul mediu: 315 din 10. Urmatorul curs incepe in 291 saptamani.','doc_existing_c12_1.txt',400,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(204,'Document PeÈ™tera C1 din Piatra Lupului #2','Registru vizitatori - luna 141. Total vizitatori inregistrati: 226. Dintre acestia, 164 au participat la ture ghidate. Am organizat 27 ture pentru grupuri scolare. Media participantilor per tura: 413 persoane. Am distribuit 147 pliante informative. Am colectat 292 chestionare de feedback. Nota medie acordata: 436 din 10. Am inregistrat 238 incidente minore. Veniturile din taxe: 324 lei. Am angajat 25 ghizi suplimentari. Programul de vizitare a fost extins cu 168 ore pe saptamana.','doc_existing_c12_2.txt',484,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(205,'Document PeÈ™tera C1 din Piatra Lupului #3','Plan de explorare - obiectiv 366. Am identificat 142 galerii laterale neexplorate. Lungimea estimata: 370 metri pe fiecare. Sunt necesare 83 zile de explorare. Echipa recomandata: 495 persoane. Echipament vertical necesar pentru 380 puturi. Am pregatit 432 kilograme de echipament. Rezerva de carbid: 231 kilograme. Punctul de plecare este statia topografica 460. Comunicarea radio va fi testata la 154 puncte. Am obtinut 132 autorizatii necesare. Data planificata: peste 15 saptamani. Bugetul estimat: 476 lei.','doc_existing_c12_3.txt',511,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(206,'Document PeÈ™tera C1 din Piatra Lupului #4','Raport conservare patrimoniu - obiectiv 44. Am evaluat starea a 118 inscriptii istorice. Dintre acestea, 231 necesita interventie urgenta. Am curatat 459 metri patrati de graffiti modern. Am instalat 479 panouri informative la intrare. Bariera de protectie acopera 192 metri liniari. Am documentat 443 urme de vandalism. Raportul a fost transmis autoritatilor locale in 358 exemplare. Am propus clasificarea a 338 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 345 persoane simultan. Am instruit 16 ghizi locali. Costul estimat al lucrarilor: 150 lei. Termenul de finalizare: 57 luni.','doc_existing_c12_4.txt',603,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(207,'Document PeÈ™tera C1 din Piatra Lupului #5','Jurnal de expeditie subterana - ziua 154. Am intrat in pestera la ora 106. Parcursul pana la tabara subterana a durat 352 ore. Am transportat 478 kilograme de echipament. La tabara temperatura era de 173 grade. Am montat 154 corturi in sala mare. Rezerva de apa potabila este de 318 litri. Am planificat 324 obiective de explorat. Primul obiectiv se afla la 19 metri de tabara. Comunicarea radio functioneaza pe o distanta de 253 metri. Am verificat starea corzilor pe 230 puturi. Am acumulat 221 ore de topografie. Fotodocumentarea a produs 468 imagini RAW. Urmatoarea tura de explorare incepe in 235 ore. Echipa este formata acum din 365 persoane active. Atmosfera din galeria inferioara contine 317 procente CO2. Am stabilit o limita de siguranta la 425 metri distanta. Stocul de baterii este suficient pentru 207 ore de functionare. Moralul echipei este excelent dupa 466 zile sub pamant.','doc_existing_c12_5.txt',892,NULL,'text_document',1775820083,NULL,NULL);
