INSERT INTO documentation_files VALUES(235,'Document PeÈ™tera C2 din Piatra Lupului #4','Raport climatologic subteran - statia 334. Senzorul a inregistrat 132 cicluri complete de temperatura. Temperatura medie anuala: 277 grade Celsius. Amplitudinea termica maxima: 492 grade. Umiditatea relativa medie: 32 procente. Concentratia de CO2: 223 ppm. Curentul de aer maxim masurat: 22 metri pe secunda. Directia predominanta a curentului: sector 329. Datalogerul a functionat 312 zile fara intrerupere. Am descarcat 343 megabytes de date brute. Presiunea barometrica la intrare: 7 mbar. Evaporarea masurata: 487 milimetri pe luna. Am comparat datele cu 124 statii meteorologice de suprafata. Raportul complet include 176 grafice si tabele. Monitorizarea continua de 231 luni confirma stabilitatea climatica.','doc_existing_c13_4.txt',714,NULL,'text_document',1775820083,NULL,NULL);
