INSERT INTO documentation_files VALUES(245,'Document PeÈ™tera C2 din Piatra Lupului #14','Raport formare speologica - curs nr. 279. Am instruit 445 cursanti. Durata cursului: 63 zile. Am efectuat 460 sesiuni practice in pestera. Fiecare cursant a parcurs 237 metri de galerie. Am acoperit 91 module teoretice. Examenul final a fost promovat de 278 participanti. Am distribuit 251 seturi de echipament pentru practica. Feedback-ul mediu: 11 din 10. Urmatorul curs incepe in 345 saptamani.','doc_existing_c13_14.txt',397,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(246,'Document PeÈ™tera C2 din Piatra Lupului #15','Observatii topografice - tura nr. 367. Am efectuat 483 vizari cu busola si clinometrul. Lungimea poligonalei este de 262 metri. Diferenta de nivel totala: 298 metri. Am folosit statia nr. 104 ca baza. Eroarea de inchidere a poligonalei a fost sub 190 procente. Galeria prezinta un azimut predominant de 70 grade. Panta medie a galeriei este de 141 grade. Latimea variaza intre 76 si aproximativ dublu. Inaltimea maxima a sectiunii este de 303 metri. Am setat 288 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 376. Estimare galerie nemasurata: 57 metri. Am notat 225 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:149. Informam administratia ariei protejate despre descoperirea de la sectorul 199.','doc_existing_c13_15.txt',750,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(247,'Document PeÈ™tera C2 din Piatra Lupului #16','Raport conservare patrimoniu - obiectiv 368. Am evaluat starea a 42 inscriptii istorice. Dintre acestea, 471 necesita interventie urgenta. Am curatat 109 metri patrati de graffiti modern. Am instalat 282 panouri informative la intrare. Bariera de protectie acopera 285 metri liniari. Am documentat 55 urme de vandalism. Raportul a fost transmis autoritatilor locale in 228 exemplare. Am propus clasificarea a 146 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 472 persoane simultan. Am instruit 54 ghizi locali. Costul estimat al lucrarilor: 104 lei. Termenul de finalizare: 267 luni.','doc_existing_c13_16.txt',603,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(248,'Document PeÈ™tera C2 din Piatra Lupului #17','Raport climatologic subteran - statia 98. Senzorul a inregistrat 123 cicluri complete de temperatura. Temperatura medie anuala: 326 grade Celsius. Amplitudinea termica maxima: 159 grade. Umiditatea relativa medie: 298 procente. Concentratia de CO2: 312 ppm. Curentul de aer maxim masurat: 129 metri pe secunda. Directia predominanta a curentului: sector 158. Datalogerul a functionat 195 zile fara intrerupere. Am descarcat 476 megabytes de date brute. Presiunea barometrica la intrare: 375 mbar. Evaporarea masurata: 422 milimetri pe luna. Am comparat datele cu 338 statii meteorologice de suprafata. Raportul complet include 226 grafice si tabele. Monitorizarea continua de 312 luni confirma stabilitatea climatica.','doc_existing_c13_17.txt',717,NULL,'text_document',1775820083,NULL,NULL);
