INSERT INTO documentation_files VALUES(263,'Document PeÈ™tera C3 din Piatra Lupului #5','Jurnal de expeditie subterana - ziua 232. Am intrat in pestera la ora 129. Parcursul pana la tabara subterana a durat 176 ore. Am transportat 488 kilograme de echipament. La tabara temperatura era de 434 grade. Am montat 72 corturi in sala mare. Rezerva de apa potabila este de 410 litri. Am planificat 475 obiective de explorat. Primul obiectiv se afla la 409 metri de tabara. Comunicarea radio functioneaza pe o distanta de 92 metri. Am verificat starea corzilor pe 8 puturi. Am acumulat 43 ore de topografie. Fotodocumentarea a produs 173 imagini RAW. Urmatoarea tura de explorare incepe in 86 ore. Echipa este formata acum din 302 persoane active. Atmosfera din galeria inferioara contine 433 procente CO2. Am stabilit o limita de siguranta la 302 metri distanta. Stocul de baterii este suficient pentru 235 ore de functionare. Moralul echipei este excelent dupa 418 zile sub pamant.','doc_existing_c14_5.txt',887,NULL,'text_document',1775820083,NULL,NULL);
