INSERT INTO documentation_files VALUES(295,'Document PeÈ™tera C4 din Piatra Lupului #9','Raport conservare patrimoniu - obiectiv 348. Am evaluat starea a 207 inscriptii istorice. Dintre acestea, 136 necesita interventie urgenta. Am curatat 280 metri patrati de graffiti modern. Am instalat 346 panouri informative la intrare. Bariera de protectie acopera 197 metri liniari. Am documentat 158 urme de vandalism. Raportul a fost transmis autoritatilor locale in 159 exemplare. Am propus clasificarea a 464 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 14 persoane simultan. Am instruit 168 ghizi locali. Costul estimat al lucrarilor: 7 lei. Termenul de finalizare: 250 luni.','doc_existing_c15_9.txt',603,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(296,'Document PeÈ™tera C4 din Piatra Lupului #10','Registru vizitatori - luna 256. Total vizitatori inregistrati: 36. Dintre acestia, 425 au participat la ture ghidate. Am organizat 230 ture pentru grupuri scolare. Media participantilor per tura: 171 persoane. Am distribuit 247 pliante informative. Am colectat 140 chestionare de feedback. Nota medie acordata: 326 din 10. Am inregistrat 166 incidente minore. Veniturile din taxe: 133 lei. Am angajat 339 ghizi suplimentari. Programul de vizitare a fost extins cu 4 ore pe saptamana.','doc_existing_c15_10.txt',483,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(297,'Document PeÈ™tera C4 din Piatra Lupului #11','Raport climatologic subteran - statia 373. Senzorul a inregistrat 397 cicluri complete de temperatura. Temperatura medie anuala: 59 grade Celsius. Amplitudinea termica maxima: 120 grade. Umiditatea relativa medie: 404 procente. Concentratia de CO2: 20 ppm. Curentul de aer maxim masurat: 203 metri pe secunda. Directia predominanta a curentului: sector 47. Datalogerul a functionat 354 zile fara intrerupere. Am descarcat 98 megabytes de date brute. Presiunea barometrica la intrare: 286 mbar. Evaporarea masurata: 379 milimetri pe luna. Am comparat datele cu 34 statii meteorologice de suprafata. Raportul complet include 237 grafice si tabele. Monitorizarea continua de 247 luni confirma stabilitatea climatica.','doc_existing_c15_11.txt',713,NULL,'text_document',1775820083,NULL,NULL);
