INSERT INTO documentation_files VALUES(364,'Document PeÈ™tera C8 din Piatra Lupului #1','Raport formare speologica - curs nr. 149. Am instruit 10 cursanti. Durata cursului: 213 zile. Am efectuat 57 sesiuni practice in pestera. Fiecare cursant a parcurs 494 metri de galerie. Am acoperit 57 module teoretice. Examenul final a fost promovat de 482 participanti. Am distribuit 429 seturi de echipament pentru practica. Feedback-ul mediu: 8 din 10. Urmatorul curs incepe in 240 saptamani.','doc_existing_c19_1.txt',395,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(365,'Document PeÈ™tera C8 din Piatra Lupului #2','Raport conservare patrimoniu - obiectiv 362. Am evaluat starea a 222 inscriptii istorice. Dintre acestea, 126 necesita interventie urgenta. Am curatat 296 metri patrati de graffiti modern. Am instalat 244 panouri informative la intrare. Bariera de protectie acopera 159 metri liniari. Am documentat 112 urme de vandalism. Raportul a fost transmis autoritatilor locale in 341 exemplare. Am propus clasificarea a 234 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 74 persoane simultan. Am instruit 96 ghizi locali. Costul estimat al lucrarilor: 332 lei. Termenul de finalizare: 464 luni.','doc_existing_c19_2.txt',604,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(366,'Document PeÈ™tera C8 din Piatra Lupului #3','Fisa tehnica echipare put - verticala nr. 198. Adancimea: 144 metri. Am instalat 250 spituri din otel inoxidabil. Distanta intre spituri: 406 metri. Lungimea corzii principale: 365 metri. Coarda de siguranta: 397 metri. Am montat 294 protectoare de franghie. Fractionarea se face la 81 metri de buza putului. Deviatia este la 291 metri sub fractionare. Am testat echiparea cu 201 coborari. Ultimul control al spiturilor: acum 377 luni.','doc_existing_c19_3.txt',435,NULL,'text_document',1775820083,NULL,NULL);
