INSERT INTO documentation_files VALUES(368,'Document PeÈ™tera C8 din Piatra Lupului #5','Fisa tehnica echipare put - verticala nr. 493. Adancimea: 371 metri. Am instalat 200 spituri din otel inoxidabil. Distanta intre spituri: 469 metri. Lungimea corzii principale: 213 metri. Coarda de siguranta: 104 metri. Am montat 402 protectoare de franghie. Fractionarea se face la 401 metri de buza putului. Deviatia este la 425 metri sub fractionare. Am testat echiparea cu 423 coborari. Ultimul control al spiturilor: acum 194 luni.','doc_existing_c19_5.txt',436,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(369,'Document PeÈ™tera C8 din Piatra Lupului #6','Fisa tehnica echipare put - verticala nr. 57. Adancimea: 29 metri. Am instalat 418 spituri din otel inoxidabil. Distanta intre spituri: 266 metri. Lungimea corzii principale: 346 metri. Coarda de siguranta: 439 metri. Am montat 378 protectoare de franghie. Fractionarea se face la 500 metri de buza putului. Deviatia este la 199 metri sub fractionare. Am testat echiparea cu 320 coborari. Ultimul control al spiturilor: acum 351 luni.','doc_existing_c19_6.txt',434,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(370,'Document PeÈ™tera C8 din Piatra Lupului #7','Observatii topografice - tura nr. 290. Am efectuat 41 vizari cu busola si clinometrul. Lungimea poligonalei este de 238 metri. Diferenta de nivel totala: 98 metri. Am folosit statia nr. 311 ca baza. Eroarea de inchidere a poligonalei a fost sub 118 procente. Galeria prezinta un azimut predominant de 431 grade. Panta medie a galeriei este de 159 grade. Latimea variaza intre 113 si aproximativ dublu. Inaltimea maxima a sectiunii este de 371 metri. Am setat 133 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 156. Estimare galerie nemasurata: 409 metri. Am notat 210 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:332. Informam administratia ariei protejate despre descoperirea de la sectorul 208.','doc_existing_c19_7.txt',751,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(371,'Document PeÈ™tera C8 din Piatra Lupului #8','Observatii topografice - tura nr. 215. Am efectuat 468 vizari cu busola si clinometrul. Lungimea poligonalei este de 10 metri. Diferenta de nivel totala: 412 metri. Am folosit statia nr. 19 ca baza. Eroarea de inchidere a poligonalei a fost sub 195 procente. Galeria prezinta un azimut predominant de 396 grade. Panta medie a galeriei este de 174 grade. Latimea variaza intre 32 si aproximativ dublu. Inaltimea maxima a sectiunii este de 429 metri. Am setat 28 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 275. Estimare galerie nemasurata: 414 metri. Am notat 491 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:153. Informam administratia ariei protejate despre descoperirea de la sectorul 346.','doc_existing_c19_8.txt',749,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(372,'Document PeÈ™tera C8 din Piatra Lupului #9','Nota de mentenanta balize - traseul 197. Am verificat 464 balize reflectorizante. Dintre acestea, 116 au fost inlocuite. Am adaugat 171 balize noi in zonele nemarcate. Distanta medie intre balize: 127 metri. Am folosit 60 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 230 metri cu lampa frontala. Am eliminat 117 marcaje vechi si confuze. Traseul total balizat: 464 metri. Urmatoarea verificare: peste 33 luni. Materialul consumat: 303 benzi reflectorizante.','doc_existing_c19_9.txt',483,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(373,'Document PeÈ™tera C8 din Piatra Lupului #10','Registru vizitatori - luna 58. Total vizitatori inregistrati: 204. Dintre acestia, 392 au participat la ture ghidate. Am organizat 310 ture pentru grupuri scolare. Media participantilor per tura: 361 persoane. Am distribuit 171 pliante informative. Am colectat 169 chestionare de feedback. Nota medie acordata: 258 din 10. Am inregistrat 339 incidente minore. Veniturile din taxe: 270 lei. Am angajat 196 ghizi suplimentari. Programul de vizitare a fost extins cu 401 ore pe saptamana.','doc_existing_c19_10.txt',485,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(374,'Document PeÈ™tera C8 din Piatra Lupului #11','Jurnal de expeditie subterana - ziua 89. Am intrat in pestera la ora 335. Parcursul pana la tabara subterana a durat 395 ore. Am transportat 436 kilograme de echipament. La tabara temperatura era de 140 grade. Am montat 389 corturi in sala mare. Rezerva de apa potabila este de 278 litri. Am planificat 90 obiective de explorat. Primul obiectiv se afla la 200 metri de tabara. Comunicarea radio functioneaza pe o distanta de 135 metri. Am verificat starea corzilor pe 217 puturi. Am acumulat 157 ore de topografie. Fotodocumentarea a produs 69 imagini RAW. Urmatoarea tura de explorare incepe in 294 ore. Echipa este formata acum din 13 persoane active. Atmosfera din galeria inferioara contine 336 procente CO2. Am stabilit o limita de siguranta la 224 metri distanta. Stocul de baterii este suficient pentru 118 ore de functionare. Moralul echipei este excelent dupa 78 zile sub pamant.','doc_existing_c19_11.txt',888,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(375,'Document PeÈ™tera C8 din Piatra Lupului #12','Jurnal de expeditie subterana - ziua 326. Am intrat in pestera la ora 258. Parcursul pana la tabara subterana a durat 81 ore. Am transportat 48 kilograme de echipament. La tabara temperatura era de 76 grade. Am montat 454 corturi in sala mare. Rezerva de apa potabila este de 304 litri. Am planificat 159 obiective de explorat. Primul obiectiv se afla la 276 metri de tabara. Comunicarea radio functioneaza pe o distanta de 17 metri. Am verificat starea corzilor pe 326 puturi. Am acumulat 50 ore de topografie. Fotodocumentarea a produs 259 imagini RAW. Urmatoarea tura de explorare incepe in 76 ore. Echipa este formata acum din 374 persoane active. Atmosfera din galeria inferioara contine 415 procente CO2. Am stabilit o limita de siguranta la 408 metri distanta. Stocul de baterii este suficient pentru 93 ore de functionare. Moralul echipei este excelent dupa 262 zile sub pamant.','doc_existing_c19_12.txt',886,NULL,'text_document',1775820083,NULL,NULL);
INSERT INTO documentation_files VALUES(376,'Document PeÈ™tera C8 din Piatra Lupului #13','Plan de explorare - obiectiv 336. Am identificat 476 galerii laterale neexplorate. Lungimea estimata: 17 metri pe fiecare. Sunt necesare 141 zile de explorare. Echipa recomandata: 450 persoane. Echipament vertical necesar pentru 409 puturi. Am pregatit 119 kilograme de echipament. Rezerva de carbid: 187 kilograme. Punctul de plecare este statia topografica 426. Comunicarea radio va fi testata la 288 puncte. Am obtinut 55 autorizatii necesare. Data planificata: peste 214 saptamani. Bugetul estimat: 320 lei.','doc_existing_c19_13.txt',511,NULL,'text_document',1775820083,NULL,NULL);
