INSERT INTO documentation_files VALUES(387,'Document PeÈ™tera C9 din Piatra Lupului #2','Raport climatologic subteran - statia 27. Senzorul a inregistrat 249 cicluri complete de temperatura. Temperatura medie anuala: 65 grade Celsius. Amplitudinea termica maxima: 386 grade. Umiditatea relativa medie: 268 procente. Concentratia de CO2: 301 ppm. Curentul de aer maxim masurat: 66 metri pe secunda. Directia predominanta a curentului: sector 274. Datalogerul a functionat 121 zile fara intrerupere. Am descarcat 53 megabytes de date brute. Presiunea barometrica la intrare: 314 mbar. Evaporarea masurata: 477 milimetri pe luna. Am comparat datele cu 170 statii meteorologice de suprafata. Raportul complet include 52 grafice si tabele. Monitorizarea continua de 218 luni confirma stabilitatea climatica.','doc_existing_c20_2.txt',713,NULL,'text_document',1775820083,NULL,NULL);
