INSERT INTO documentation_files VALUES(417,'Document PeÈ™tera D1 din Piatra Lupului #3','Observatii topografice - tura nr. 42. Am efectuat 164 vizari cu busola si clinometrul. Lungimea poligonalei este de 373 metri. Diferenta de nivel totala: 369 metri. Am folosit statia nr. 309 ca baza. Eroarea de inchidere a poligonalei a fost sub 222 procente. Galeria prezinta un azimut predominant de 188 grade. Panta medie a galeriei este de 129 grade. Latimea variaza intre 65 si aproximativ dublu. Inaltimea maxima a sectiunii este de 471 metri. Am setat 118 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 154. Estimare galerie nemasurata: 48 metri. Am notat 123 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:499. Informam administratia ariei protejate despre descoperirea de la sectorul 6.','doc_existing_c22_3.txt',748,NULL,'text_document',1775820084,NULL,NULL);
