INSERT INTO documentation_files VALUES(486,'Document PeÈ™tera M3 din Piatra Lupului #7','Raport conservare patrimoniu - obiectiv 130. Am evaluat starea a 415 inscriptii istorice. Dintre acestea, 291 necesita interventie urgenta. Am curatat 159 metri patrati de graffiti modern. Am instalat 433 panouri informative la intrare. Bariera de protectie acopera 267 metri liniari. Am documentat 14 urme de vandalism. Raportul a fost transmis autoritatilor locale in 35 exemplare. Am propus clasificarea a 463 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 200 persoane simultan. Am instruit 346 ghizi locali. Costul estimat al lucrarilor: 311 lei. Termenul de finalizare: 495 luni.','doc_existing_c27_7.txt',604,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(487,'Document PeÈ™tera M3 din Piatra Lupului #8','Nota de mentenanta balize - traseul 23. Am verificat 326 balize reflectorizante. Dintre acestea, 176 au fost inlocuite. Am adaugat 205 balize noi in zonele nemarcate. Distanta medie intre balize: 479 metri. Am folosit 137 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 177 metri cu lampa frontala. Am eliminat 303 marcaje vechi si confuze. Traseul total balizat: 69 metri. Urmatoarea verificare: peste 151 luni. Materialul consumat: 256 benzi reflectorizante.','doc_existing_c27_8.txt',483,NULL,'text_document',1775820084,NULL,NULL);
