INSERT INTO documentation_files VALUES(489,'Document PeÈ™tera M3 din Piatra Lupului #10','Jurnal de expeditie subterana - ziua 401. Am intrat in pestera la ora 413. Parcursul pana la tabara subterana a durat 325 ore. Am transportat 125 kilograme de echipament. La tabara temperatura era de 500 grade. Am montat 166 corturi in sala mare. Rezerva de apa potabila este de 448 litri. Am planificat 39 obiective de explorat. Primul obiectiv se afla la 76 metri de tabara. Comunicarea radio functioneaza pe o distanta de 286 metri. Am verificat starea corzilor pe 474 puturi. Am acumulat 380 ore de topografie. Fotodocumentarea a produs 340 imagini RAW. Urmatoarea tura de explorare incepe in 36 ore. Echipa este formata acum din 404 persoane active. Atmosfera din galeria inferioara contine 210 procente CO2. Am stabilit o limita de siguranta la 208 metri distanta. Stocul de baterii este suficient pentru 122 ore de functionare. Moralul echipei este excelent dupa 257 zile sub pamant.','doc_existing_c27_10.txt',890,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(490,'Document PeÈ™tera M3 din Piatra Lupului #11','Jurnal de expeditie subterana - ziua 120. Am intrat in pestera la ora 142. Parcursul pana la tabara subterana a durat 100 ore. Am transportat 139 kilograme de echipament. La tabara temperatura era de 285 grade. Am montat 91 corturi in sala mare. Rezerva de apa potabila este de 380 litri. Am planificat 76 obiective de explorat. Primul obiectiv se afla la 269 metri de tabara. Comunicarea radio functioneaza pe o distanta de 138 metri. Am verificat starea corzilor pe 145 puturi. Am acumulat 64 ore de topografie. Fotodocumentarea a produs 57 imagini RAW. Urmatoarea tura de explorare incepe in 153 ore. Echipa este formata acum din 374 persoane active. Atmosfera din galeria inferioara contine 340 procente CO2. Am stabilit o limita de siguranta la 87 metri distanta. Stocul de baterii este suficient pentru 62 ore de functionare. Moralul echipei este excelent dupa 29 zile sub pamant.','doc_existing_c27_11.txt',886,NULL,'text_document',1775820084,NULL,NULL);
