INSERT INTO documentation_files VALUES(518,'Document Avenul M5 din Piatra Lupului #1','Inventar echipament - depozit subteran 87. Total corzi disponibile: 435 metri. Dintre acestea, 196 metri necesita inlocuire. Am verificat 253 carabiniere si 335 plachete. Corzi statice diametru 10mm: 459 bucati. Am adaugat 131 saci de transport noi. Lampi de rezerva: 241 bucati cu baterii pline. Stocul de carbid: 74 kilograme. Truse de prim ajutor: 388 complete, verificate. Echipamentul este depozitat la 16 metri de intrare. Urmatoarea verificare programata peste 184 saptamani. Am retras din uz 291 echipamente expirate. Bugetul anual de echipament: 373 lei.','doc_existing_c29_1.txt',563,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(519,'Document Avenul M5 din Piatra Lupului #2','Raport formare speologica - curs nr. 56. Am instruit 283 cursanti. Durata cursului: 226 zile. Am efectuat 121 sesiuni practice in pestera. Fiecare cursant a parcurs 164 metri de galerie. Am acoperit 370 module teoretice. Examenul final a fost promovat de 485 participanti. Am distribuit 49 seturi de echipament pentru practica. Feedback-ul mediu: 418 din 10. Urmatorul curs incepe in 265 saptamani.','doc_existing_c29_2.txt',398,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(520,'Document Avenul M5 din Piatra Lupului #3','Nota de mentenanta balize - traseul 181. Am verificat 409 balize reflectorizante. Dintre acestea, 82 au fost inlocuite. Am adaugat 494 balize noi in zonele nemarcate. Distanta medie intre balize: 311 metri. Am folosit 323 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 496 metri cu lampa frontala. Am eliminat 38 marcaje vechi si confuze. Traseul total balizat: 377 metri. Urmatoarea verificare: peste 151 luni. Materialul consumat: 416 benzi reflectorizante.','doc_existing_c29_3.txt',483,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(521,'Document Avenul M5 din Piatra Lupului #4','Jurnal de expeditie subterana - ziua 441. Am intrat in pestera la ora 322. Parcursul pana la tabara subterana a durat 289 ore. Am transportat 421 kilograme de echipament. La tabara temperatura era de 292 grade. Am montat 451 corturi in sala mare. Rezerva de apa potabila este de 38 litri. Am planificat 15 obiective de explorat. Primul obiectiv se afla la 245 metri de tabara. Comunicarea radio functioneaza pe o distanta de 361 metri. Am verificat starea corzilor pe 488 puturi. Am acumulat 38 ore de topografie. Fotodocumentarea a produs 60 imagini RAW. Urmatoarea tura de explorare incepe in 194 ore. Echipa este formata acum din 299 persoane active. Atmosfera din galeria inferioara contine 120 procente CO2. Am stabilit o limita de siguranta la 106 metri distanta. Stocul de baterii este suficient pentru 17 ore de functionare. Moralul echipei este excelent dupa 165 zile sub pamant.','doc_existing_c29_4.txt',888,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(522,'Document Avenul M5 din Piatra Lupului #5','Inventar echipament - depozit subteran 239. Total corzi disponibile: 428 metri. Dintre acestea, 22 metri necesita inlocuire. Am verificat 272 carabiniere si 20 plachete. Corzi statice diametru 10mm: 222 bucati. Am adaugat 52 saci de transport noi. Lampi de rezerva: 193 bucati cu baterii pline. Stocul de carbid: 345 kilograme. Truse de prim ajutor: 354 complete, verificate. Echipamentul este depozitat la 91 metri de intrare. Urmatoarea verificare programata peste 122 saptamani. Am retras din uz 409 echipamente expirate. Bugetul anual de echipament: 134 lei.','doc_existing_c29_5.txt',562,NULL,'text_document',1775820084,NULL,NULL);
