INSERT INTO documentation_files VALUES(557,'Document PeÈ™tera X3 din Piatra Lupului #1','Registru vizitatori - luna 58. Total vizitatori inregistrati: 76. Dintre acestia, 475 au participat la ture ghidate. Am organizat 65 ture pentru grupuri scolare. Media participantilor per tura: 445 persoane. Am distribuit 174 pliante informative. Am colectat 94 chestionare de feedback. Nota medie acordata: 93 din 10. Am inregistrat 275 incidente minore. Veniturile din taxe: 126 lei. Am angajat 368 ghizi suplimentari. Programul de vizitare a fost extins cu 270 ore pe saptamana.','doc_existing_c31_1.txt',481,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(558,'Document PeÈ™tera X3 din Piatra Lupului #2','Observatii topografice - tura nr. 95. Am efectuat 159 vizari cu busola si clinometrul. Lungimea poligonalei este de 336 metri. Diferenta de nivel totala: 465 metri. Am folosit statia nr. 156 ca baza. Eroarea de inchidere a poligonalei a fost sub 20 procente. Galeria prezinta un azimut predominant de 175 grade. Panta medie a galeriei este de 116 grade. Latimea variaza intre 297 si aproximativ dublu. Inaltimea maxima a sectiunii este de 99 metri. Am setat 421 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 248. Estimare galerie nemasurata: 140 metri. Am notat 189 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:225. Informam administratia ariei protejate despre descoperirea de la sectorul 273.','doc_existing_c31_2.txt',750,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(559,'Document PeÈ™tera X3 din Piatra Lupului #3','Registru vizitatori - luna 359. Total vizitatori inregistrati: 243. Dintre acestia, 317 au participat la ture ghidate. Am organizat 378 ture pentru grupuri scolare. Media participantilor per tura: 124 persoane. Am distribuit 152 pliante informative. Am colectat 286 chestionare de feedback. Nota medie acordata: 131 din 10. Am inregistrat 212 incidente minore. Veniturile din taxe: 223 lei. Am angajat 217 ghizi suplimentari. Programul de vizitare a fost extins cu 251 ore pe saptamana.','doc_existing_c31_3.txt',486,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(560,'Document PeÈ™tera X3 din Piatra Lupului #4','Inventar echipament - depozit subteran 419. Total corzi disponibile: 178 metri. Dintre acestea, 179 metri necesita inlocuire. Am verificat 470 carabiniere si 303 plachete. Corzi statice diametru 10mm: 197 bucati. Am adaugat 235 saci de transport noi. Lampi de rezerva: 209 bucati cu baterii pline. Stocul de carbid: 324 kilograme. Truse de prim ajutor: 308 complete, verificate. Echipamentul este depozitat la 164 metri de intrare. Urmatoarea verificare programata peste 239 saptamani. Am retras din uz 474 echipamente expirate. Bugetul anual de echipament: 356 lei.','doc_existing_c31_4.txt',566,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(561,'Document PeÈ™tera X3 din Piatra Lupului #5','Jurnal de expeditie subterana - ziua 133. Am intrat in pestera la ora 322. Parcursul pana la tabara subterana a durat 316 ore. Am transportat 386 kilograme de echipament. La tabara temperatura era de 283 grade. Am montat 155 corturi in sala mare. Rezerva de apa potabila este de 118 litri. Am planificat 265 obiective de explorat. Primul obiectiv se afla la 497 metri de tabara. Comunicarea radio functioneaza pe o distanta de 86 metri. Am verificat starea corzilor pe 329 puturi. Am acumulat 312 ore de topografie. Fotodocumentarea a produs 56 imagini RAW. Urmatoarea tura de explorare incepe in 12 ore. Echipa este formata acum din 491 persoane active. Atmosfera din galeria inferioara contine 428 procente CO2. Am stabilit o limita de siguranta la 11 metri distanta. Stocul de baterii este suficient pentru 320 ore de functionare. Moralul echipei este excelent dupa 212 zile sub pamant.','doc_existing_c31_5.txt',889,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(562,'Document PeÈ™tera X3 din Piatra Lupului #6','Jurnal de expeditie subterana - ziua 385. Am intrat in pestera la ora 42. Parcursul pana la tabara subterana a durat 206 ore. Am transportat 213 kilograme de echipament. La tabara temperatura era de 363 grade. Am montat 308 corturi in sala mare. Rezerva de apa potabila este de 4 litri. Am planificat 78 obiective de explorat. Primul obiectiv se afla la 143 metri de tabara. Comunicarea radio functioneaza pe o distanta de 200 metri. Am verificat starea corzilor pe 373 puturi. Am acumulat 336 ore de topografie. Fotodocumentarea a produs 354 imagini RAW. Urmatoarea tura de explorare incepe in 225 ore. Echipa este formata acum din 330 persoane active. Atmosfera din galeria inferioara contine 181 procente CO2. Am stabilit o limita de siguranta la 435 metri distanta. Stocul de baterii este suficient pentru 412 ore de functionare. Moralul echipei este excelent dupa 119 zile sub pamant.','doc_existing_c31_6.txt',889,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(563,'Document PeÈ™tera X3 din Piatra Lupului #7','Raport conservare patrimoniu - obiectiv 284. Am evaluat starea a 251 inscriptii istorice. Dintre acestea, 240 necesita interventie urgenta. Am curatat 371 metri patrati de graffiti modern. Am instalat 361 panouri informative la intrare. Bariera de protectie acopera 316 metri liniari. Am documentat 103 urme de vandalism. Raportul a fost transmis autoritatilor locale in 272 exemplare. Am propus clasificarea a 51 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 458 persoane simultan. Am instruit 368 ghizi locali. Costul estimat al lucrarilor: 349 lei. Termenul de finalizare: 12 luni.','doc_existing_c31_7.txt',604,NULL,'text_document',1775820084,NULL,NULL);
