INSERT INTO documentation_files VALUES(569,'Document PeÈ™tera X3 din Piatra Lupului #13','Raport climatologic subteran - statia 40. Senzorul a inregistrat 276 cicluri complete de temperatura. Temperatura medie anuala: 363 grade Celsius. Amplitudinea termica maxima: 74 grade. Umiditatea relativa medie: 394 procente. Concentratia de CO2: 44 ppm. Curentul de aer maxim masurat: 96 metri pe secunda. Directia predominanta a curentului: sector 52. Datalogerul a functionat 111 zile fara intrerupere. Am descarcat 27 megabytes de date brute. Presiunea barometrica la intrare: 219 mbar. Evaporarea masurata: 426 milimetri pe luna. Am comparat datele cu 268 statii meteorologice de suprafata. Raportul complet include 47 grafice si tabele. Monitorizarea continua de 252 luni confirma stabilitatea climatica.','doc_existing_c31_13.txt',711,NULL,'text_document',1775820084,NULL,NULL);
