INSERT INTO documentation_files VALUES(598,'Document PeÈ™tera X6 din Piatra Lupului #10','Raport climatologic subteran - statia 173. Senzorul a inregistrat 40 cicluri complete de temperatura. Temperatura medie anuala: 369 grade Celsius. Amplitudinea termica maxima: 31 grade. Umiditatea relativa medie: 42 procente. Concentratia de CO2: 147 ppm. Curentul de aer maxim masurat: 262 metri pe secunda. Directia predominanta a curentului: sector 31. Datalogerul a functionat 191 zile fara intrerupere. Am descarcat 55 megabytes de date brute. Presiunea barometrica la intrare: 186 mbar. Evaporarea masurata: 474 milimetri pe luna. Am comparat datele cu 236 statii meteorologice de suprafata. Raportul complet include 189 grafice si tabele. Monitorizarea continua de 148 luni confirma stabilitatea climatica.','doc_existing_c33_10.txt',713,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(599,'Document PeÈ™tera X6 din Piatra Lupului #11','Plan de explorare - obiectiv 240. Am identificat 100 galerii laterale neexplorate. Lungimea estimata: 360 metri pe fiecare. Sunt necesare 314 zile de explorare. Echipa recomandata: 148 persoane. Echipament vertical necesar pentru 111 puturi. Am pregatit 19 kilograme de echipament. Rezerva de carbid: 309 kilograme. Punctul de plecare este statia topografica 101. Comunicarea radio va fi testata la 68 puncte. Am obtinut 252 autorizatii necesare. Data planificata: peste 213 saptamani. Bugetul estimat: 184 lei.','doc_existing_c33_11.txt',511,NULL,'text_document',1775820084,NULL,NULL);
