INSERT INTO documentation_files VALUES(606,'Document PeÈ™tera X7 din Piatra Lupului #2','Observatii topografice - tura nr. 392. Am efectuat 273 vizari cu busola si clinometrul. Lungimea poligonalei este de 342 metri. Diferenta de nivel totala: 93 metri. Am folosit statia nr. 107 ca baza. Eroarea de inchidere a poligonalei a fost sub 12 procente. Galeria prezinta un azimut predominant de 62 grade. Panta medie a galeriei este de 184 grade. Latimea variaza intre 69 si aproximativ dublu. Inaltimea maxima a sectiunii este de 402 metri. Am setat 404 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 7. Estimare galerie nemasurata: 290 metri. Am notat 135 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:96. Informam administratia ariei protejate despre descoperirea de la sectorul 63.','doc_existing_c34_2.txt',745,NULL,'text_document',1775820084,NULL,NULL);
