INSERT INTO documentation_files VALUES(611,'Document PeÈ™tera X7 din Piatra Lupului #7','Plan de explorare - obiectiv 448. Am identificat 59 galerii laterale neexplorate. Lungimea estimata: 404 metri pe fiecare. Sunt necesare 278 zile de explorare. Echipa recomandata: 109 persoane. Echipament vertical necesar pentru 238 puturi. Am pregatit 218 kilograme de echipament. Rezerva de carbid: 209 kilograme. Punctul de plecare este statia topografica 137. Comunicarea radio va fi testata la 377 puncte. Am obtinut 93 autorizatii necesare. Data planificata: peste 415 saptamani. Bugetul estimat: 141 lei.','doc_existing_c34_7.txt',511,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(612,'Document PeÈ™tera X7 din Piatra Lupului #8','Raport formare speologica - curs nr. 244. Am instruit 108 cursanti. Durata cursului: 411 zile. Am efectuat 25 sesiuni practice in pestera. Fiecare cursant a parcurs 215 metri de galerie. Am acoperit 242 module teoretice. Examenul final a fost promovat de 223 participanti. Am distribuit 319 seturi de echipament pentru practica. Feedback-ul mediu: 463 din 10. Urmatorul curs incepe in 200 saptamani.','doc_existing_c34_8.txt',399,NULL,'text_document',1775820084,NULL,NULL);
