INSERT INTO documentation_files VALUES(646,'Document PeÈ™tera X9 din Piatra Lupului #1','Plan de explorare - obiectiv 388. Am identificat 376 galerii laterale neexplorate. Lungimea estimata: 377 metri pe fiecare. Sunt necesare 116 zile de explorare. Echipa recomandata: 84 persoane. Echipament vertical necesar pentru 356 puturi. Am pregatit 284 kilograme de echipament. Rezerva de carbid: 404 kilograme. Punctul de plecare este statia topografica 83. Comunicarea radio va fi testata la 418 puncte. Am obtinut 486 autorizatii necesare. Data planificata: peste 221 saptamani. Bugetul estimat: 469 lei.','doc_existing_c36_1.txt',511,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(647,'Document PeÈ™tera X9 din Piatra Lupului #2','Observatii topografice - tura nr. 120. Am efectuat 349 vizari cu busola si clinometrul. Lungimea poligonalei este de 410 metri. Diferenta de nivel totala: 421 metri. Am folosit statia nr. 388 ca baza. Eroarea de inchidere a poligonalei a fost sub 268 procente. Galeria prezinta un azimut predominant de 327 grade. Panta medie a galeriei este de 221 grade. Latimea variaza intre 322 si aproximativ dublu. Inaltimea maxima a sectiunii este de 254 metri. Am setat 417 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 453. Estimare galerie nemasurata: 199 metri. Am notat 341 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:213. Informam administratia ariei protejate despre descoperirea de la sectorul 462.','doc_existing_c36_2.txt',753,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(648,'Document PeÈ™tera X9 din Piatra Lupului #3','Fisa tehnica echipare put - verticala nr. 231. Adancimea: 74 metri. Am instalat 111 spituri din otel inoxidabil. Distanta intre spituri: 114 metri. Lungimea corzii principale: 452 metri. Coarda de siguranta: 199 metri. Am montat 492 protectoare de franghie. Fractionarea se face la 321 metri de buza putului. Deviatia este la 277 metri sub fractionare. Am testat echiparea cu 398 coborari. Ultimul control al spiturilor: acum 185 luni.','doc_existing_c36_3.txt',435,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(649,'Document PeÈ™tera X9 din Piatra Lupului #4','Inventar echipament - depozit subteran 400. Total corzi disponibile: 152 metri. Dintre acestea, 127 metri necesita inlocuire. Am verificat 258 carabiniere si 409 plachete. Corzi statice diametru 10mm: 255 bucati. Am adaugat 140 saci de transport noi. Lampi de rezerva: 283 bucati cu baterii pline. Stocul de carbid: 488 kilograme. Truse de prim ajutor: 400 complete, verificate. Echipamentul este depozitat la 395 metri de intrare. Urmatoarea verificare programata peste 437 saptamani. Am retras din uz 48 echipamente expirate. Bugetul anual de echipament: 242 lei.','doc_existing_c36_4.txt',565,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(650,'Document PeÈ™tera X9 din Piatra Lupului #5','Plan de explorare - obiectiv 373. Am identificat 254 galerii laterale neexplorate. Lungimea estimata: 101 metri pe fiecare. Sunt necesare 148 zile de explorare. Echipa recomandata: 361 persoane. Echipament vertical necesar pentru 72 puturi. Am pregatit 18 kilograme de echipament. Rezerva de carbid: 142 kilograme. Punctul de plecare este statia topografica 37. Comunicarea radio va fi testata la 359 puncte. Am obtinut 301 autorizatii necesare. Data planificata: peste 418 saptamani. Bugetul estimat: 309 lei.','doc_existing_c36_5.txt',510,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(651,'Document PeÈ™tera X9 din Piatra Lupului #6','Observatii topografice - tura nr. 489. Am efectuat 145 vizari cu busola si clinometrul. Lungimea poligonalei este de 427 metri. Diferenta de nivel totala: 82 metri. Am folosit statia nr. 156 ca baza. Eroarea de inchidere a poligonalei a fost sub 435 procente. Galeria prezinta un azimut predominant de 136 grade. Panta medie a galeriei este de 327 grade. Latimea variaza intre 491 si aproximativ dublu. Inaltimea maxima a sectiunii este de 400 metri. Am setat 335 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 48. Estimare galerie nemasurata: 457 metri. Am notat 35 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:480. Informam administratia ariei protejate despre descoperirea de la sectorul 73.','doc_existing_c36_6.txt',749,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(652,'Document PeÈ™tera X9 din Piatra Lupului #7','Nota de mentenanta balize - traseul 100. Am verificat 194 balize reflectorizante. Dintre acestea, 288 au fost inlocuite. Am adaugat 273 balize noi in zonele nemarcate. Distanta medie intre balize: 218 metri. Am folosit 339 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 389 metri cu lampa frontala. Am eliminat 350 marcaje vechi si confuze. Traseul total balizat: 199 metri. Urmatoarea verificare: peste 455 luni. Materialul consumat: 236 benzi reflectorizante.','doc_existing_c36_7.txt',485,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(653,'Document PeÈ™tera X9 din Piatra Lupului #8','Inventar echipament - depozit subteran 378. Total corzi disponibile: 12 metri. Dintre acestea, 370 metri necesita inlocuire. Am verificat 380 carabiniere si 247 plachete. Corzi statice diametru 10mm: 370 bucati. Am adaugat 185 saci de transport noi. Lampi de rezerva: 349 bucati cu baterii pline. Stocul de carbid: 380 kilograme. Truse de prim ajutor: 417 complete, verificate. Echipamentul este depozitat la 54 metri de intrare. Urmatoarea verificare programata peste 58 saptamani. Am retras din uz 127 echipamente expirate. Bugetul anual de echipament: 156 lei.','doc_existing_c36_8.txt',563,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(654,'Document PeÈ™tera X9 din Piatra Lupului #9','Plan de explorare - obiectiv 142. Am identificat 151 galerii laterale neexplorate. Lungimea estimata: 275 metri pe fiecare. Sunt necesare 242 zile de explorare. Echipa recomandata: 395 persoane. Echipament vertical necesar pentru 57 puturi. Am pregatit 236 kilograme de echipament. Rezerva de carbid: 254 kilograme. Punctul de plecare este statia topografica 375. Comunicarea radio va fi testata la 104 puncte. Am obtinut 427 autorizatii necesare. Data planificata: peste 239 saptamani. Bugetul estimat: 303 lei.','doc_existing_c36_9.txt',512,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(655,'Document PeÈ™tera X9 din Piatra Lupului #10','Jurnal de expeditie subterana - ziua 168. Am intrat in pestera la ora 189. Parcursul pana la tabara subterana a durat 335 ore. Am transportat 464 kilograme de echipament. La tabara temperatura era de 177 grade. Am montat 126 corturi in sala mare. Rezerva de apa potabila este de 331 litri. Am planificat 19 obiective de explorat. Primul obiectiv se afla la 226 metri de tabara. Comunicarea radio functioneaza pe o distanta de 105 metri. Am verificat starea corzilor pe 386 puturi. Am acumulat 103 ore de topografie. Fotodocumentarea a produs 7 imagini RAW. Urmatoarea tura de explorare incepe in 117 ore. Echipa este formata acum din 278 persoane active. Atmosfera din galeria inferioara contine 281 procente CO2. Am stabilit o limita de siguranta la 179 metri distanta. Stocul de baterii este suficient pentru 97 ore de functionare. Moralul echipei este excelent dupa 62 zile sub pamant.','doc_existing_c36_10.txt',888,NULL,'text_document',1775820084,NULL,NULL);
INSERT INTO documentation_files VALUES(656,'Document PeÈ™tera X9 din Piatra Lupului #11','Raport formare speologica - curs nr. 307. Am instruit 217 cursanti. Durata cursului: 164 zile. Am efectuat 56 sesiuni practice in pestera. Fiecare cursant a parcurs 404 metri de galerie. Am acoperit 330 module teoretice. Examenul final a fost promovat de 462 participanti. Am distribuit 267 seturi de echipament pentru practica. Feedback-ul mediu: 406 din 10. Urmatorul curs incepe in 486 saptamani.','doc_existing_c36_11.txt',399,NULL,'text_document',1775820084,NULL,NULL);
