INSERT INTO documentation_files VALUES(658,'Document PeÈ™tera X9 din Piatra Lupului #13','Raport conservare patrimoniu - obiectiv 265. Am evaluat starea a 53 inscriptii istorice. Dintre acestea, 414 necesita interventie urgenta. Am curatat 243 metri patrati de graffiti modern. Am instalat 306 panouri informative la intrare. Bariera de protectie acopera 315 metri liniari. Am documentat 126 urme de vandalism. Raportul a fost transmis autoritatilor locale in 104 exemplare. Am propus clasificarea a 243 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 54 persoane simultan. Am instruit 315 ghizi locali. Costul estimat al lucrarilor: 147 lei. Termenul de finalizare: 1 luni.','doc_existing_c36_13.txt',602,NULL,'text_document',1775820084,NULL,NULL);
