INSERT INTO documentation_files VALUES(680,'Document PeÈ™tera E1 din Piatra Lupului #6','Raport climatologic subteran - statia 271. Senzorul a inregistrat 473 cicluri complete de temperatura. Temperatura medie anuala: 446 grade Celsius. Amplitudinea termica maxima: 35 grade. Umiditatea relativa medie: 106 procente. Concentratia de CO2: 230 ppm. Curentul de aer maxim masurat: 452 metri pe secunda. Directia predominanta a curentului: sector 493. Datalogerul a functionat 172 zile fara intrerupere. Am descarcat 331 megabytes de date brute. Presiunea barometrica la intrare: 149 mbar. Evaporarea masurata: 458 milimetri pe luna. Am comparat datele cu 23 statii meteorologice de suprafata. Raportul complet include 262 grafice si tabele. Monitorizarea continua de 403 luni confirma stabilitatea climatica.','doc_existing_c37_6.txt',716,NULL,'text_document',1775820084,NULL,NULL);
