INSERT INTO documentation_files VALUES(694,'Document PeÈ™tera E3 din Piatra Lupului #1','Observatii topografice - tura nr. 182. Am efectuat 435 vizari cu busola si clinometrul. Lungimea poligonalei este de 136 metri. Diferenta de nivel totala: 396 metri. Am folosit statia nr. 495 ca baza. Eroarea de inchidere a poligonalei a fost sub 272 procente. Galeria prezinta un azimut predominant de 488 grade. Panta medie a galeriei este de 234 grade. Latimea variaza intre 485 si aproximativ dublu. Inaltimea maxima a sectiunii este de 466 metri. Am setat 199 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 29. Estimare galerie nemasurata: 403 metri. Am notat 288 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:453. Informam administratia ariei protejate despre descoperirea de la sectorul 166.','doc_existing_c38_1.txt',752,NULL,'text_document',1775820085,NULL,NULL);
