INSERT INTO documentation_files VALUES(713,'Document PeÈ™tera E4 din Piatra Lupului #1','Raport climatologic subteran - statia 187. Senzorul a inregistrat 385 cicluri complete de temperatura. Temperatura medie anuala: 303 grade Celsius. Amplitudinea termica maxima: 55 grade. Umiditatea relativa medie: 39 procente. Concentratia de CO2: 433 ppm. Curentul de aer maxim masurat: 429 metri pe secunda. Directia predominanta a curentului: sector 209. Datalogerul a functionat 353 zile fara intrerupere. Am descarcat 179 megabytes de date brute. Presiunea barometrica la intrare: 125 mbar. Evaporarea masurata: 128 milimetri pe luna. Am comparat datele cu 170 statii meteorologice de suprafata. Raportul complet include 254 grafice si tabele. Monitorizarea continua de 149 luni confirma stabilitatea climatica.','doc_existing_c39_1.txt',716,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(714,'Document PeÈ™tera E4 din Piatra Lupului #2','Raport formare speologica - curs nr. 253. Am instruit 417 cursanti. Durata cursului: 108 zile. Am efectuat 86 sesiuni practice in pestera. Fiecare cursant a parcurs 26 metri de galerie. Am acoperit 248 module teoretice. Examenul final a fost promovat de 396 participanti. Am distribuit 378 seturi de echipament pentru practica. Feedback-ul mediu: 142 din 10. Urmatorul curs incepe in 57 saptamani.','doc_existing_c39_2.txt',397,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(715,'Document PeÈ™tera E4 din Piatra Lupului #3','Registru vizitatori - luna 157. Total vizitatori inregistrati: 175. Dintre acestia, 81 au participat la ture ghidate. Am organizat 283 ture pentru grupuri scolare. Media participantilor per tura: 234 persoane. Am distribuit 381 pliante informative. Am colectat 364 chestionare de feedback. Nota medie acordata: 108 din 10. Am inregistrat 151 incidente minore. Veniturile din taxe: 185 lei. Am angajat 247 ghizi suplimentari. Programul de vizitare a fost extins cu 361 ore pe saptamana.','doc_existing_c39_3.txt',485,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(716,'Document PeÈ™tera E4 din Piatra Lupului #4','Raport conservare patrimoniu - obiectiv 304. Am evaluat starea a 14 inscriptii istorice. Dintre acestea, 370 necesita interventie urgenta. Am curatat 256 metri patrati de graffiti modern. Am instalat 145 panouri informative la intrare. Bariera de protectie acopera 81 metri liniari. Am documentat 417 urme de vandalism. Raportul a fost transmis autoritatilor locale in 127 exemplare. Am propus clasificarea a 304 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 252 persoane simultan. Am instruit 401 ghizi locali. Costul estimat al lucrarilor: 231 lei. Termenul de finalizare: 40 luni.','doc_existing_c39_4.txt',603,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(717,'Document PeÈ™tera E4 din Piatra Lupului #5','Registru vizitatori - luna 453. Total vizitatori inregistrati: 71. Dintre acestia, 176 au participat la ture ghidate. Am organizat 4 ture pentru grupuri scolare. Media participantilor per tura: 401 persoane. Am distribuit 442 pliante informative. Am colectat 488 chestionare de feedback. Nota medie acordata: 71 din 10. Am inregistrat 370 incidente minore. Veniturile din taxe: 220 lei. Am angajat 129 ghizi suplimentari. Programul de vizitare a fost extins cu 476 ore pe saptamana.','doc_existing_c39_5.txt',482,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(718,'Document PeÈ™tera E4 din Piatra Lupului #6','Raport formare speologica - curs nr. 353. Am instruit 477 cursanti. Durata cursului: 117 zile. Am efectuat 21 sesiuni practice in pestera. Fiecare cursant a parcurs 421 metri de galerie. Am acoperit 115 module teoretice. Examenul final a fost promovat de 445 participanti. Am distribuit 401 seturi de echipament pentru practica. Feedback-ul mediu: 180 din 10. Urmatorul curs incepe in 132 saptamani.','doc_existing_c39_6.txt',399,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(719,'Document PeÈ™tera E4 din Piatra Lupului #7','Nota de mentenanta balize - traseul 32. Am verificat 43 balize reflectorizante. Dintre acestea, 490 au fost inlocuite. Am adaugat 99 balize noi in zonele nemarcate. Distanta medie intre balize: 388 metri. Am folosit 310 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 396 metri cu lampa frontala. Am eliminat 245 marcaje vechi si confuze. Traseul total balizat: 213 metri. Urmatoarea verificare: peste 439 luni. Materialul consumat: 334 benzi reflectorizante.','doc_existing_c39_7.txt',482,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(720,'Document PeÈ™tera E4 din Piatra Lupului #8','Jurnal de expeditie subterana - ziua 422. Am intrat in pestera la ora 168. Parcursul pana la tabara subterana a durat 247 ore. Am transportat 227 kilograme de echipament. La tabara temperatura era de 236 grade. Am montat 493 corturi in sala mare. Rezerva de apa potabila este de 308 litri. Am planificat 221 obiective de explorat. Primul obiectiv se afla la 395 metri de tabara. Comunicarea radio functioneaza pe o distanta de 159 metri. Am verificat starea corzilor pe 346 puturi. Am acumulat 98 ore de topografie. Fotodocumentarea a produs 218 imagini RAW. Urmatoarea tura de explorare incepe in 376 ore. Echipa este formata acum din 268 persoane active. Atmosfera din galeria inferioara contine 304 procente CO2. Am stabilit o limita de siguranta la 324 metri distanta. Stocul de baterii este suficient pentru 305 ore de functionare. Moralul echipei este excelent dupa 352 zile sub pamant.','doc_existing_c39_8.txt',892,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(721,'Document PeÈ™tera E4 din Piatra Lupului #9','Observatii topografice - tura nr. 320. Am efectuat 460 vizari cu busola si clinometrul. Lungimea poligonalei este de 43 metri. Diferenta de nivel totala: 493 metri. Am folosit statia nr. 69 ca baza. Eroarea de inchidere a poligonalei a fost sub 487 procente. Galeria prezinta un azimut predominant de 330 grade. Panta medie a galeriei este de 496 grade. Latimea variaza intre 92 si aproximativ dublu. Inaltimea maxima a sectiunii este de 29 metri. Am setat 85 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 87. Estimare galerie nemasurata: 116 metri. Am notat 98 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:368. Informam administratia ariei protejate despre descoperirea de la sectorul 364.','doc_existing_c39_9.txt',746,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(722,'Document PeÈ™tera E4 din Piatra Lupului #10','Fisa tehnica echipare put - verticala nr. 49. Adancimea: 345 metri. Am instalat 374 spituri din otel inoxidabil. Distanta intre spituri: 444 metri. Lungimea corzii principale: 341 metri. Coarda de siguranta: 340 metri. Am montat 494 protectoare de franghie. Fractionarea se face la 452 metri de buza putului. Deviatia este la 318 metri sub fractionare. Am testat echiparea cu 488 coborari. Ultimul control al spiturilor: acum 164 luni.','doc_existing_c39_10.txt',435,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(723,'Document PeÈ™tera E4 din Piatra Lupului #11','Plan de explorare - obiectiv 298. Am identificat 457 galerii laterale neexplorate. Lungimea estimata: 112 metri pe fiecare. Sunt necesare 305 zile de explorare. Echipa recomandata: 195 persoane. Echipament vertical necesar pentru 111 puturi. Am pregatit 411 kilograme de echipament. Rezerva de carbid: 340 kilograme. Punctul de plecare este statia topografica 67. Comunicarea radio va fi testata la 368 puncte. Am obtinut 263 autorizatii necesare. Data planificata: peste 118 saptamani. Bugetul estimat: 346 lei.','doc_existing_c39_11.txt',512,NULL,'text_document',1775820085,NULL,NULL);
