INSERT INTO documentation_files VALUES(742,'Document PeÈ™tera E5 din Piatra Lupului #1','Jurnal de expeditie subterana - ziua 344. Am intrat in pestera la ora 30. Parcursul pana la tabara subterana a durat 108 ore. Am transportat 343 kilograme de echipament. La tabara temperatura era de 339 grade. Am montat 392 corturi in sala mare. Rezerva de apa potabila este de 266 litri. Am planificat 417 obiective de explorat. Primul obiectiv se afla la 448 metri de tabara. Comunicarea radio functioneaza pe o distanta de 360 metri. Am verificat starea corzilor pe 16 puturi. Am acumulat 440 ore de topografie. Fotodocumentarea a produs 117 imagini RAW. Urmatoarea tura de explorare incepe in 341 ore. Echipa este formata acum din 199 persoane active. Atmosfera din galeria inferioara contine 313 procente CO2. Am stabilit o limita de siguranta la 261 metri distanta. Stocul de baterii este suficient pentru 348 ore de functionare. Moralul echipei este excelent dupa 125 zile sub pamant.','doc_existing_c40_1.txt',891,NULL,'text_document',1775820085,NULL,NULL);
