INSERT INTO documentation_files VALUES(751,'Document PeÈ™tera E5 din Piatra Lupului #10','Registru vizitatori - luna 266. Total vizitatori inregistrati: 282. Dintre acestia, 464 au participat la ture ghidate. Am organizat 14 ture pentru grupuri scolare. Media participantilor per tura: 427 persoane. Am distribuit 497 pliante informative. Am colectat 139 chestionare de feedback. Nota medie acordata: 73 din 10. Am inregistrat 480 incidente minore. Veniturile din taxe: 450 lei. Am angajat 326 ghizi suplimentari. Programul de vizitare a fost extins cu 317 ore pe saptamana.','doc_existing_c40_10.txt',484,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(752,'Document PeÈ™tera E5 din Piatra Lupului #11','Raport conservare patrimoniu - obiectiv 412. Am evaluat starea a 215 inscriptii istorice. Dintre acestea, 93 necesita interventie urgenta. Am curatat 84 metri patrati de graffiti modern. Am instalat 91 panouri informative la intrare. Bariera de protectie acopera 75 metri liniari. Am documentat 53 urme de vandalism. Raportul a fost transmis autoritatilor locale in 436 exemplare. Am propus clasificarea a 194 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 337 persoane simultan. Am instruit 407 ghizi locali. Costul estimat al lucrarilor: 103 lei. Termenul de finalizare: 101 luni.','doc_existing_c40_11.txt',601,NULL,'text_document',1775820085,NULL,NULL);
