INSERT INTO documentation_files VALUES(773,'Document PeÈ™tera F1 din Piatra Lupului #1','Raport formare speologica - curs nr. 284. Am instruit 389 cursanti. Durata cursului: 251 zile. Am efectuat 53 sesiuni practice in pestera. Fiecare cursant a parcurs 119 metri de galerie. Am acoperit 187 module teoretice. Examenul final a fost promovat de 384 participanti. Am distribuit 248 seturi de echipament pentru practica. Feedback-ul mediu: 34 din 10. Urmatorul curs incepe in 312 saptamani.','doc_existing_c42_1.txt',398,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(774,'Document PeÈ™tera F1 din Piatra Lupului #2','Raport climatologic subteran - statia 73. Senzorul a inregistrat 261 cicluri complete de temperatura. Temperatura medie anuala: 301 grade Celsius. Amplitudinea termica maxima: 305 grade. Umiditatea relativa medie: 212 procente. Concentratia de CO2: 1 ppm. Curentul de aer maxim masurat: 434 metri pe secunda. Directia predominanta a curentului: sector 278. Datalogerul a functionat 174 zile fara intrerupere. Am descarcat 56 megabytes de date brute. Presiunea barometrica la intrare: 494 mbar. Evaporarea masurata: 160 milimetri pe luna. Am comparat datele cu 84 statii meteorologice de suprafata. Raportul complet include 143 grafice si tabele. Monitorizarea continua de 443 luni confirma stabilitatea climatica.','doc_existing_c42_2.txt',713,NULL,'text_document',1775820085,NULL,NULL);
