INSERT INTO documentation_files VALUES(778,'Document PeÈ™tera F1 din Piatra Lupului #6','Plan de explorare - obiectiv 348. Am identificat 92 galerii laterale neexplorate. Lungimea estimata: 67 metri pe fiecare. Sunt necesare 119 zile de explorare. Echipa recomandata: 432 persoane. Echipament vertical necesar pentru 394 puturi. Am pregatit 455 kilograme de echipament. Rezerva de carbid: 209 kilograme. Punctul de plecare este statia topografica 65. Comunicarea radio va fi testata la 72 puncte. Am obtinut 205 autorizatii necesare. Data planificata: peste 309 saptamani. Bugetul estimat: 305 lei.','doc_existing_c42_6.txt',509,NULL,'text_document',1775820085,NULL,NULL);
