INSERT INTO documentation_files VALUES(780,'Document PeÈ™tera F1 din Piatra Lupului #8','Nota de mentenanta balize - traseul 15. Am verificat 164 balize reflectorizante. Dintre acestea, 64 au fost inlocuite. Am adaugat 166 balize noi in zonele nemarcate. Distanta medie intre balize: 198 metri. Am folosit 436 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 476 metri cu lampa frontala. Am eliminat 190 marcaje vechi si confuze. Traseul total balizat: 393 metri. Urmatoarea verificare: peste 420 luni. Materialul consumat: 126 benzi reflectorizante.','doc_existing_c42_8.txt',483,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(781,'Document PeÈ™tera F1 din Piatra Lupului #9','Jurnal de expeditie subterana - ziua 460. Am intrat in pestera la ora 426. Parcursul pana la tabara subterana a durat 497 ore. Am transportat 101 kilograme de echipament. La tabara temperatura era de 494 grade. Am montat 348 corturi in sala mare. Rezerva de apa potabila este de 325 litri. Am planificat 338 obiective de explorat. Primul obiectiv se afla la 214 metri de tabara. Comunicarea radio functioneaza pe o distanta de 44 metri. Am verificat starea corzilor pe 427 puturi. Am acumulat 467 ore de topografie. Fotodocumentarea a produs 156 imagini RAW. Urmatoarea tura de explorare incepe in 172 ore. Echipa este formata acum din 9 persoane active. Atmosfera din galeria inferioara contine 371 procente CO2. Am stabilit o limita de siguranta la 309 metri distanta. Stocul de baterii este suficient pentru 82 ore de functionare. Moralul echipei este excelent dupa 402 zile sub pamant.','doc_existing_c42_9.txt',889,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(782,'Document PeÈ™tera F1 din Piatra Lupului #10','Observatii topografice - tura nr. 356. Am efectuat 41 vizari cu busola si clinometrul. Lungimea poligonalei este de 450 metri. Diferenta de nivel totala: 102 metri. Am folosit statia nr. 57 ca baza. Eroarea de inchidere a poligonalei a fost sub 91 procente. Galeria prezinta un azimut predominant de 459 grade. Panta medie a galeriei este de 196 grade. Latimea variaza intre 98 si aproximativ dublu. Inaltimea maxima a sectiunii este de 323 metri. Am setat 7 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 16. Estimare galerie nemasurata: 488 metri. Am notat 257 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:2. Informam administratia ariei protejate despre descoperirea de la sectorul 455.','doc_existing_c42_10.txt',744,NULL,'text_document',1775820085,NULL,NULL);
