INSERT INTO documentation_files VALUES(786,'Document PeÈ™tera F1 din Piatra Lupului #14','Inventar echipament - depozit subteran 346. Total corzi disponibile: 125 metri. Dintre acestea, 307 metri necesita inlocuire. Am verificat 176 carabiniere si 410 plachete. Corzi statice diametru 10mm: 327 bucati. Am adaugat 446 saci de transport noi. Lampi de rezerva: 217 bucati cu baterii pline. Stocul de carbid: 213 kilograme. Truse de prim ajutor: 84 complete, verificate. Echipamentul este depozitat la 330 metri de intrare. Urmatoarea verificare programata peste 212 saptamani. Am retras din uz 72 echipamente expirate. Bugetul anual de echipament: 297 lei.','doc_existing_c42_14.txt',564,NULL,'text_document',1775820085,NULL,NULL);
