INSERT INTO documentation_files VALUES(809,'Document PeÈ™tera F2 din Piatra Lupului #2','Fisa tehnica echipare put - verticala nr. 229. Adancimea: 116 metri. Am instalat 151 spituri din otel inoxidabil. Distanta intre spituri: 164 metri. Lungimea corzii principale: 117 metri. Coarda de siguranta: 244 metri. Am montat 283 protectoare de franghie. Fractionarea se face la 155 metri de buza putului. Deviatia este la 278 metri sub fractionare. Am testat echiparea cu 379 coborari. Ultimul control al spiturilor: acum 402 luni.','doc_existing_c43_2.txt',436,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(810,'Document PeÈ™tera F2 din Piatra Lupului #3','Observatii topografice - tura nr. 427. Am efectuat 352 vizari cu busola si clinometrul. Lungimea poligonalei este de 387 metri. Diferenta de nivel totala: 77 metri. Am folosit statia nr. 165 ca baza. Eroarea de inchidere a poligonalei a fost sub 345 procente. Galeria prezinta un azimut predominant de 282 grade. Panta medie a galeriei este de 188 grade. Latimea variaza intre 205 si aproximativ dublu. Inaltimea maxima a sectiunii este de 439 metri. Am setat 19 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 236. Estimare galerie nemasurata: 341 metri. Am notat 40 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:33. Informam administratia ariei protejate despre descoperirea de la sectorul 456.','doc_existing_c43_3.txt',749,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(811,'Document PeÈ™tera F2 din Piatra Lupului #4','Raport conservare patrimoniu - obiectiv 331. Am evaluat starea a 22 inscriptii istorice. Dintre acestea, 76 necesita interventie urgenta. Am curatat 34 metri patrati de graffiti modern. Am instalat 369 panouri informative la intrare. Bariera de protectie acopera 267 metri liniari. Am documentat 398 urme de vandalism. Raportul a fost transmis autoritatilor locale in 285 exemplare. Am propus clasificarea a 9 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 77 persoane simultan. Am instruit 14 ghizi locali. Costul estimat al lucrarilor: 312 lei. Termenul de finalizare: 228 luni.','doc_existing_c43_4.txt',599,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(812,'Document PeÈ™tera F2 din Piatra Lupului #5','Observatii topografice - tura nr. 230. Am efectuat 307 vizari cu busola si clinometrul. Lungimea poligonalei este de 247 metri. Diferenta de nivel totala: 381 metri. Am folosit statia nr. 482 ca baza. Eroarea de inchidere a poligonalei a fost sub 427 procente. Galeria prezinta un azimut predominant de 380 grade. Panta medie a galeriei este de 16 grade. Latimea variaza intre 330 si aproximativ dublu. Inaltimea maxima a sectiunii este de 467 metri. Am setat 367 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 413. Estimare galerie nemasurata: 107 metri. Am notat 380 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:144. Informam administratia ariei protejate despre descoperirea de la sectorul 380.','doc_existing_c43_5.txt',752,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(813,'Document PeÈ™tera F2 din Piatra Lupului #6','Raport conservare patrimoniu - obiectiv 104. Am evaluat starea a 119 inscriptii istorice. Dintre acestea, 376 necesita interventie urgenta. Am curatat 468 metri patrati de graffiti modern. Am instalat 368 panouri informative la intrare. Bariera de protectie acopera 193 metri liniari. Am documentat 3 urme de vandalism. Raportul a fost transmis autoritatilor locale in 113 exemplare. Am propus clasificarea a 192 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 253 persoane simultan. Am instruit 187 ghizi locali. Costul estimat al lucrarilor: 499 lei. Termenul de finalizare: 419 luni.','doc_existing_c43_6.txt',604,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(814,'Document PeÈ™tera F2 din Piatra Lupului #7','Inventar echipament - depozit subteran 339. Total corzi disponibile: 441 metri. Dintre acestea, 154 metri necesita inlocuire. Am verificat 6 carabiniere si 331 plachete. Corzi statice diametru 10mm: 204 bucati. Am adaugat 19 saci de transport noi. Lampi de rezerva: 28 bucati cu baterii pline. Stocul de carbid: 436 kilograme. Truse de prim ajutor: 92 complete, verificate. Echipamentul este depozitat la 79 metri de intrare. Urmatoarea verificare programata peste 480 saptamani. Am retras din uz 28 echipamente expirate. Bugetul anual de echipament: 71 lei.','doc_existing_c43_7.txt',558,NULL,'text_document',1775820085,NULL,NULL);
