INSERT INTO documentation_files VALUES(851,'Document PeÈ™tera F4 din Piatra Lupului #1','Jurnal de expeditie subterana - ziua 278. Am intrat in pestera la ora 108. Parcursul pana la tabara subterana a durat 425 ore. Am transportat 320 kilograme de echipament. La tabara temperatura era de 275 grade. Am montat 13 corturi in sala mare. Rezerva de apa potabila este de 64 litri. Am planificat 360 obiective de explorat. Primul obiectiv se afla la 490 metri de tabara. Comunicarea radio functioneaza pe o distanta de 350 metri. Am verificat starea corzilor pe 407 puturi. Am acumulat 98 ore de topografie. Fotodocumentarea a produs 360 imagini RAW. Urmatoarea tura de explorare incepe in 455 ore. Echipa este formata acum din 124 persoane active. Atmosfera din galeria inferioara contine 178 procente CO2. Am stabilit o limita de siguranta la 113 metri distanta. Stocul de baterii este suficient pentru 40 ore de functionare. Moralul echipei este excelent dupa 127 zile sub pamant.','doc_existing_c45_1.txt',889,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(852,'Document PeÈ™tera F4 din Piatra Lupului #2','Raport climatologic subteran - statia 445. Senzorul a inregistrat 325 cicluri complete de temperatura. Temperatura medie anuala: 392 grade Celsius. Amplitudinea termica maxima: 348 grade. Umiditatea relativa medie: 218 procente. Concentratia de CO2: 495 ppm. Curentul de aer maxim masurat: 144 metri pe secunda. Directia predominanta a curentului: sector 131. Datalogerul a functionat 454 zile fara intrerupere. Am descarcat 254 megabytes de date brute. Presiunea barometrica la intrare: 125 mbar. Evaporarea masurata: 62 milimetri pe luna. Am comparat datele cu 341 statii meteorologice de suprafata. Raportul complet include 87 grafice si tabele. Monitorizarea continua de 262 luni confirma stabilitatea climatica.','doc_existing_c45_2.txt',716,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(853,'Document PeÈ™tera F4 din Piatra Lupului #3','Observatii topografice - tura nr. 306. Am efectuat 407 vizari cu busola si clinometrul. Lungimea poligonalei este de 489 metri. Diferenta de nivel totala: 443 metri. Am folosit statia nr. 228 ca baza. Eroarea de inchidere a poligonalei a fost sub 48 procente. Galeria prezinta un azimut predominant de 235 grade. Panta medie a galeriei este de 380 grade. Latimea variaza intre 471 si aproximativ dublu. Inaltimea maxima a sectiunii este de 354 metri. Am setat 83 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 369. Estimare galerie nemasurata: 435 metri. Am notat 247 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:352. Informam administratia ariei protejate despre descoperirea de la sectorul 467.','doc_existing_c45_3.txt',751,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(854,'Document PeÈ™tera F4 din Piatra Lupului #4','Raport climatologic subteran - statia 356. Senzorul a inregistrat 111 cicluri complete de temperatura. Temperatura medie anuala: 44 grade Celsius. Amplitudinea termica maxima: 65 grade. Umiditatea relativa medie: 368 procente. Concentratia de CO2: 175 ppm. Curentul de aer maxim masurat: 90 metri pe secunda. Directia predominanta a curentului: sector 120. Datalogerul a functionat 274 zile fara intrerupere. Am descarcat 423 megabytes de date brute. Presiunea barometrica la intrare: 350 mbar. Evaporarea masurata: 190 milimetri pe luna. Am comparat datele cu 246 statii meteorologice de suprafata. Raportul complet include 201 grafice si tabele. Monitorizarea continua de 182 luni confirma stabilitatea climatica.','doc_existing_c45_4.txt',715,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(855,'Document PeÈ™tera F4 din Piatra Lupului #5','Raport climatologic subteran - statia 310. Senzorul a inregistrat 433 cicluri complete de temperatura. Temperatura medie anuala: 165 grade Celsius. Amplitudinea termica maxima: 418 grade. Umiditatea relativa medie: 84 procente. Concentratia de CO2: 292 ppm. Curentul de aer maxim masurat: 350 metri pe secunda. Directia predominanta a curentului: sector 345. Datalogerul a functionat 110 zile fara intrerupere. Am descarcat 368 megabytes de date brute. Presiunea barometrica la intrare: 350 mbar. Evaporarea masurata: 478 milimetri pe luna. Am comparat datele cu 262 statii meteorologice de suprafata. Raportul complet include 49 grafice si tabele. Monitorizarea continua de 436 luni confirma stabilitatea climatica.','doc_existing_c45_5.txt',716,NULL,'text_document',1775820085,NULL,NULL);
