INSERT INTO documentation_files VALUES(873,'Document PeÈ™tera F5 din Piatra Lupului #2','Registru vizitatori - luna 236. Total vizitatori inregistrati: 500. Dintre acestia, 21 au participat la ture ghidate. Am organizat 485 ture pentru grupuri scolare. Media participantilor per tura: 433 persoane. Am distribuit 278 pliante informative. Am colectat 109 chestionare de feedback. Nota medie acordata: 348 din 10. Am inregistrat 247 incidente minore. Veniturile din taxe: 440 lei. Am angajat 445 ghizi suplimentari. Programul de vizitare a fost extins cu 409 ore pe saptamana.','doc_existing_c46_2.txt',485,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(874,'Document PeÈ™tera F5 din Piatra Lupului #3','Plan de explorare - obiectiv 500. Am identificat 238 galerii laterale neexplorate. Lungimea estimata: 232 metri pe fiecare. Sunt necesare 44 zile de explorare. Echipa recomandata: 271 persoane. Echipament vertical necesar pentru 276 puturi. Am pregatit 420 kilograme de echipament. Rezerva de carbid: 208 kilograme. Punctul de plecare este statia topografica 150. Comunicarea radio va fi testata la 416 puncte. Am obtinut 417 autorizatii necesare. Data planificata: peste 310 saptamani. Bugetul estimat: 469 lei.','doc_existing_c46_3.txt',512,NULL,'text_document',1775820085,NULL,NULL);
