INSERT INTO documentation_files VALUES(907,'Document PeÈ™tera G2 din Piatra Lupului #9','Raport conservare patrimoniu - obiectiv 230. Am evaluat starea a 473 inscriptii istorice. Dintre acestea, 291 necesita interventie urgenta. Am curatat 427 metri patrati de graffiti modern. Am instalat 160 panouri informative la intrare. Bariera de protectie acopera 103 metri liniari. Am documentat 93 urme de vandalism. Raportul a fost transmis autoritatilor locale in 16 exemplare. Am propus clasificarea a 251 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 152 persoane simultan. Am instruit 421 ghizi locali. Costul estimat al lucrarilor: 140 lei. Termenul de finalizare: 70 luni.','doc_existing_c48_9.txt',603,NULL,'text_document',1775820085,NULL,NULL);
