INSERT INTO documentation_files VALUES(910,'Document PeÈ™tera G2 din Piatra Lupului #12','Fisa tehnica echipare put - verticala nr. 79. Adancimea: 386 metri. Am instalat 494 spituri din otel inoxidabil. Distanta intre spituri: 191 metri. Lungimea corzii principale: 460 metri. Coarda de siguranta: 307 metri. Am montat 107 protectoare de franghie. Fractionarea se face la 345 metri de buza putului. Deviatia este la 19 metri sub fractionare. Am testat echiparea cu 142 coborari. Ultimul control al spiturilor: acum 116 luni.','doc_existing_c48_12.txt',434,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(911,'Document PeÈ™tera G2 din Piatra Lupului #13','Jurnal de expeditie subterana - ziua 306. Am intrat in pestera la ora 71. Parcursul pana la tabara subterana a durat 441 ore. Am transportat 233 kilograme de echipament. La tabara temperatura era de 469 grade. Am montat 191 corturi in sala mare. Rezerva de apa potabila este de 424 litri. Am planificat 183 obiective de explorat. Primul obiectiv se afla la 212 metri de tabara. Comunicarea radio functioneaza pe o distanta de 133 metri. Am verificat starea corzilor pe 3 puturi. Am acumulat 281 ore de topografie. Fotodocumentarea a produs 381 imagini RAW. Urmatoarea tura de explorare incepe in 369 ore. Echipa este formata acum din 97 persoane active. Atmosfera din galeria inferioara contine 228 procente CO2. Am stabilit o limita de siguranta la 346 metri distanta. Stocul de baterii este suficient pentru 262 ore de functionare. Moralul echipei este excelent dupa 310 zile sub pamant.','doc_existing_c48_13.txt',889,NULL,'text_document',1775820085,NULL,NULL);
