INSERT INTO documentation_files VALUES(934,'Document PeÈ™tera G3 din Piatra Lupului #1','Fisa tehnica echipare put - verticala nr. 398. Adancimea: 347 metri. Am instalat 448 spituri din otel inoxidabil. Distanta intre spituri: 323 metri. Lungimea corzii principale: 291 metri. Coarda de siguranta: 357 metri. Am montat 99 protectoare de franghie. Fractionarea se face la 104 metri de buza putului. Deviatia este la 445 metri sub fractionare. Am testat echiparea cu 456 coborari. Ultimul control al spiturilor: acum 330 luni.','doc_existing_c49_1.txt',435,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(935,'Document PeÈ™tera G3 din Piatra Lupului #2','Registru vizitatori - luna 315. Total vizitatori inregistrati: 296. Dintre acestia, 287 au participat la ture ghidate. Am organizat 383 ture pentru grupuri scolare. Media participantilor per tura: 321 persoane. Am distribuit 281 pliante informative. Am colectat 406 chestionare de feedback. Nota medie acordata: 328 din 10. Am inregistrat 440 incidente minore. Veniturile din taxe: 9 lei. Am angajat 19 ghizi suplimentari. Programul de vizitare a fost extins cu 410 ore pe saptamana.','doc_existing_c49_2.txt',483,NULL,'text_document',1775820085,NULL,NULL);
