INSERT INTO documentation_files VALUES(938,'Document PeÈ™tera H1 din Piatra Lupului #1','Plan de explorare - obiectiv 394. Am identificat 330 galerii laterale neexplorate. Lungimea estimata: 68 metri pe fiecare. Sunt necesare 264 zile de explorare. Echipa recomandata: 298 persoane. Echipament vertical necesar pentru 136 puturi. Am pregatit 177 kilograme de echipament. Rezerva de carbid: 233 kilograme. Punctul de plecare este statia topografica 145. Comunicarea radio va fi testata la 30 puncte. Am obtinut 55 autorizatii necesare. Data planificata: peste 457 saptamani. Bugetul estimat: 426 lei.','doc_existing_c50_1.txt',510,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(939,'Document PeÈ™tera H1 din Piatra Lupului #2','Plan de explorare - obiectiv 313. Am identificat 369 galerii laterale neexplorate. Lungimea estimata: 85 metri pe fiecare. Sunt necesare 70 zile de explorare. Echipa recomandata: 205 persoane. Echipament vertical necesar pentru 237 puturi. Am pregatit 323 kilograme de echipament. Rezerva de carbid: 247 kilograme. Punctul de plecare este statia topografica 50. Comunicarea radio va fi testata la 406 puncte. Am obtinut 155 autorizatii necesare. Data planificata: peste 202 saptamani. Bugetul estimat: 25 lei.','doc_existing_c50_2.txt',509,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(940,'Document PeÈ™tera H1 din Piatra Lupului #3','Raport conservare patrimoniu - obiectiv 241. Am evaluat starea a 322 inscriptii istorice. Dintre acestea, 423 necesita interventie urgenta. Am curatat 372 metri patrati de graffiti modern. Am instalat 260 panouri informative la intrare. Bariera de protectie acopera 212 metri liniari. Am documentat 443 urme de vandalism. Raportul a fost transmis autoritatilor locale in 3 exemplare. Am propus clasificarea a 282 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 413 persoane simultan. Am instruit 162 ghizi locali. Costul estimat al lucrarilor: 285 lei. Termenul de finalizare: 391 luni.','doc_existing_c50_3.txt',604,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(941,'Document PeÈ™tera H1 din Piatra Lupului #4','Observatii topografice - tura nr. 437. Am efectuat 258 vizari cu busola si clinometrul. Lungimea poligonalei este de 171 metri. Diferenta de nivel totala: 227 metri. Am folosit statia nr. 464 ca baza. Eroarea de inchidere a poligonalei a fost sub 398 procente. Galeria prezinta un azimut predominant de 358 grade. Panta medie a galeriei este de 203 grade. Latimea variaza intre 325 si aproximativ dublu. Inaltimea maxima a sectiunii este de 270 metri. Am setat 46 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 438. Estimare galerie nemasurata: 47 metri. Am notat 93 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:221. Informam administratia ariei protejate despre descoperirea de la sectorul 85.','doc_existing_c50_4.txt',749,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(942,'Document PeÈ™tera H1 din Piatra Lupului #5','Plan de explorare - obiectiv 116. Am identificat 468 galerii laterale neexplorate. Lungimea estimata: 430 metri pe fiecare. Sunt necesare 418 zile de explorare. Echipa recomandata: 367 persoane. Echipament vertical necesar pentru 13 puturi. Am pregatit 144 kilograme de echipament. Rezerva de carbid: 112 kilograme. Punctul de plecare este statia topografica 114. Comunicarea radio va fi testata la 274 puncte. Am obtinut 331 autorizatii necesare. Data planificata: peste 137 saptamani. Bugetul estimat: 271 lei.','doc_existing_c50_5.txt',512,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(943,'Document PeÈ™tera H1 din Piatra Lupului #6','Jurnal de expeditie subterana - ziua 46. Am intrat in pestera la ora 155. Parcursul pana la tabara subterana a durat 419 ore. Am transportat 121 kilograme de echipament. La tabara temperatura era de 373 grade. Am montat 135 corturi in sala mare. Rezerva de apa potabila este de 415 litri. Am planificat 433 obiective de explorat. Primul obiectiv se afla la 349 metri de tabara. Comunicarea radio functioneaza pe o distanta de 221 metri. Am verificat starea corzilor pe 7 puturi. Am acumulat 225 ore de topografie. Fotodocumentarea a produs 65 imagini RAW. Urmatoarea tura de explorare incepe in 233 ore. Echipa este formata acum din 436 persoane active. Atmosfera din galeria inferioara contine 339 procente CO2. Am stabilit o limita de siguranta la 22 metri distanta. Stocul de baterii este suficient pentru 273 ore de functionare. Moralul echipei este excelent dupa 461 zile sub pamant.','doc_existing_c50_6.txt',888,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(944,'Document PeÈ™tera H1 din Piatra Lupului #7','Nota de mentenanta balize - traseul 4. Am verificat 366 balize reflectorizante. Dintre acestea, 483 au fost inlocuite. Am adaugat 265 balize noi in zonele nemarcate. Distanta medie intre balize: 343 metri. Am folosit 223 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 489 metri cu lampa frontala. Am eliminat 230 marcaje vechi si confuze. Traseul total balizat: 410 metri. Urmatoarea verificare: peste 500 luni. Materialul consumat: 9 benzi reflectorizante.','doc_existing_c50_7.txt',481,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(945,'Document PeÈ™tera H1 din Piatra Lupului #8','Inventar echipament - depozit subteran 405. Total corzi disponibile: 327 metri. Dintre acestea, 264 metri necesita inlocuire. Am verificat 322 carabiniere si 7 plachete. Corzi statice diametru 10mm: 381 bucati. Am adaugat 196 saci de transport noi. Lampi de rezerva: 240 bucati cu baterii pline. Stocul de carbid: 426 kilograme. Truse de prim ajutor: 285 complete, verificate. Echipamentul este depozitat la 108 metri de intrare. Urmatoarea verificare programata peste 340 saptamani. Am retras din uz 213 echipamente expirate. Bugetul anual de echipament: 29 lei.','doc_existing_c50_8.txt',563,NULL,'text_document',1775820085,NULL,NULL);
INSERT INTO documentation_files VALUES(946,'Document PeÈ™tera H1 din Piatra Lupului #9','Fisa tehnica echipare put - verticala nr. 329. Adancimea: 495 metri. Am instalat 176 spituri din otel inoxidabil. Distanta intre spituri: 194 metri. Lungimea corzii principale: 363 metri. Coarda de siguranta: 14 metri. Am montat 371 protectoare de franghie. Fractionarea se face la 220 metri de buza putului. Deviatia este la 45 metri sub fractionare. Am testat echiparea cu 387 coborari. Ultimul control al spiturilor: acum 292 luni.','doc_existing_c50_9.txt',434,NULL,'text_document',1775820085,NULL,NULL);
