INSERT INTO documentation_files VALUES(969,'Document PeÈ™tera H2 din Piatra Lupului #12','Nota de mentenanta balize - traseul 264. Am verificat 73 balize reflectorizante. Dintre acestea, 383 au fost inlocuite. Am adaugat 320 balize noi in zonele nemarcate. Distanta medie intre balize: 50 metri. Am folosit 13 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 144 metri cu lampa frontala. Am eliminat 102 marcaje vechi si confuze. Traseul total balizat: 284 metri. Urmatoarea verificare: peste 331 luni. Materialul consumat: 125 benzi reflectorizante.','doc_existing_c51_12.txt',482,NULL,'text_document',1775820085,NULL,NULL);
