INSERT INTO documentation_files VALUES(987,'Document PeÈ™tera H3 din Piatra Lupului #2','Observatii topografice - tura nr. 61. Am efectuat 118 vizari cu busola si clinometrul. Lungimea poligonalei este de 221 metri. Diferenta de nivel totala: 274 metri. Am folosit statia nr. 90 ca baza. Eroarea de inchidere a poligonalei a fost sub 103 procente. Galeria prezinta un azimut predominant de 491 grade. Panta medie a galeriei este de 278 grade. Latimea variaza intre 307 si aproximativ dublu. Inaltimea maxima a sectiunii este de 341 metri. Am setat 174 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 394. Estimare galerie nemasurata: 427 metri. Am notat 38 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:313. Informam administratia ariei protejate despre descoperirea de la sectorul 424.','doc_existing_c52_2.txt',750,NULL,'text_document',1775820085,NULL,NULL);
