INSERT INTO documentation_files VALUES(998,'Document PeÈ™tera H4 din Piatra Lupului #5','Jurnal de expeditie subterana - ziua 291. Am intrat in pestera la ora 134. Parcursul pana la tabara subterana a durat 79 ore. Am transportat 138 kilograme de echipament. La tabara temperatura era de 436 grade. Am montat 348 corturi in sala mare. Rezerva de apa potabila este de 121 litri. Am planificat 306 obiective de explorat. Primul obiectiv se afla la 183 metri de tabara. Comunicarea radio functioneaza pe o distanta de 120 metri. Am verificat starea corzilor pe 399 puturi. Am acumulat 305 ore de topografie. Fotodocumentarea a produs 51 imagini RAW. Urmatoarea tura de explorare incepe in 279 ore. Echipa este formata acum din 198 persoane active. Atmosfera din galeria inferioara contine 78 procente CO2. Am stabilit o limita de siguranta la 489 metri distanta. Stocul de baterii este suficient pentru 266 ore de functionare. Moralul echipei este excelent dupa 182 zile sub pamant.','doc_existing_c53_5.txt',890,NULL,'text_document',1775820085,NULL,NULL);
