INSERT INTO documentation_files VALUES(1032,'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #9','Raport conservare patrimoniu - obiectiv 296. Am evaluat starea a 375 inscriptii istorice. Dintre acestea, 91 necesita interventie urgenta. Am curatat 59 metri patrati de graffiti modern. Am instalat 495 panouri informative la intrare. Bariera de protectie acopera 102 metri liniari. Am documentat 261 urme de vandalism. Raportul a fost transmis autoritatilor locale in 79 exemplare. Am propus clasificarea a 56 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 455 persoane simultan. Am instruit 341 ghizi locali. Costul estimat al lucrarilor: 484 lei. Termenul de finalizare: 116 luni.','doc_existing_c55_9.txt',602,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1033,'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #10','Observatii topografice - tura nr. 457. Am efectuat 430 vizari cu busola si clinometrul. Lungimea poligonalei este de 291 metri. Diferenta de nivel totala: 492 metri. Am folosit statia nr. 434 ca baza. Eroarea de inchidere a poligonalei a fost sub 347 procente. Galeria prezinta un azimut predominant de 265 grade. Panta medie a galeriei este de 64 grade. Latimea variaza intre 396 si aproximativ dublu. Inaltimea maxima a sectiunii este de 216 metri. Am setat 63 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 425. Estimare galerie nemasurata: 448 metri. Am notat 259 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:135. Informam administratia ariei protejate despre descoperirea de la sectorul 418.','doc_existing_c55_10.txt',751,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1034,'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #11','Raport conservare patrimoniu - obiectiv 270. Am evaluat starea a 448 inscriptii istorice. Dintre acestea, 305 necesita interventie urgenta. Am curatat 63 metri patrati de graffiti modern. Am instalat 261 panouri informative la intrare. Bariera de protectie acopera 359 metri liniari. Am documentat 426 urme de vandalism. Raportul a fost transmis autoritatilor locale in 154 exemplare. Am propus clasificarea a 291 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 485 persoane simultan. Am instruit 61 ghizi locali. Costul estimat al lucrarilor: 220 lei. Termenul de finalizare: 243 luni.','doc_existing_c55_11.txt',604,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1035,'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #12','Inventar echipament - depozit subteran 179. Total corzi disponibile: 279 metri. Dintre acestea, 415 metri necesita inlocuire. Am verificat 395 carabiniere si 385 plachete. Corzi statice diametru 10mm: 12 bucati. Am adaugat 431 saci de transport noi. Lampi de rezerva: 464 bucati cu baterii pline. Stocul de carbid: 430 kilograme. Truse de prim ajutor: 385 complete, verificate. Echipamentul este depozitat la 297 metri de intrare. Urmatoarea verificare programata peste 86 saptamani. Am retras din uz 431 echipamente expirate. Bugetul anual de echipament: 43 lei.','doc_existing_c55_12.txt',563,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1036,'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #13','Jurnal de expeditie subterana - ziua 487. Am intrat in pestera la ora 207. Parcursul pana la tabara subterana a durat 376 ore. Am transportat 347 kilograme de echipament. La tabara temperatura era de 160 grade. Am montat 284 corturi in sala mare. Rezerva de apa potabila este de 220 litri. Am planificat 208 obiective de explorat. Primul obiectiv se afla la 267 metri de tabara. Comunicarea radio functioneaza pe o distanta de 392 metri. Am verificat starea corzilor pe 12 puturi. Am acumulat 248 ore de topografie. Fotodocumentarea a produs 348 imagini RAW. Urmatoarea tura de explorare incepe in 318 ore. Echipa este formata acum din 351 persoane active. Atmosfera din galeria inferioara contine 229 procente CO2. Am stabilit o limita de siguranta la 444 metri distanta. Stocul de baterii este suficient pentru 460 ore de functionare. Moralul echipei este excelent dupa 339 zile sub pamant.','doc_existing_c55_13.txt',892,NULL,'text_document',1775820086,NULL,NULL);
