INSERT INTO documentation_files VALUES(1056,'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #4','Raport climatologic subteran - statia 181. Senzorul a inregistrat 411 cicluri complete de temperatura. Temperatura medie anuala: 113 grade Celsius. Amplitudinea termica maxima: 91 grade. Umiditatea relativa medie: 106 procente. Concentratia de CO2: 5 ppm. Curentul de aer maxim masurat: 235 metri pe secunda. Directia predominanta a curentului: sector 437. Datalogerul a functionat 319 zile fara intrerupere. Am descarcat 180 megabytes de date brute. Presiunea barometrica la intrare: 328 mbar. Evaporarea masurata: 28 milimetri pe luna. Am comparat datele cu 322 statii meteorologice de suprafata. Raportul complet include 304 grafice si tabele. Monitorizarea continua de 152 luni confirma stabilitatea climatica.','doc_existing_c56_4.txt',714,NULL,'text_document',1775820086,NULL,NULL);
