INSERT INTO documentation_files VALUES(1084,'Document PeÈ™tera CaroleÈ™tilor #1','Plan de explorare - obiectiv 500. Am identificat 22 galerii laterale neexplorate. Lungimea estimata: 268 metri pe fiecare. Sunt necesare 150 zile de explorare. Echipa recomandata: 302 persoane. Echipament vertical necesar pentru 149 puturi. Am pregatit 402 kilograme de echipament. Rezerva de carbid: 98 kilograme. Punctul de plecare este statia topografica 482. Comunicarea radio va fi testata la 277 puncte. Am obtinut 372 autorizatii necesare. Data planificata: peste 160 saptamani. Bugetul estimat: 2 lei.','doc_existing_c58_1.txt',509,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1085,'Document PeÈ™tera CaroleÈ™tilor #2','Registru vizitatori - luna 484. Total vizitatori inregistrati: 93. Dintre acestia, 267 au participat la ture ghidate. Am organizat 486 ture pentru grupuri scolare. Media participantilor per tura: 378 persoane. Am distribuit 170 pliante informative. Am colectat 314 chestionare de feedback. Nota medie acordata: 20 din 10. Am inregistrat 251 incidente minore. Veniturile din taxe: 248 lei. Am angajat 119 ghizi suplimentari. Programul de vizitare a fost extins cu 393 ore pe saptamana.','doc_existing_c58_2.txt',484,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1086,'Document PeÈ™tera CaroleÈ™tilor #3','Inventar echipament - depozit subteran 464. Total corzi disponibile: 374 metri. Dintre acestea, 39 metri necesita inlocuire. Am verificat 477 carabiniere si 492 plachete. Corzi statice diametru 10mm: 414 bucati. Am adaugat 465 saci de transport noi. Lampi de rezerva: 483 bucati cu baterii pline. Stocul de carbid: 341 kilograme. Truse de prim ajutor: 306 complete, verificate. Echipamentul este depozitat la 200 metri de intrare. Urmatoarea verificare programata peste 156 saptamani. Am retras din uz 200 echipamente expirate. Bugetul anual de echipament: 80 lei.','doc_existing_c58_3.txt',564,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1087,'Document PeÈ™tera CaroleÈ™tilor #4','Raport climatologic subteran - statia 428. Senzorul a inregistrat 336 cicluri complete de temperatura. Temperatura medie anuala: 81 grade Celsius. Amplitudinea termica maxima: 490 grade. Umiditatea relativa medie: 329 procente. Concentratia de CO2: 388 ppm. Curentul de aer maxim masurat: 164 metri pe secunda. Directia predominanta a curentului: sector 480. Datalogerul a functionat 276 zile fara intrerupere. Am descarcat 326 megabytes de date brute. Presiunea barometrica la intrare: 385 mbar. Evaporarea masurata: 455 milimetri pe luna. Am comparat datele cu 98 statii meteorologice de suprafata. Raportul complet include 409 grafice si tabele. Monitorizarea continua de 428 luni confirma stabilitatea climatica.','doc_existing_c58_4.txt',716,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1088,'Document PeÈ™tera CaroleÈ™tilor #5','Jurnal de expeditie subterana - ziua 332. Am intrat in pestera la ora 199. Parcursul pana la tabara subterana a durat 464 ore. Am transportat 416 kilograme de echipament. La tabara temperatura era de 311 grade. Am montat 121 corturi in sala mare. Rezerva de apa potabila este de 251 litri. Am planificat 369 obiective de explorat. Primul obiectiv se afla la 464 metri de tabara. Comunicarea radio functioneaza pe o distanta de 8 metri. Am verificat starea corzilor pe 227 puturi. Am acumulat 301 ore de topografie. Fotodocumentarea a produs 225 imagini RAW. Urmatoarea tura de explorare incepe in 274 ore. Echipa este formata acum din 226 persoane active. Atmosfera din galeria inferioara contine 435 procente CO2. Am stabilit o limita de siguranta la 382 metri distanta. Stocul de baterii este suficient pentru 148 ore de functionare. Moralul echipei este excelent dupa 178 zile sub pamant.','doc_existing_c58_5.txt',891,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1089,'Document PeÈ™tera CaroleÈ™tilor #6','Raport climatologic subteran - statia 201. Senzorul a inregistrat 260 cicluri complete de temperatura. Temperatura medie anuala: 52 grade Celsius. Amplitudinea termica maxima: 182 grade. Umiditatea relativa medie: 179 procente. Concentratia de CO2: 322 ppm. Curentul de aer maxim masurat: 280 metri pe secunda. Directia predominanta a curentului: sector 133. Datalogerul a functionat 45 zile fara intrerupere. Am descarcat 289 megabytes de date brute. Presiunea barometrica la intrare: 170 mbar. Evaporarea masurata: 12 milimetri pe luna. Am comparat datele cu 473 statii meteorologice de suprafata. Raportul complet include 90 grafice si tabele. Monitorizarea continua de 107 luni confirma stabilitatea climatica.','doc_existing_c58_6.txt',714,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1090,'Document PeÈ™tera CaroleÈ™tilor #7','Raport conservare patrimoniu - obiectiv 423. Am evaluat starea a 84 inscriptii istorice. Dintre acestea, 442 necesita interventie urgenta. Am curatat 236 metri patrati de graffiti modern. Am instalat 371 panouri informative la intrare. Bariera de protectie acopera 306 metri liniari. Am documentat 313 urme de vandalism. Raportul a fost transmis autoritatilor locale in 268 exemplare. Am propus clasificarea a 76 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 356 persoane simultan. Am instruit 460 ghizi locali. Costul estimat al lucrarilor: 326 lei. Termenul de finalizare: 326 luni.','doc_existing_c58_7.txt',604,NULL,'text_document',1775820086,NULL,NULL);
