INSERT INTO documentation_files VALUES(1112,'Document PeÈ™tera nr. 2 din Dealul Bulz #1','Nota de mentenanta balize - traseul 323. Am verificat 444 balize reflectorizante. Dintre acestea, 320 au fost inlocuite. Am adaugat 342 balize noi in zonele nemarcate. Distanta medie intre balize: 471 metri. Am folosit 28 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 148 metri cu lampa frontala. Am eliminat 297 marcaje vechi si confuze. Traseul total balizat: 151 metri. Urmatoarea verificare: peste 165 luni. Materialul consumat: 194 benzi reflectorizante.','doc_existing_c59_1.txt',484,NULL,'text_document',1775820086,NULL,NULL);
