INSERT INTO documentation_files VALUES(1128,'Document PeÈ™tera "Hotel" #1','Jurnal de expeditie subterana - ziua 397. Am intrat in pestera la ora 260. Parcursul pana la tabara subterana a durat 184 ore. Am transportat 152 kilograme de echipament. La tabara temperatura era de 281 grade. Am montat 432 corturi in sala mare. Rezerva de apa potabila este de 203 litri. Am planificat 203 obiective de explorat. Primul obiectiv se afla la 431 metri de tabara. Comunicarea radio functioneaza pe o distanta de 84 metri. Am verificat starea corzilor pe 40 puturi. Am acumulat 361 ore de topografie. Fotodocumentarea a produs 427 imagini RAW. Urmatoarea tura de explorare incepe in 90 ore. Echipa este formata acum din 449 persoane active. Atmosfera din galeria inferioara contine 218 procente CO2. Am stabilit o limita de siguranta la 494 metri distanta. Stocul de baterii este suficient pentru 497 ore de functionare. Moralul echipei este excelent dupa 126 zile sub pamant.','doc_existing_c60_1.txt',890,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1129,'Document PeÈ™tera "Hotel" #2','Fisa tehnica echipare put - verticala nr. 293. Adancimea: 53 metri. Am instalat 5 spituri din otel inoxidabil. Distanta intre spituri: 295 metri. Lungimea corzii principale: 121 metri. Coarda de siguranta: 303 metri. Am montat 473 protectoare de franghie. Fractionarea se face la 224 metri de buza putului. Deviatia este la 34 metri sub fractionare. Am testat echiparea cu 38 coborari. Ultimul control al spiturilor: acum 91 luni.','doc_existing_c60_2.txt',430,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1130,'Document PeÈ™tera "Hotel" #3','Observatii topografice - tura nr. 394. Am efectuat 114 vizari cu busola si clinometrul. Lungimea poligonalei este de 36 metri. Diferenta de nivel totala: 302 metri. Am folosit statia nr. 181 ca baza. Eroarea de inchidere a poligonalei a fost sub 286 procente. Galeria prezinta un azimut predominant de 453 grade. Panta medie a galeriei este de 388 grade. Latimea variaza intre 92 si aproximativ dublu. Inaltimea maxima a sectiunii este de 125 metri. Am setat 490 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 317. Estimare galerie nemasurata: 155 metri. Am notat 280 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:284. Informam administratia ariei protejate despre descoperirea de la sectorul 26.','doc_existing_c60_3.txt',750,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1131,'Document PeÈ™tera "Hotel" #4','Nota de mentenanta balize - traseul 447. Am verificat 483 balize reflectorizante. Dintre acestea, 345 au fost inlocuite. Am adaugat 295 balize noi in zonele nemarcate. Distanta medie intre balize: 321 metri. Am folosit 79 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 267 metri cu lampa frontala. Am eliminat 353 marcaje vechi si confuze. Traseul total balizat: 409 metri. Urmatoarea verificare: peste 307 luni. Materialul consumat: 137 benzi reflectorizante.','doc_existing_c60_4.txt',484,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1132,'Document PeÈ™tera "Hotel" #5','Raport conservare patrimoniu - obiectiv 44. Am evaluat starea a 343 inscriptii istorice. Dintre acestea, 162 necesita interventie urgenta. Am curatat 6 metri patrati de graffiti modern. Am instalat 224 panouri informative la intrare. Bariera de protectie acopera 127 metri liniari. Am documentat 237 urme de vandalism. Raportul a fost transmis autoritatilor locale in 282 exemplare. Am propus clasificarea a 133 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 441 persoane simultan. Am instruit 280 ghizi locali. Costul estimat al lucrarilor: 239 lei. Termenul de finalizare: 58 luni.','doc_existing_c60_5.txt',602,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1133,'Document PeÈ™tera "Hotel" #6','Nota de mentenanta balize - traseul 377. Am verificat 238 balize reflectorizante. Dintre acestea, 150 au fost inlocuite. Am adaugat 273 balize noi in zonele nemarcate. Distanta medie intre balize: 17 metri. Am folosit 284 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 133 metri cu lampa frontala. Am eliminat 200 marcaje vechi si confuze. Traseul total balizat: 316 metri. Urmatoarea verificare: peste 94 luni. Materialul consumat: 85 benzi reflectorizante.','doc_existing_c60_6.txt',482,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1134,'Document PeÈ™tera "Hotel" #7','Jurnal de expeditie subterana - ziua 386. Am intrat in pestera la ora 500. Parcursul pana la tabara subterana a durat 364 ore. Am transportat 215 kilograme de echipament. La tabara temperatura era de 445 grade. Am montat 169 corturi in sala mare. Rezerva de apa potabila este de 365 litri. Am planificat 286 obiective de explorat. Primul obiectiv se afla la 325 metri de tabara. Comunicarea radio functioneaza pe o distanta de 375 metri. Am verificat starea corzilor pe 277 puturi. Am acumulat 136 ore de topografie. Fotodocumentarea a produs 55 imagini RAW. Urmatoarea tura de explorare incepe in 382 ore. Echipa este formata acum din 256 persoane active. Atmosfera din galeria inferioara contine 356 procente CO2. Am stabilit o limita de siguranta la 132 metri distanta. Stocul de baterii este suficient pentru 174 ore de functionare. Moralul echipei este excelent dupa 190 zile sub pamant.','doc_existing_c60_7.txt',892,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1135,'Document PeÈ™tera "Hotel" #8','Raport climatologic subteran - statia 47. Senzorul a inregistrat 482 cicluri complete de temperatura. Temperatura medie anuala: 177 grade Celsius. Amplitudinea termica maxima: 466 grade. Umiditatea relativa medie: 312 procente. Concentratia de CO2: 442 ppm. Curentul de aer maxim masurat: 243 metri pe secunda. Directia predominanta a curentului: sector 324. Datalogerul a functionat 215 zile fara intrerupere. Am descarcat 205 megabytes de date brute. Presiunea barometrica la intrare: 69 mbar. Evaporarea masurata: 58 milimetri pe luna. Am comparat datele cu 41 statii meteorologice de suprafata. Raportul complet include 392 grafice si tabele. Monitorizarea continua de 235 luni confirma stabilitatea climatica.','doc_existing_c60_8.txt',714,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1136,'Document PeÈ™tera "Hotel" #9','Observatii topografice - tura nr. 179. Am efectuat 190 vizari cu busola si clinometrul. Lungimea poligonalei este de 36 metri. Diferenta de nivel totala: 289 metri. Am folosit statia nr. 383 ca baza. Eroarea de inchidere a poligonalei a fost sub 397 procente. Galeria prezinta un azimut predominant de 372 grade. Panta medie a galeriei este de 89 grade. Latimea variaza intre 222 si aproximativ dublu. Inaltimea maxima a sectiunii este de 407 metri. Am setat 444 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 296. Estimare galerie nemasurata: 182 metri. Am notat 451 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:448. Informam administratia ariei protejate despre descoperirea de la sectorul 466.','doc_existing_c60_9.txt',751,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1137,'Document PeÈ™tera "Hotel" #10','Inventar echipament - depozit subteran 247. Total corzi disponibile: 384 metri. Dintre acestea, 105 metri necesita inlocuire. Am verificat 275 carabiniere si 248 plachete. Corzi statice diametru 10mm: 8 bucati. Am adaugat 365 saci de transport noi. Lampi de rezerva: 476 bucati cu baterii pline. Stocul de carbid: 306 kilograme. Truse de prim ajutor: 50 complete, verificate. Echipamentul este depozitat la 249 metri de intrare. Urmatoarea verificare programata peste 414 saptamani. Am retras din uz 454 echipamente expirate. Bugetul anual de echipament: 60 lei.','doc_existing_c60_10.txt',562,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1138,'Document PeÈ™tera "Hotel" #11','Plan de explorare - obiectiv 151. Am identificat 410 galerii laterale neexplorate. Lungimea estimata: 348 metri pe fiecare. Sunt necesare 449 zile de explorare. Echipa recomandata: 336 persoane. Echipament vertical necesar pentru 467 puturi. Am pregatit 223 kilograme de echipament. Rezerva de carbid: 79 kilograme. Punctul de plecare este statia topografica 104. Comunicarea radio va fi testata la 468 puncte. Am obtinut 10 autorizatii necesare. Data planificata: peste 180 saptamani. Bugetul estimat: 325 lei.','doc_existing_c60_11.txt',511,NULL,'text_document',1775820086,NULL,NULL);
