INSERT INTO documentation_files VALUES(1170,'Document PeÈ™tera nr. 1 din Bulz #12','Raport conservare patrimoniu - obiectiv 235. Am evaluat starea a 436 inscriptii istorice. Dintre acestea, 256 necesita interventie urgenta. Am curatat 154 metri patrati de graffiti modern. Am instalat 223 panouri informative la intrare. Bariera de protectie acopera 497 metri liniari. Am documentat 109 urme de vandalism. Raportul a fost transmis autoritatilor locale in 385 exemplare. Am propus clasificarea a 228 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 408 persoane simultan. Am instruit 161 ghizi locali. Costul estimat al lucrarilor: 80 lei. Termenul de finalizare: 311 luni.','doc_existing_c62_12.txt',605,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1171,'Document PeÈ™tera nr. 1 din Bulz #13','Registru vizitatori - luna 128. Total vizitatori inregistrati: 3. Dintre acestia, 441 au participat la ture ghidate. Am organizat 466 ture pentru grupuri scolare. Media participantilor per tura: 122 persoane. Am distribuit 51 pliante informative. Am colectat 357 chestionare de feedback. Nota medie acordata: 204 din 10. Am inregistrat 254 incidente minore. Veniturile din taxe: 218 lei. Am angajat 406 ghizi suplimentari. Programul de vizitare a fost extins cu 159 ore pe saptamana.','doc_existing_c62_13.txt',483,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1172,'Document PeÈ™tera nr. 1 din Bulz #14','Fisa tehnica echipare put - verticala nr. 245. Adancimea: 81 metri. Am instalat 37 spituri din otel inoxidabil. Distanta intre spituri: 223 metri. Lungimea corzii principale: 7 metri. Coarda de siguranta: 41 metri. Am montat 181 protectoare de franghie. Fractionarea se face la 350 metri de buza putului. Deviatia este la 38 metri sub fractionare. Am testat echiparea cu 109 coborari. Ultimul control al spiturilor: acum 315 luni.','doc_existing_c62_14.txt',430,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1173,'Document PeÈ™tera nr. 1 din Bulz #15','Inventar echipament - depozit subteran 417. Total corzi disponibile: 303 metri. Dintre acestea, 71 metri necesita inlocuire. Am verificat 399 carabiniere si 228 plachete. Corzi statice diametru 10mm: 165 bucati. Am adaugat 217 saci de transport noi. Lampi de rezerva: 432 bucati cu baterii pline. Stocul de carbid: 410 kilograme. Truse de prim ajutor: 331 complete, verificate. Echipamentul este depozitat la 67 metri de intrare. Urmatoarea verificare programata peste 241 saptamani. Am retras din uz 264 echipamente expirate. Bugetul anual de echipament: 164 lei.','doc_existing_c62_15.txt',564,NULL,'text_document',1775820086,NULL,NULL);
INSERT INTO documentation_files VALUES(1174,'Document PeÈ™tera nr. 1 din Bulz #16','Observatii topografice - tura nr. 71. Am efectuat 125 vizari cu busola si clinometrul. Lungimea poligonalei este de 475 metri. Diferenta de nivel totala: 299 metri. Am folosit statia nr. 455 ca baza. Eroarea de inchidere a poligonalei a fost sub 290 procente. Galeria prezinta un azimut predominant de 294 grade. Panta medie a galeriei este de 468 grade. Latimea variaza intre 95 si aproximativ dublu. Inaltimea maxima a sectiunii este de 404 metri. Am setat 331 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 338. Estimare galerie nemasurata: 420 metri. Am notat 18 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:259. Informam administratia ariei protejate despre descoperirea de la sectorul 404.','doc_existing_c62_16.txt',750,NULL,'text_document',1775820086,NULL,NULL);
