INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1182, 'Document P. Ponorul Suspendat #1', 'Fisa tehnica echipare put - verticala nr. 262. Adancimea: 128 metri. Am instalat 10 spituri din otel inoxidabil. Distanta intre spituri: 122 metri. Lungimea corzii principale: 328 metri. Coarda de siguranta: 131 metri. Am montat 215 protectoare de franghie. Fractionarea se face la 356 metri de buza putului. Deviatia este la 169 metri sub fractionare. Am testat echiparea cu 477 coborari. Ultimul control al spiturilor: acum 127 luni.', 'doc_existing_c1_1.txt', 435, NULL, 'text_document', 1775839973);
