INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1183, 'Document P. Ponorul Suspendat #2', 'Evaluare risc - sectorul 434. Am identificat 361 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 489 centimetri. Nivelul apei poate creste cu 201 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 263 metri. Am instalat 101 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 21 minute. Echipamentul de prim ajutor este pozitionat la statia 472. Am testat comunicarea radio in 26 puncte critice. Semnalul radio este pierdut dupa 428 metri de la intrare. Am recomandat echipa minima de 440 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 200 ore. Protocoalele de securitate au fost revizuite de 499 ori anul acesta. Ultimul incident a avut loc cu 210 luni in urma. Am efectuat 276 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 308.', 'doc_existing_c1_2.txt', 889, NULL, 'text_document', 1775839973);
