INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1184, 'Document P. Ponorul Suspendat #3', 'Fisa tehnica echipare put - verticala nr. 47. Adancimea: 164 metri. Am instalat 490 spituri din otel inoxidabil. Distanta intre spituri: 132 metri. Lungimea corzii principale: 333 metri. Coarda de siguranta: 415 metri. Am montat 393 protectoare de franghie. Fractionarea se face la 290 metri de buza putului. Deviatia este la 484 metri sub fractionare. Am testat echiparea cu 160 coborari. Ultimul control al spiturilor: acum 253 luni.', 'doc_existing_c1_3.txt', 435, NULL, 'text_document', 1775839973);
