INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1190, 'Document P. Ponorul Suspendat #9', 'Raport conservare patrimoniu - obiectiv 233. Am evaluat starea a 201 inscriptii istorice. Dintre acestea, 301 necesita interventie urgenta. Am curatat 355 metri patrati de graffiti modern. Am instalat 220 panouri informative la intrare. Bariera de protectie acopera 111 metri liniari. Am documentat 446 urme de vandalism. Raportul a fost transmis autoritatilor locale in 397 exemplare. Am propus clasificarea a 356 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 271 persoane simultan. Am instruit 54 ghizi locali. Costul estimat al lucrarilor: 206 lei. Termenul de finalizare: 371 luni.', 'doc_existing_c1_9.txt', 605, NULL, 'text_document', 1775839973);
