INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1194, 'Document P. Ponorul Suspendat #13', 'Proces verbal intalnire club - sedinta nr. 443. Au participat 50 membri. Am discutat 95 puncte pe ordinea de zi. S-a aprobat bugetul de 392 lei pentru trimestrul urmator. Am planificat 173 expeditii in urmatoarele luni. S-au inscris 398 membri noi. Am evaluat 229 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 153 lei. Urmatoarea sedinta: peste 255 saptamani. Am desemnat 193 responsabili pentru proiecte.', 'doc_existing_c1_13.txt', 435, NULL, 'text_document', 1775839973);
