INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1195, 'Document P. Ponorul Suspendat #14', 'Evaluare risc - sectorul 65. Am identificat 461 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 273 centimetri. Nivelul apei poate creste cu 152 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 404 metri. Am instalat 376 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 112 minute. Echipamentul de prim ajutor este pozitionat la statia 424. Am testat comunicarea radio in 366 puncte critice. Semnalul radio este pierdut dupa 384 metri de la intrare. Am recomandat echipa minima de 374 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 470 ore. Protocoalele de securitate au fost revizuite de 283 ori anul acesta. Ultimul incident a avut loc cu 382 luni in urma. Am efectuat 379 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 470.', 'doc_existing_c1_14.txt', 890, NULL, 'text_document', 1775839973);
