INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1196, 'Document P. Ponorul Suspendat #15', 'Raport climatologic subteran - statia 318. Senzorul a inregistrat 306 cicluri complete de temperatura. Temperatura medie anuala: 129 grade Celsius. Amplitudinea termica maxima: 347 grade. Umiditatea relativa medie: 443 procente. Concentratia de CO2: 451 ppm. Curentul de aer maxim masurat: 317 metri pe secunda. Directia predominanta a curentului: sector 330. Datalogerul a functionat 436 zile fara intrerupere. Am descarcat 231 megabytes de date brute. Presiunea barometrica la intrare: 181 mbar. Evaporarea masurata: 382 milimetri pe luna. Am comparat datele cu 316 statii meteorologice de suprafata. Raportul complet include 244 grafice si tabele. Monitorizarea continua de 54 luni confirma stabilitatea climatica.', 'doc_existing_c1_15.txt', 717, NULL, 'text_document', 1775839973);
