INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1212, 'Document P. Ponorul Nou #6', 'Nota de mentenanta balize - traseul 69. Am verificat 119 balize reflectorizante. Dintre acestea, 459 au fost inlocuite. Am adaugat 122 balize noi in zonele nemarcate. Distanta medie intre balize: 378 metri. Am folosit 359 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 111 metri cu lampa frontala. Am eliminat 38 marcaje vechi si confuze. Traseul total balizat: 446 metri. Urmatoarea verificare: peste 292 luni. Materialul consumat: 273 benzi reflectorizante.', 'doc_existing_c2_6.txt', 483, NULL, 'text_document', 1775839973);
