INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1213, 'Document P. Ponorul Nou #7', 'Raport climatologic subteran - statia 485. Senzorul a inregistrat 359 cicluri complete de temperatura. Temperatura medie anuala: 422 grade Celsius. Amplitudinea termica maxima: 203 grade. Umiditatea relativa medie: 137 procente. Concentratia de CO2: 499 ppm. Curentul de aer maxim masurat: 402 metri pe secunda. Directia predominanta a curentului: sector 163. Datalogerul a functionat 464 zile fara intrerupere. Am descarcat 260 megabytes de date brute. Presiunea barometrica la intrare: 173 mbar. Evaporarea masurata: 351 milimetri pe luna. Am comparat datele cu 476 statii meteorologice de suprafata. Raportul complet include 431 grafice si tabele. Monitorizarea continua de 4 luni confirma stabilitatea climatica.', 'doc_existing_c2_7.txt', 716, NULL, 'text_document', 1775839973);
