INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1219, 'Document P. Ponorul Nou #13', 'Nota de mentenanta balize - traseul 425. Am verificat 149 balize reflectorizante. Dintre acestea, 333 au fost inlocuite. Am adaugat 429 balize noi in zonele nemarcate. Distanta medie intre balize: 88 metri. Am folosit 157 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 318 metri cu lampa frontala. Am eliminat 71 marcaje vechi si confuze. Traseul total balizat: 481 metri. Urmatoarea verificare: peste 41 luni. Materialul consumat: 408 benzi reflectorizante.', 'doc_existing_c2_13.txt', 482, NULL, 'text_document', 1775839973);
