INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1221, 'Document P. Ponorul Nou #15', 'Fisa tehnica echipare put - verticala nr. 371. Adancimea: 159 metri. Am instalat 104 spituri din otel inoxidabil. Distanta intre spituri: 456 metri. Lungimea corzii principale: 56 metri. Coarda de siguranta: 418 metri. Am montat 494 protectoare de franghie. Fractionarea se face la 386 metri de buza putului. Deviatia este la 115 metri sub fractionare. Am testat echiparea cu 446 coborari. Ultimul control al spiturilor: acum 66 luni.', 'doc_existing_c2_15.txt', 434, NULL, 'text_document', 1775839973);
