INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1247, 'Document P. Gaura cu VÃ¢jgÄƒu #7', 'Nota de mentenanta balize - traseul 113. Am verificat 64 balize reflectorizante. Dintre acestea, 488 au fost inlocuite. Am adaugat 172 balize noi in zonele nemarcate. Distanta medie intre balize: 272 metri. Am folosit 438 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 373 metri cu lampa frontala. Am eliminat 128 marcaje vechi si confuze. Traseul total balizat: 365 metri. Urmatoarea verificare: peste 415 luni. Materialul consumat: 393 benzi reflectorizante.', 'doc_existing_c3_7.txt', 484, NULL, 'text_document', 1775839973);
