INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1250, 'Document PeÈ™tera AscendentÄƒ din Guguiova #1', 'Evidenta resurse hidrologice - punctul 138. Debitul mediu masurat: 386 litri pe secunda. Am efectuat 384 masuratori in perioade diferite. Temperatura apei: 287 grade Celsius, constanta. pH-ul masurat: 384 unitati. Conductivitatea electrica: 307 microsiemensi. Am injectat 387 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 487 ore. Distanta estimata: 152 metri de conducte carstice. Nivelul maxim in sezonul ploios: 255 centimetri peste normal. Am monitorizat 379 izvoare din bazin. Volumul estimat al lacului subteran: 296 metri cubi.', 'doc_existing_c4_1.txt', 549, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2935, 4, 'cave', 1250, 1775839974);
