INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1251, 'Document PeÈ™tera AscendentÄƒ din Guguiova #2', 'Fisa tehnica echipare put - verticala nr. 103. Adancimea: 421 metri. Am instalat 301 spituri din otel inoxidabil. Distanta intre spituri: 188 metri. Lungimea corzii principale: 498 metri. Coarda de siguranta: 51 metri. Am montat 125 protectoare de franghie. Fractionarea se face la 317 metri de buza putului. Deviatia este la 324 metri sub fractionare. Am testat echiparea cu 207 coborari. Ultimul control al spiturilor: acum 193 luni.', 'doc_existing_c4_2.txt', 435, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2938, 4, 'cave', 1251, 1775839974);
