INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1252, 'Document PeÈ™tera AscendentÄƒ din Guguiova #3', 'Studiu speleogenetic - sectorul 424. Am analizat 337 probe de calcar sub microscop. Varsta estimata a galeriei: 425 milioane de ani. Am identificat 364 faze de speleogeneza. Nivelul freatic actual este la 14 metri adancime. Am corelat cu 29 alte pesteri din zona. Porozitatea medie a rocii: 25 procente. Am realizat 245 sectiuni subtiri din probe. Studiul va fi publicat in volumul 86 al buletinului. Am colaborat cu 190 geologi specialisti.', 'doc_existing_c4_3.txt', 441, NULL, 'text_document', 1775839974);
