INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1256, 'Document PeÈ™tera AscendentÄƒ din Guguiova #7', 'Raport climatologic subteran - statia 122. Senzorul a inregistrat 347 cicluri complete de temperatura. Temperatura medie anuala: 77 grade Celsius. Amplitudinea termica maxima: 318 grade. Umiditatea relativa medie: 403 procente. Concentratia de CO2: 178 ppm. Curentul de aer maxim masurat: 3 metri pe secunda. Directia predominanta a curentului: sector 360. Datalogerul a functionat 471 zile fara intrerupere. Am descarcat 215 megabytes de date brute. Presiunea barometrica la intrare: 65 mbar. Evaporarea masurata: 482 milimetri pe luna. Am comparat datele cu 451 statii meteorologice de suprafata. Raportul complet include 412 grafice si tabele. Monitorizarea continua de 388 luni confirma stabilitatea climatica.', 'doc_existing_c4_7.txt', 714, NULL, 'text_document', 1775839974);
