INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1259, 'Document PeÈ™tera AscendentÄƒ din Guguiova #10', 'Raport conservare patrimoniu - obiectiv 337. Am evaluat starea a 264 inscriptii istorice. Dintre acestea, 392 necesita interventie urgenta. Am curatat 8 metri patrati de graffiti modern. Am instalat 238 panouri informative la intrare. Bariera de protectie acopera 193 metri liniari. Am documentat 402 urme de vandalism. Raportul a fost transmis autoritatilor locale in 167 exemplare. Am propus clasificarea a 139 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 124 persoane simultan. Am instruit 357 ghizi locali. Costul estimat al lucrarilor: 188 lei. Termenul de finalizare: 376 luni.', 'doc_existing_c4_10.txt', 604, NULL, 'text_document', 1775839974);
