INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1274, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #1', 'Raport geologic - profil 56. Stratele de calcar apartin etajului 80. Grosimea medie a stratelor este de 357 centimetri. Fisurile tectonice au un azimut predominant de 467 grade. Am recoltat 237 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 453 procente. Concretii de aragonita au fost gasite la cota 271. Varsta estimata a speleothemelor: 452 mii de ani. Depozitele clastice au o grosime de 23 centimetri. Am identificat 270 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 498 metri. Analiza XRD confirma 38 faze minerale distincte. Sectorul analizat are o lungime de 9 metri. Am realizat 323 profile transversale ale galeriei. Cutele vizibile au amplitudini de 267 centimetri.', 'doc_existing_c5_1.txt', 724, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2993, 5, 'cave', 1274, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2994, 18, 'cave_area', 1274, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1275, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #2', 'Evidenta resurse hidrologice - punctul 388. Debitul mediu masurat: 32 litri pe secunda. Am efectuat 178 masuratori in perioade diferite. Temperatura apei: 418 grade Celsius, constanta. pH-ul masurat: 340 unitati. Conductivitatea electrica: 484 microsiemensi. Am injectat 270 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 315 ore. Distanta estimata: 382 metri de conducte carstice. Nivelul maxim in sezonul ploios: 346 centimetri peste normal. Am monitorizat 414 izvoare din bazin. Volumul estimat al lacului subteran: 171 metri cubi.', 'doc_existing_c5_2.txt', 548, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2995, 5, 'cave', 1275, 1775839974);
