INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1276, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #3', 'Evidenta resurse hidrologice - punctul 106. Debitul mediu masurat: 114 litri pe secunda. Am efectuat 349 masuratori in perioade diferite. Temperatura apei: 314 grade Celsius, constanta. pH-ul masurat: 415 unitati. Conductivitatea electrica: 107 microsiemensi. Am injectat 388 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 496 ore. Distanta estimata: 464 metri de conducte carstice. Nivelul maxim in sezonul ploios: 172 centimetri peste normal. Am monitorizat 412 izvoare din bazin. Volumul estimat al lacului subteran: 437 metri cubi.', 'doc_existing_c5_3.txt', 549, NULL, 'text_document', 1775839974);
