INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1281, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #8', 'Proces verbal intalnire club - sedinta nr. 58. Au participat 288 membri. Am discutat 369 puncte pe ordinea de zi. S-a aprobat bugetul de 252 lei pentru trimestrul urmator. Am planificat 457 expeditii in urmatoarele luni. S-au inscris 55 membri noi. Am evaluat 236 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 484 lei. Urmatoarea sedinta: peste 102 saptamani. Am desemnat 422 responsabili pentru proiecte.', 'doc_existing_c5_8.txt', 435, NULL, 'text_document', 1775839974);
