INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1319, 'Document PeÈ™tera B1 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 227. Am verificat 371 balize reflectorizante. Dintre acestea, 97 au fost inlocuite. Am adaugat 250 balize noi in zonele nemarcate. Distanta medie intre balize: 223 metri. Am folosit 129 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 210 metri cu lampa frontala. Am eliminat 354 marcaje vechi si confuze. Traseul total balizat: 151 metri. Urmatoarea verificare: peste 203 luni. Materialul consumat: 141 benzi reflectorizante.', 'doc_existing_c7_7.txt', 484, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3099, 7, 'cave', 1319, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3100, 284, 'cave_place', 1319, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1320, 'Document PeÈ™tera B1 din Piatra Lupului #8', 'Studiu speleogenetic - sectorul 436. Am analizat 460 probe de calcar sub microscop. Varsta estimata a galeriei: 364 milioane de ani. Am identificat 264 faze de speleogeneza. Nivelul freatic actual este la 453 metri adancime. Am corelat cu 457 alte pesteri din zona. Porozitatea medie a rocii: 63 procente. Am realizat 431 sectiuni subtiri din probe. Studiul va fi publicat in volumul 142 al buletinului. Am colaborat cu 113 geologi specialisti.', 'doc_existing_c7_8.txt', 444, NULL, 'text_document', 1775839974);
