INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1330, 'Document PeÈ™tera B1 din Piatra Lupului #18', 'Proces verbal intalnire club - sedinta nr. 427. Au participat 36 membri. Am discutat 93 puncte pe ordinea de zi. S-a aprobat bugetul de 6 lei pentru trimestrul urmator. Am planificat 288 expeditii in urmatoarele luni. S-au inscris 329 membri noi. Am evaluat 423 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 13 lei. Urmatoarea sedinta: peste 173 saptamani. Am desemnat 33 responsabili pentru proiecte.', 'doc_existing_c7_18.txt', 431, NULL, 'text_document', 1775839974);
