INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1349, 'Document PeÈ™tera B2 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 197. Am analizat 118 probe de calcar sub microscop. Varsta estimata a galeriei: 455 milioane de ani. Am identificat 206 faze de speleogeneza. Nivelul freatic actual este la 256 metri adancime. Am corelat cu 14 alte pesteri din zona. Porozitatea medie a rocii: 142 procente. Am realizat 124 sectiuni subtiri din probe. Studiul va fi publicat in volumul 333 al buletinului. Am colaborat cu 156 geologi specialisti.', 'doc_existing_c8_1.txt', 444, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3167, 8, 'cave', 1349, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3168, 34, 'cave_area', 1349, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1350, 'Document PeÈ™tera B2 din Piatra Lupului #2', 'Evidenta resurse hidrologice - punctul 205. Debitul mediu masurat: 214 litri pe secunda. Am efectuat 387 masuratori in perioade diferite. Temperatura apei: 323 grade Celsius, constanta. pH-ul masurat: 307 unitati. Conductivitatea electrica: 314 microsiemensi. Am injectat 56 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 184 ore. Distanta estimata: 25 metri de conducte carstice. Nivelul maxim in sezonul ploios: 418 centimetri peste normal. Am monitorizat 25 izvoare din bazin. Volumul estimat al lacului subteran: 105 metri cubi.', 'doc_existing_c8_2.txt', 546, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3169, 8, 'cave', 1350, 1775839974);
