INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1351, 'Document PeÈ™tera B2 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 458. Am analizat 153 probe de calcar sub microscop. Varsta estimata a galeriei: 19 milioane de ani. Am identificat 313 faze de speleogeneza. Nivelul freatic actual este la 127 metri adancime. Am corelat cu 62 alte pesteri din zona. Porozitatea medie a rocii: 21 procente. Am realizat 465 sectiuni subtiri din probe. Studiul va fi publicat in volumul 255 al buletinului. Am colaborat cu 342 geologi specialisti.', 'doc_existing_c8_3.txt', 442, NULL, 'text_document', 1775839974);
