INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1354, 'Document PeÈ™tera B2 din Piatra Lupului #6', 'Proces verbal intalnire club - sedinta nr. 42. Au participat 468 membri. Am discutat 417 puncte pe ordinea de zi. S-a aprobat bugetul de 141 lei pentru trimestrul urmator. Am planificat 109 expeditii in urmatoarele luni. S-au inscris 130 membri noi. Am evaluat 386 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 268 lei. Urmatoarea sedinta: peste 232 saptamani. Am desemnat 500 responsabili pentru proiecte.', 'doc_existing_c8_6.txt', 436, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3181, 8, 'cave', 1354, 1775839974);
