INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1355, 'Document PeÈ™tera B2 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 418. Am analizat 362 probe de calcar sub microscop. Varsta estimata a galeriei: 50 milioane de ani. Am identificat 447 faze de speleogeneza. Nivelul freatic actual este la 481 metri adancime. Am corelat cu 363 alte pesteri din zona. Porozitatea medie a rocii: 467 procente. Am realizat 415 sectiuni subtiri din probe. Studiul va fi publicat in volumul 137 al buletinului. Am colaborat cu 106 geologi specialisti.', 'doc_existing_c8_7.txt', 444, NULL, 'text_document', 1775839974);
