INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1365, 'Document PeÈ™tera B3 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 58. Am evaluat starea a 451 inscriptii istorice. Dintre acestea, 64 necesita interventie urgenta. Am curatat 38 metri patrati de graffiti modern. Am instalat 38 panouri informative la intrare. Bariera de protectie acopera 489 metri liniari. Am documentat 419 urme de vandalism. Raportul a fost transmis autoritatilor locale in 237 exemplare. Am propus clasificarea a 438 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 331 persoane simultan. Am instruit 328 ghizi locali. Costul estimat al lucrarilor: 201 lei. Termenul de finalizare: 197 luni.', 'doc_existing_c9_1.txt', 602, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3207, 9, 'cave', 1365, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3208, 40, 'cave_area', 1365, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3209, 413, 'cave_place', 1365, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1366, 'Document PeÈ™tera B3 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 141. Am verificat 14 balize reflectorizante. Dintre acestea, 319 au fost inlocuite. Am adaugat 383 balize noi in zonele nemarcate. Distanta medie intre balize: 209 metri. Am folosit 237 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 102 metri cu lampa frontala. Am eliminat 489 marcaje vechi si confuze. Traseul total balizat: 27 metri. Urmatoarea verificare: peste 457 luni. Materialul consumat: 218 benzi reflectorizante.', 'doc_existing_c9_2.txt', 483, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3210, 9, 'cave', 1366, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1367, 'Document PeÈ™tera B3 din Piatra Lupului #3', 'Raport geologic - profil 275. Stratele de calcar apartin etajului 276. Grosimea medie a stratelor este de 335 centimetri. Fisurile tectonice au un azimut predominant de 345 grade. Am recoltat 111 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 190 procente. Concretii de aragonita au fost gasite la cota 421. Varsta estimata a speleothemelor: 36 mii de ani. Depozitele clastice au o grosime de 304 centimetri. Am identificat 293 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 452 metri. Analiza XRD confirma 248 faze minerale distincte. Sectorul analizat are o lungime de 459 metri. Am realizat 148 profile transversale ale galeriei. Cutele vizibile au amplitudini de 59 centimetri.', 'doc_existing_c9_3.txt', 728, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3211, 9, 'cave', 1367, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3212, 41, 'cave_area', 1367, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1368, 'Document PeÈ™tera B3 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 218. Am analizat 77 probe de calcar sub microscop. Varsta estimata a galeriei: 82 milioane de ani. Am identificat 195 faze de speleogeneza. Nivelul freatic actual este la 489 metri adancime. Am corelat cu 114 alte pesteri din zona. Porozitatea medie a rocii: 87 procente. Am realizat 144 sectiuni subtiri din probe. Studiul va fi publicat in volumul 267 al buletinului. Am colaborat cu 395 geologi specialisti.', 'doc_existing_c9_4.txt', 442, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3213, 9, 'cave', 1368, 1775839974);
