INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1397, 'Document PeÈ™tera B4 din Piatra Lupului #10', 'Studiu speleogenetic - sectorul 86. Am analizat 136 probe de calcar sub microscop. Varsta estimata a galeriei: 106 milioane de ani. Am identificat 300 faze de speleogeneza. Nivelul freatic actual este la 419 metri adancime. Am corelat cu 265 alte pesteri din zona. Porozitatea medie a rocii: 220 procente. Am realizat 337 sectiuni subtiri din probe. Studiul va fi publicat in volumul 206 al buletinului. Am colaborat cu 341 geologi specialisti.', 'doc_existing_c10_10.txt', 444, NULL, 'text_document', 1775839974);
