INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1416, 'Document PeÈ™tera B5 din Piatra Lupului #6', 'Raport geologic - profil 190. Stratele de calcar apartin etajului 382. Grosimea medie a stratelor este de 462 centimetri. Fisurile tectonice au un azimut predominant de 316 grade. Am recoltat 118 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 187 procente. Concretii de aragonita au fost gasite la cota 30. Varsta estimata a speleothemelor: 360 mii de ani. Depozitele clastice au o grosime de 416 centimetri. Am identificat 198 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 309 metri. Analiza XRD confirma 375 faze minerale distincte. Sectorul analizat are o lungime de 454 metri. Am realizat 211 profile transversale ale galeriei. Cutele vizibile au amplitudini de 478 centimetri.', 'doc_existing_c11_6.txt', 729, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3323, 11, 'cave', 1416, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3324, 48, 'cave_area', 1416, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1417, 'Document PeÈ™tera B5 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 172. Am verificat 367 balize reflectorizante. Dintre acestea, 330 au fost inlocuite. Am adaugat 457 balize noi in zonele nemarcate. Distanta medie intre balize: 24 metri. Am folosit 192 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 422 metri cu lampa frontala. Am eliminat 274 marcaje vechi si confuze. Traseul total balizat: 119 metri. Urmatoarea verificare: peste 67 luni. Materialul consumat: 230 benzi reflectorizante.', 'doc_existing_c11_7.txt', 483, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3325, 11, 'cave', 1417, 1775839974);
