INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1419, 'Document PeÈ™tera B5 din Piatra Lupului #9', 'Studiu speleogenetic - sectorul 446. Am analizat 254 probe de calcar sub microscop. Varsta estimata a galeriei: 261 milioane de ani. Am identificat 488 faze de speleogeneza. Nivelul freatic actual este la 356 metri adancime. Am corelat cu 375 alte pesteri din zona. Porozitatea medie a rocii: 87 procente. Am realizat 81 sectiuni subtiri din probe. Studiul va fi publicat in volumul 87 al buletinului. Am colaborat cu 495 geologi specialisti.', 'doc_existing_c11_9.txt', 442, NULL, 'text_document', 1775839974);
