INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1469, 'Document PeÈ™tera C4 din Piatra Lupului #1', 'Raport geologic - profil 486. Stratele de calcar apartin etajului 387. Grosimea medie a stratelor este de 177 centimetri. Fisurile tectonice au un azimut predominant de 184 grade. Am recoltat 340 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 342 procente. Concretii de aragonita au fost gasite la cota 281. Varsta estimata a speleothemelor: 70 mii de ani. Depozitele clastice au o grosime de 148 centimetri. Am identificat 257 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 108 metri. Analiza XRD confirma 329 faze minerale distincte. Sectorul analizat are o lungime de 179 metri. Am realizat 274 profile transversale ale galeriei. Cutele vizibile au amplitudini de 485 centimetri.', 'doc_existing_c15_1.txt', 729, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3443, 15, 'cave', 1469, 1775839974);
