INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1470, 'Document PeÈ™tera C4 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 357. Adancimea: 318 metri. Am instalat 428 spituri din otel inoxidabil. Distanta intre spituri: 353 metri. Lungimea corzii principale: 234 metri. Coarda de siguranta: 304 metri. Am montat 163 protectoare de franghie. Fractionarea se face la 4 metri de buza putului. Deviatia este la 378 metri sub fractionare. Am testat echiparea cu 434 coborari. Ultimul control al spiturilor: acum 248 luni.', 'doc_existing_c15_2.txt', 434, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3445, 15, 'cave', 1470, 1775839974);
