INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1471, 'Document PeÈ™tera C4 din Piatra Lupului #3', 'Evaluare risc - sectorul 68. Am identificat 40 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 95 centimetri. Nivelul apei poate creste cu 60 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 454 metri. Am instalat 182 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 283 minute. Echipamentul de prim ajutor este pozitionat la statia 122. Am testat comunicarea radio in 498 puncte critice. Semnalul radio este pierdut dupa 50 metri de la intrare. Am recomandat echipa minima de 269 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 4 ore. Protocoalele de securitate au fost revizuite de 268 ori anul acesta. Ultimul incident a avut loc cu 481 luni in urma. Am efectuat 117 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 377.', 'doc_existing_c15_3.txt', 884, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3447, 15, 'cave', 1471, 1775839974);
