INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1472, 'Document PeÈ™tera C4 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 261. Am verificat 266 balize reflectorizante. Dintre acestea, 266 au fost inlocuite. Am adaugat 374 balize noi in zonele nemarcate. Distanta medie intre balize: 217 metri. Am folosit 93 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 215 metri cu lampa frontala. Am eliminat 415 marcaje vechi si confuze. Traseul total balizat: 389 metri. Urmatoarea verificare: peste 278 luni. Materialul consumat: 227 benzi reflectorizante.', 'doc_existing_c15_4.txt', 484, NULL, 'text_document', 1775839974);
