INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1485, 'Document PeÈ™tera C5 din Piatra Lupului #1', 'Raport climatologic subteran - statia 373. Senzorul a inregistrat 443 cicluri complete de temperatura. Temperatura medie anuala: 118 grade Celsius. Amplitudinea termica maxima: 117 grade. Umiditatea relativa medie: 250 procente. Concentratia de CO2: 346 ppm. Curentul de aer maxim masurat: 254 metri pe secunda. Directia predominanta a curentului: sector 465. Datalogerul a functionat 414 zile fara intrerupere. Am descarcat 65 megabytes de date brute. Presiunea barometrica la intrare: 48 mbar. Evaporarea masurata: 482 milimetri pe luna. Am comparat datele cu 168 statii meteorologice de suprafata. Raportul complet include 498 grafice si tabele. Monitorizarea continua de 281 luni confirma stabilitatea climatica.', 'doc_existing_c16_1.txt', 716, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3476, 16, 'cave', 1485, 1775839974);
