INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1486, 'Document PeÈ™tera C5 din Piatra Lupului #2', 'Raport climatologic subteran - statia 410. Senzorul a inregistrat 25 cicluri complete de temperatura. Temperatura medie anuala: 422 grade Celsius. Amplitudinea termica maxima: 2 grade. Umiditatea relativa medie: 475 procente. Concentratia de CO2: 136 ppm. Curentul de aer maxim masurat: 61 metri pe secunda. Directia predominanta a curentului: sector 221. Datalogerul a functionat 117 zile fara intrerupere. Am descarcat 379 megabytes de date brute. Presiunea barometrica la intrare: 111 mbar. Evaporarea masurata: 271 milimetri pe luna. Am comparat datele cu 291 statii meteorologice de suprafata. Raportul complet include 365 grafice si tabele. Monitorizarea continua de 298 luni confirma stabilitatea climatica.', 'doc_existing_c16_2.txt', 714, NULL, 'text_document', 1775839974);
