INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1488, 'Document PeÈ™tera C5 din Piatra Lupului #4', 'Proces verbal intalnire club - sedinta nr. 43. Au participat 239 membri. Am discutat 121 puncte pe ordinea de zi. S-a aprobat bugetul de 72 lei pentru trimestrul urmator. Am planificat 494 expeditii in urmatoarele luni. S-au inscris 366 membri noi. Am evaluat 460 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 342 lei. Urmatoarea sedinta: peste 358 saptamani. Am desemnat 245 responsabili pentru proiecte.', 'doc_existing_c16_4.txt', 435, NULL, 'text_document', 1775839974);
