INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1489, 'Document PeÈ™tera C5 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 19. Am evaluat starea a 430 inscriptii istorice. Dintre acestea, 203 necesita interventie urgenta. Am curatat 464 metri patrati de graffiti modern. Am instalat 392 panouri informative la intrare. Bariera de protectie acopera 486 metri liniari. Am documentat 422 urme de vandalism. Raportul a fost transmis autoritatilor locale in 198 exemplare. Am propus clasificarea a 64 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 285 persoane simultan. Am instruit 107 ghizi locali. Costul estimat al lucrarilor: 212 lei. Termenul de finalizare: 76 luni.', 'doc_existing_c16_5.txt', 603, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3485, 16, 'cave', 1489, 1775839974);
