INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1490, 'Document PeÈ™tera C5 din Piatra Lupului #6', 'Studiu speleogenetic - sectorul 331. Am analizat 152 probe de calcar sub microscop. Varsta estimata a galeriei: 301 milioane de ani. Am identificat 47 faze de speleogeneza. Nivelul freatic actual este la 317 metri adancime. Am corelat cu 329 alte pesteri din zona. Porozitatea medie a rocii: 381 procente. Am realizat 45 sectiuni subtiri din probe. Studiul va fi publicat in volumul 246 al buletinului. Am colaborat cu 264 geologi specialisti.', 'doc_existing_c16_6.txt', 443, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3487, 16, 'cave', 1490, 1775839974);
