INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1508, 'Document PeÈ™tera C6 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 456. Am analizat 217 probe de calcar sub microscop. Varsta estimata a galeriei: 387 milioane de ani. Am identificat 183 faze de speleogeneza. Nivelul freatic actual este la 259 metri adancime. Am corelat cu 284 alte pesteri din zona. Porozitatea medie a rocii: 182 procente. Am realizat 269 sectiuni subtiri din probe. Studiul va fi publicat in volumul 348 al buletinului. Am colaborat cu 14 geologi specialisti.', 'doc_existing_c17_1.txt', 444, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3526, 17, 'cave', 1508, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3527, 63, 'cave_area', 1508, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3528, 845, 'cave_place', 1508, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1509, 'Document PeÈ™tera C6 din Piatra Lupului #2', 'Raport geologic - profil 169. Stratele de calcar apartin etajului 154. Grosimea medie a stratelor este de 375 centimetri. Fisurile tectonice au un azimut predominant de 79 grade. Am recoltat 313 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 231 procente. Concretii de aragonita au fost gasite la cota 231. Varsta estimata a speleothemelor: 468 mii de ani. Depozitele clastice au o grosime de 265 centimetri. Am identificat 301 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 419 metri. Analiza XRD confirma 153 faze minerale distincte. Sectorul analizat are o lungime de 70 metri. Am realizat 265 profile transversale ale galeriei. Cutele vizibile au amplitudini de 384 centimetri.', 'doc_existing_c17_2.txt', 728, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3529, 17, 'cave', 1509, 1775839974);
