INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1514, 'Document PeÈ™tera C7 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 408. Adancimea: 301 metri. Am instalat 239 spituri din otel inoxidabil. Distanta intre spituri: 44 metri. Lungimea corzii principale: 247 metri. Coarda de siguranta: 329 metri. Am montat 188 protectoare de franghie. Fractionarea se face la 304 metri de buza putului. Deviatia este la 104 metri sub fractionare. Am testat echiparea cu 413 coborari. Ultimul control al spiturilor: acum 344 luni.', 'doc_existing_c18_1.txt', 435, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3542, 18, 'cave', 1514, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3543, 940, 'cave_place', 1514, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1515, 'Document PeÈ™tera C7 din Piatra Lupului #2', 'Raport conservare patrimoniu - obiectiv 201. Am evaluat starea a 327 inscriptii istorice. Dintre acestea, 7 necesita interventie urgenta. Am curatat 492 metri patrati de graffiti modern. Am instalat 288 panouri informative la intrare. Bariera de protectie acopera 429 metri liniari. Am documentat 378 urme de vandalism. Raportul a fost transmis autoritatilor locale in 239 exemplare. Am propus clasificarea a 374 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 317 persoane simultan. Am instruit 54 ghizi locali. Costul estimat al lucrarilor: 284 lei. Termenul de finalizare: 495 luni.', 'doc_existing_c18_2.txt', 603, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3544, 18, 'cave', 1515, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3545, 900, 'cave_place', 1515, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1516, 'Document PeÈ™tera C7 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 342. Am verificat 112 balize reflectorizante. Dintre acestea, 418 au fost inlocuite. Am adaugat 364 balize noi in zonele nemarcate. Distanta medie intre balize: 369 metri. Am folosit 438 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 377 metri cu lampa frontala. Am eliminat 271 marcaje vechi si confuze. Traseul total balizat: 254 metri. Urmatoarea verificare: peste 33 luni. Materialul consumat: 108 benzi reflectorizante.', 'doc_existing_c18_3.txt', 484, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3546, 18, 'cave', 1516, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3547, 65, 'cave_area', 1516, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3548, 916, 'cave_place', 1516, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1517, 'Document PeÈ™tera C7 din Piatra Lupului #4', 'Evidenta resurse hidrologice - punctul 392. Debitul mediu masurat: 311 litri pe secunda. Am efectuat 330 masuratori in perioade diferite. Temperatura apei: 162 grade Celsius, constanta. pH-ul masurat: 74 unitati. Conductivitatea electrica: 330 microsiemensi. Am injectat 369 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 117 ore. Distanta estimata: 83 metri de conducte carstice. Nivelul maxim in sezonul ploios: 207 centimetri peste normal. Am monitorizat 414 izvoare din bazin. Volumul estimat al lacului subteran: 113 metri cubi.', 'doc_existing_c18_4.txt', 547, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3549, 18, 'cave', 1517, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3550, 917, 'cave_place', 1517, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1518, 'Document PeÈ™tera C7 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 18. Am analizat 159 probe de calcar sub microscop. Varsta estimata a galeriei: 72 milioane de ani. Am identificat 2 faze de speleogeneza. Nivelul freatic actual este la 159 metri adancime. Am corelat cu 136 alte pesteri din zona. Porozitatea medie a rocii: 485 procente. Am realizat 217 sectiuni subtiri din probe. Studiul va fi publicat in volumul 431 al buletinului. Am colaborat cu 399 geologi specialisti.', 'doc_existing_c18_5.txt', 441, NULL, 'text_document', 1775839975);
