INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1534, 'Document PeÈ™tera C8 din Piatra Lupului #1', 'Raport geologic - profil 213. Stratele de calcar apartin etajului 46. Grosimea medie a stratelor este de 448 centimetri. Fisurile tectonice au un azimut predominant de 135 grade. Am recoltat 361 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 234 procente. Concretii de aragonita au fost gasite la cota 23. Varsta estimata a speleothemelor: 63 mii de ani. Depozitele clastice au o grosime de 7 centimetri. Am identificat 451 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 132 metri. Analiza XRD confirma 66 faze minerale distincte. Sectorul analizat are o lungime de 12 metri. Am realizat 142 profile transversale ale galeriei. Cutele vizibile au amplitudini de 5 centimetri.', 'doc_existing_c19_1.txt', 721, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3588, 19, 'cave', 1534, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3589, 70, 'cave_area', 1534, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1535, 'Document PeÈ™tera C8 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 184. Am analizat 53 probe de calcar sub microscop. Varsta estimata a galeriei: 319 milioane de ani. Am identificat 416 faze de speleogeneza. Nivelul freatic actual este la 55 metri adancime. Am corelat cu 290 alte pesteri din zona. Porozitatea medie a rocii: 205 procente. Am realizat 200 sectiuni subtiri din probe. Studiul va fi publicat in volumul 443 al buletinului. Am colaborat cu 91 geologi specialisti.', 'doc_existing_c19_2.txt', 442, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3590, 19, 'cave', 1535, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1536, 'Document PeÈ™tera C8 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 176. Adancimea: 378 metri. Am instalat 178 spituri din otel inoxidabil. Distanta intre spituri: 7 metri. Lungimea corzii principale: 301 metri. Coarda de siguranta: 106 metri. Am montat 153 protectoare de franghie. Fractionarea se face la 425 metri de buza putului. Deviatia este la 204 metri sub fractionare. Am testat echiparea cu 205 coborari. Ultimul control al spiturilor: acum 299 luni.', 'doc_existing_c19_3.txt', 434, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3591, 19, 'cave', 1536, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3592, 995, 'cave_place', 1536, 1775839975);
