INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1543, 'Document PeÈ™tera C8 din Piatra Lupului #10', 'Nota de mentenanta balize - traseul 314. Am verificat 331 balize reflectorizante. Dintre acestea, 351 au fost inlocuite. Am adaugat 338 balize noi in zonele nemarcate. Distanta medie intre balize: 29 metri. Am folosit 10 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 197 metri cu lampa frontala. Am eliminat 375 marcaje vechi si confuze. Traseul total balizat: 38 metri. Urmatoarea verificare: peste 386 luni. Materialul consumat: 316 benzi reflectorizante.', 'doc_existing_c19_10.txt', 482, NULL, 'text_document', 1775839975);
