INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1546, 'Document PeÈ™tera C8 din Piatra Lupului #13', 'Evidenta resurse hidrologice - punctul 135. Debitul mediu masurat: 30 litri pe secunda. Am efectuat 57 masuratori in perioade diferite. Temperatura apei: 487 grade Celsius, constanta. pH-ul masurat: 365 unitati. Conductivitatea electrica: 39 microsiemensi. Am injectat 152 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 312 ore. Distanta estimata: 420 metri de conducte carstice. Nivelul maxim in sezonul ploios: 306 centimetri peste normal. Am monitorizat 313 izvoare din bazin. Volumul estimat al lacului subteran: 339 metri cubi.', 'doc_existing_c19_13.txt', 546, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3615, 19, 'cave', 1546, 1775839975);
