INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3617, 1015, 'cave_place', 1546, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1547, 'Document PeÈ™tera C8 din Piatra Lupului #14', 'Proces verbal intalnire club - sedinta nr. 172. Au participat 490 membri. Am discutat 204 puncte pe ordinea de zi. S-a aprobat bugetul de 102 lei pentru trimestrul urmator. Am planificat 10 expeditii in urmatoarele luni. S-au inscris 149 membri noi. Am evaluat 493 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 17 lei. Urmatoarea sedinta: peste 498 saptamani. Am desemnat 96 responsabili pentru proiecte.', 'doc_existing_c19_14.txt', 434, NULL, 'text_document', 1775839975);
