INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1548, 'Document PeÈ™tera C8 din Piatra Lupului #15', 'Fisa tehnica echipare put - verticala nr. 62. Adancimea: 281 metri. Am instalat 254 spituri din otel inoxidabil. Distanta intre spituri: 332 metri. Lungimea corzii principale: 331 metri. Coarda de siguranta: 321 metri. Am montat 7 protectoare de franghie. Fractionarea se face la 201 metri de buza putului. Deviatia este la 340 metri sub fractionare. Am testat echiparea cu 148 coborari. Ultimul control al spiturilor: acum 387 luni.', 'doc_existing_c19_15.txt', 433, NULL, 'text_document', 1775839975);
