INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1549, 'Document PeÈ™tera C8 din Piatra Lupului #16', 'Raport conservare patrimoniu - obiectiv 487. Am evaluat starea a 45 inscriptii istorice. Dintre acestea, 59 necesita interventie urgenta. Am curatat 262 metri patrati de graffiti modern. Am instalat 447 panouri informative la intrare. Bariera de protectie acopera 6 metri liniari. Am documentat 253 urme de vandalism. Raportul a fost transmis autoritatilor locale in 135 exemplare. Am propus clasificarea a 484 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 332 persoane simultan. Am instruit 76 ghizi locali. Costul estimat al lucrarilor: 395 lei. Termenul de finalizare: 68 luni.', 'doc_existing_c19_16.txt', 600, NULL, 'text_document', 1775839975);
