INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1550, 'Document PeÈ™tera C8 din Piatra Lupului #17', 'Evidenta resurse hidrologice - punctul 188. Debitul mediu masurat: 250 litri pe secunda. Am efectuat 22 masuratori in perioade diferite. Temperatura apei: 261 grade Celsius, constanta. pH-ul masurat: 61 unitati. Conductivitatea electrica: 429 microsiemensi. Am injectat 188 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 135 ore. Distanta estimata: 299 metri de conducte carstice. Nivelul maxim in sezonul ploios: 483 centimetri peste normal. Am monitorizat 24 izvoare din bazin. Volumul estimat al lacului subteran: 488 metri cubi.', 'doc_existing_c19_17.txt', 546, NULL, 'text_document', 1775839975);
