INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1557, 'Document PeÈ™tera C9 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 190. Am verificat 99 balize reflectorizante. Dintre acestea, 337 au fost inlocuite. Am adaugat 469 balize noi in zonele nemarcate. Distanta medie intre balize: 361 metri. Am folosit 494 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 4 metri cu lampa frontala. Am eliminat 55 marcaje vechi si confuze. Traseul total balizat: 232 metri. Urmatoarea verificare: peste 384 luni. Materialul consumat: 40 benzi reflectorizante.', 'doc_existing_c20_1.txt', 480, NULL, 'text_document', 1775839975);
