INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1558, 'Document PeÈ™tera C9 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 108. Am analizat 246 probe de calcar sub microscop. Varsta estimata a galeriei: 170 milioane de ani. Am identificat 274 faze de speleogeneza. Nivelul freatic actual este la 130 metri adancime. Am corelat cu 392 alte pesteri din zona. Porozitatea medie a rocii: 386 procente. Am realizat 51 sectiuni subtiri din probe. Studiul va fi publicat in volumul 243 al buletinului. Am colaborat cu 423 geologi specialisti.', 'doc_existing_c20_2.txt', 444, NULL, 'text_document', 1775839975);
