INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1562, 'Document PeÈ™tera C9 din Piatra Lupului #6', 'Proces verbal intalnire club - sedinta nr. 34. Au participat 484 membri. Am discutat 425 puncte pe ordinea de zi. S-a aprobat bugetul de 246 lei pentru trimestrul urmator. Am planificat 386 expeditii in urmatoarele luni. S-au inscris 316 membri noi. Am evaluat 30 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 137 lei. Urmatoarea sedinta: peste 208 saptamani. Am desemnat 252 responsabili pentru proiecte.', 'doc_existing_c20_6.txt', 435, NULL, 'text_document', 1775839975);
