INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1567, 'Document PeÈ™tera C9 din Piatra Lupului #11', 'Evaluare risc - sectorul 76. Am identificat 219 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 114 centimetri. Nivelul apei poate creste cu 333 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 476 metri. Am instalat 135 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 178 minute. Echipamentul de prim ajutor este pozitionat la statia 171. Am testat comunicarea radio in 15 puncte critice. Semnalul radio este pierdut dupa 125 metri de la intrare. Am recomandat echipa minima de 279 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 86 ore. Protocoalele de securitate au fost revizuite de 7 ori anul acesta. Ultimul incident a avut loc cu 428 luni in urma. Am efectuat 99 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 291.', 'doc_existing_c20_11.txt', 885, NULL, 'text_document', 1775839975);
