INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1571, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #2', 'Studiu speleogenetic - sectorul 297. Am analizat 17 probe de calcar sub microscop. Varsta estimata a galeriei: 485 milioane de ani. Am identificat 118 faze de speleogeneza. Nivelul freatic actual este la 246 metri adancime. Am corelat cu 96 alte pesteri din zona. Porozitatea medie a rocii: 202 procente. Am realizat 106 sectiuni subtiri din probe. Studiul va fi publicat in volumul 24 al buletinului. Am colaborat cu 51 geologi specialisti.', 'doc_existing_c21_2.txt', 441, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3678, 21, 'cave', 1571, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1572, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #3', 'Raport conservare patrimoniu - obiectiv 72. Am evaluat starea a 197 inscriptii istorice. Dintre acestea, 388 necesita interventie urgenta. Am curatat 263 metri patrati de graffiti modern. Am instalat 107 panouri informative la intrare. Bariera de protectie acopera 257 metri liniari. Am documentat 142 urme de vandalism. Raportul a fost transmis autoritatilor locale in 199 exemplare. Am propus clasificarea a 326 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 395 persoane simultan. Am instruit 270 ghizi locali. Costul estimat al lucrarilor: 477 lei. Termenul de finalizare: 280 luni.', 'doc_existing_c21_3.txt', 605, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3679, 21, 'cave', 1572, 1775839975);
