INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1591, 'Document PeÈ™tera D2 din Piatra Lupului #2', 'Evaluare risc - sectorul 214. Am identificat 81 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 111 centimetri. Nivelul apei poate creste cu 403 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 177 metri. Am instalat 381 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 416 minute. Echipamentul de prim ajutor este pozitionat la statia 276. Am testat comunicarea radio in 4 puncte critice. Semnalul radio este pierdut dupa 440 metri de la intrare. Am recomandat echipa minima de 259 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 168 ore. Protocoalele de securitate au fost revizuite de 153 ori anul acesta. Ultimul incident a avut loc cu 109 luni in urma. Am efectuat 66 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 26.', 'doc_existing_c23_2.txt', 886, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3720, 23, 'cave', 1591, 1775839975);
