INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1594, 'Document PeÈ™tera D2 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 122. Am analizat 210 probe de calcar sub microscop. Varsta estimata a galeriei: 29 milioane de ani. Am identificat 484 faze de speleogeneza. Nivelul freatic actual este la 364 metri adancime. Am corelat cu 289 alte pesteri din zona. Porozitatea medie a rocii: 361 procente. Am realizat 363 sectiuni subtiri din probe. Studiul va fi publicat in volumul 383 al buletinului. Am colaborat cu 486 geologi specialisti.', 'doc_existing_c23_5.txt', 444, NULL, 'text_document', 1775839975);
