INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1598, 'Document PeÈ™tera D2 din Piatra Lupului #9', 'Raport geologic - profil 340. Stratele de calcar apartin etajului 160. Grosimea medie a stratelor este de 265 centimetri. Fisurile tectonice au un azimut predominant de 422 grade. Am recoltat 225 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 492 procente. Concretii de aragonita au fost gasite la cota 230. Varsta estimata a speleothemelor: 373 mii de ani. Depozitele clastice au o grosime de 165 centimetri. Am identificat 70 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 267 metri. Analiza XRD confirma 133 faze minerale distincte. Sectorul analizat are o lungime de 57 metri. Am realizat 422 profile transversale ale galeriei. Cutele vizibile au amplitudini de 22 centimetri.', 'doc_existing_c23_9.txt', 727, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3736, 23, 'cave', 1598, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1599, 'Document PeÈ™tera D2 din Piatra Lupului #10', 'Evidenta resurse hidrologice - punctul 455. Debitul mediu masurat: 60 litri pe secunda. Am efectuat 156 masuratori in perioade diferite. Temperatura apei: 259 grade Celsius, constanta. pH-ul masurat: 224 unitati. Conductivitatea electrica: 156 microsiemensi. Am injectat 250 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 500 ore. Distanta estimata: 333 metri de conducte carstice. Nivelul maxim in sezonul ploios: 440 centimetri peste normal. Am monitorizat 87 izvoare din bazin. Volumul estimat al lacului subteran: 367 metri cubi.', 'doc_existing_c23_10.txt', 547, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3737, 23, 'cave', 1599, 1775839975);
