INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1604, 'Document PeÈ™tera D2 din Piatra Lupului #15', 'Nota de mentenanta balize - traseul 337. Am verificat 295 balize reflectorizante. Dintre acestea, 267 au fost inlocuite. Am adaugat 407 balize noi in zonele nemarcate. Distanta medie intre balize: 254 metri. Am folosit 33 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 362 metri cu lampa frontala. Am eliminat 13 marcaje vechi si confuze. Traseul total balizat: 58 metri. Urmatoarea verificare: peste 294 luni. Materialul consumat: 494 benzi reflectorizante.', 'doc_existing_c23_15.txt', 482, NULL, 'text_document', 1775839975);
