INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1616, 'Document PeÈ™tera D3 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 492. Adancimea: 19 metri. Am instalat 1 spituri din otel inoxidabil. Distanta intre spituri: 212 metri. Lungimea corzii principale: 337 metri. Coarda de siguranta: 470 metri. Am montat 29 protectoare de franghie. Fractionarea se face la 193 metri de buza putului. Deviatia este la 153 metri sub fractionare. Am testat echiparea cu 200 coborari. Ultimul control al spiturilor: acum 82 luni.', 'doc_existing_c24_1.txt', 431, NULL, 'text_document', 1775839975);
