INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1617, 'Document PeÈ™tera D3 din Piatra Lupului #2', 'Evaluare risc - sectorul 272. Am identificat 234 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 423 centimetri. Nivelul apei poate creste cu 397 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 393 metri. Am instalat 180 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 170 minute. Echipamentul de prim ajutor este pozitionat la statia 283. Am testat comunicarea radio in 318 puncte critice. Semnalul radio este pierdut dupa 157 metri de la intrare. Am recomandat echipa minima de 24 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 412 ore. Protocoalele de securitate au fost revizuite de 463 ori anul acesta. Ultimul incident a avut loc cu 189 luni in urma. Am efectuat 485 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 389.', 'doc_existing_c24_2.txt', 890, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3780, 24, 'cave', 1617, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1618, 'Document PeÈ™tera D3 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 218. Am analizat 60 probe de calcar sub microscop. Varsta estimata a galeriei: 74 milioane de ani. Am identificat 154 faze de speleogeneza. Nivelul freatic actual este la 168 metri adancime. Am corelat cu 448 alte pesteri din zona. Porozitatea medie a rocii: 408 procente. Am realizat 438 sectiuni subtiri din probe. Studiul va fi publicat in volumul 288 al buletinului. Am colaborat cu 362 geologi specialisti.', 'doc_existing_c24_3.txt', 443, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3781, 24, 'cave', 1618, 1775839975);
