INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1619, 'Document PeÈ™tera D3 din Piatra Lupului #4', 'Evaluare risc - sectorul 458. Am identificat 431 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 12 centimetri. Nivelul apei poate creste cu 101 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 234 metri. Am instalat 350 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 77 minute. Echipamentul de prim ajutor este pozitionat la statia 207. Am testat comunicarea radio in 51 puncte critice. Semnalul radio este pierdut dupa 18 metri de la intrare. Am recomandat echipa minima de 43 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 396 ore. Protocoalele de securitate au fost revizuite de 417 ori anul acesta. Ultimul incident a avut loc cu 420 luni in urma. Am efectuat 481 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 316.', 'doc_existing_c24_4.txt', 886, NULL, 'text_document', 1775839975);
