INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1620, 'Document PeÈ™tera D3 din Piatra Lupului #5', 'Raport climatologic subteran - statia 128. Senzorul a inregistrat 356 cicluri complete de temperatura. Temperatura medie anuala: 393 grade Celsius. Amplitudinea termica maxima: 304 grade. Umiditatea relativa medie: 114 procente. Concentratia de CO2: 436 ppm. Curentul de aer maxim masurat: 240 metri pe secunda. Directia predominanta a curentului: sector 36. Datalogerul a functionat 220 zile fara intrerupere. Am descarcat 284 megabytes de date brute. Presiunea barometrica la intrare: 469 mbar. Evaporarea masurata: 94 milimetri pe luna. Am comparat datele cu 425 statii meteorologice de suprafata. Raportul complet include 197 grafice si tabele. Monitorizarea continua de 398 luni confirma stabilitatea climatica.', 'doc_existing_c24_5.txt', 716, NULL, 'text_document', 1775839975);
