INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1629, 'Document PeÈ™tera D3 din Piatra Lupului #14', 'Proces verbal intalnire club - sedinta nr. 357. Au participat 29 membri. Am discutat 38 puncte pe ordinea de zi. S-a aprobat bugetul de 288 lei pentru trimestrul urmator. Am planificat 491 expeditii in urmatoarele luni. S-au inscris 296 membri noi. Am evaluat 426 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 381 lei. Urmatoarea sedinta: peste 446 saptamani. Am desemnat 349 responsabili pentru proiecte.', 'doc_existing_c24_14.txt', 435, NULL, 'text_document', 1775839975);
