INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1648, 'Document PeÈ™tera M1 din Piatra Lupului #1', 'Evaluare risc - sectorul 76. Am identificat 408 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 161 centimetri. Nivelul apei poate creste cu 189 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 170 metri. Am instalat 203 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 222 minute. Echipamentul de prim ajutor este pozitionat la statia 37. Am testat comunicarea radio in 395 puncte critice. Semnalul radio este pierdut dupa 96 metri de la intrare. Am recomandat echipa minima de 444 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 389 ore. Protocoalele de securitate au fost revizuite de 271 ori anul acesta. Ultimul incident a avut loc cu 128 luni in urma. Am efectuat 440 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 156.', 'doc_existing_c25_1.txt', 888, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3856, 25, 'cave', 1648, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3857, 110, 'cave_area', 1648, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3858, 1370, 'cave_place', 1648, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1649, 'Document PeÈ™tera M1 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 73. Am analizat 203 probe de calcar sub microscop. Varsta estimata a galeriei: 199 milioane de ani. Am identificat 445 faze de speleogeneza. Nivelul freatic actual este la 118 metri adancime. Am corelat cu 481 alte pesteri din zona. Porozitatea medie a rocii: 303 procente. Am realizat 230 sectiuni subtiri din probe. Studiul va fi publicat in volumul 377 al buletinului. Am colaborat cu 18 geologi specialisti.', 'doc_existing_c25_2.txt', 443, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3859, 25, 'cave', 1649, 1775839975);
