INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1654, 'Document PeÈ™tera M2 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 471. Adancimea: 186 metri. Am instalat 49 spituri din otel inoxidabil. Distanta intre spituri: 464 metri. Lungimea corzii principale: 482 metri. Coarda de siguranta: 370 metri. Am montat 364 protectoare de franghie. Fractionarea se face la 421 metri de buza putului. Deviatia este la 25 metri sub fractionare. Am testat echiparea cu 385 coborari. Ultimul control al spiturilor: acum 39 luni.', 'doc_existing_c26_1.txt', 433, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3870, 26, 'cave', 1654, 1775839975);
