INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1662, 'Document PeÈ™tera M2 din Piatra Lupului #9', 'Raport geologic - profil 350. Stratele de calcar apartin etajului 172. Grosimea medie a stratelor este de 7 centimetri. Fisurile tectonice au un azimut predominant de 138 grade. Am recoltat 81 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 409 procente. Concretii de aragonita au fost gasite la cota 394. Varsta estimata a speleothemelor: 113 mii de ani. Depozitele clastice au o grosime de 323 centimetri. Am identificat 414 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 485 metri. Analiza XRD confirma 53 faze minerale distincte. Sectorul analizat are o lungime de 476 metri. Am realizat 85 profile transversale ale galeriei. Cutele vizibile au amplitudini de 77 centimetri.', 'doc_existing_c26_9.txt', 724, NULL, 'text_document', 1775839975);
