INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1664, 'Document PeÈ™tera M2 din Piatra Lupului #11', 'Raport conservare patrimoniu - obiectiv 458. Am evaluat starea a 327 inscriptii istorice. Dintre acestea, 28 necesita interventie urgenta. Am curatat 182 metri patrati de graffiti modern. Am instalat 69 panouri informative la intrare. Bariera de protectie acopera 228 metri liniari. Am documentat 226 urme de vandalism. Raportul a fost transmis autoritatilor locale in 35 exemplare. Am propus clasificarea a 60 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 438 persoane simultan. Am instruit 331 ghizi locali. Costul estimat al lucrarilor: 334 lei. Termenul de finalizare: 38 luni.', 'doc_existing_c26_11.txt', 601, NULL, 'text_document', 1775839975);
