INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1674, 'Document PeÈ™tera M3 din Piatra Lupului #2', 'Raport geologic - profil 242. Stratele de calcar apartin etajului 442. Grosimea medie a stratelor este de 96 centimetri. Fisurile tectonice au un azimut predominant de 215 grade. Am recoltat 2 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 326 procente. Concretii de aragonita au fost gasite la cota 211. Varsta estimata a speleothemelor: 268 mii de ani. Depozitele clastice au o grosime de 461 centimetri. Am identificat 272 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 22 metri. Analiza XRD confirma 31 faze minerale distincte. Sectorul analizat are o lungime de 358 metri. Am realizat 35 profile transversale ale galeriei. Cutele vizibile au amplitudini de 405 centimetri.', 'doc_existing_c27_2.txt', 724, NULL, 'text_document', 1775839975);
