INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1681, 'Document PeÈ™tera M3 din Piatra Lupului #9', 'Evaluare risc - sectorul 62. Am identificat 164 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 322 centimetri. Nivelul apei poate creste cu 440 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 65 metri. Am instalat 32 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 114 minute. Echipamentul de prim ajutor este pozitionat la statia 223. Am testat comunicarea radio in 220 puncte critice. Semnalul radio este pierdut dupa 245 metri de la intrare. Am recomandat echipa minima de 261 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 15 ore. Protocoalele de securitate au fost revizuite de 310 ori anul acesta. Ultimul incident a avut loc cu 58 luni in urma. Am efectuat 450 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 184.', 'doc_existing_c27_9.txt', 886, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3930, 27, 'cave', 1681, 1775839975);
