INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1686, 'Document PeÈ™tera M4 din Piatra Lupului #1', 'Evaluare risc - sectorul 304. Am identificat 96 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 194 centimetri. Nivelul apei poate creste cu 250 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 182 metri. Am instalat 454 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 41 minute. Echipamentul de prim ajutor este pozitionat la statia 60. Am testat comunicarea radio in 379 puncte critice. Semnalul radio este pierdut dupa 394 metri de la intrare. Am recomandat echipa minima de 242 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 445 ore. Protocoalele de securitate au fost revizuite de 283 ori anul acesta. Ultimul incident a avut loc cu 114 luni in urma. Am efectuat 307 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 270.', 'doc_existing_c28_1.txt', 888, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3941, 28, 'cave', 1686, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3942, 118, 'cave_area', 1686, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3943, 1645, 'cave_place', 1686, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1687, 'Document PeÈ™tera M4 din Piatra Lupului #2', 'Evidenta resurse hidrologice - punctul 347. Debitul mediu masurat: 436 litri pe secunda. Am efectuat 182 masuratori in perioade diferite. Temperatura apei: 107 grade Celsius, constanta. pH-ul masurat: 204 unitati. Conductivitatea electrica: 281 microsiemensi. Am injectat 382 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 192 ore. Distanta estimata: 431 metri de conducte carstice. Nivelul maxim in sezonul ploios: 254 centimetri peste normal. Am monitorizat 486 izvoare din bazin. Volumul estimat al lacului subteran: 160 metri cubi.', 'doc_existing_c28_2.txt', 549, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3944, 28, 'cave', 1687, 1775839975);
