INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1688, 'Document PeÈ™tera M4 din Piatra Lupului #3', 'Raport geologic - profil 317. Stratele de calcar apartin etajului 56. Grosimea medie a stratelor este de 427 centimetri. Fisurile tectonice au un azimut predominant de 14 grade. Am recoltat 57 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 217 procente. Concretii de aragonita au fost gasite la cota 490. Varsta estimata a speleothemelor: 450 mii de ani. Depozitele clastice au o grosime de 449 centimetri. Am identificat 376 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 123 metri. Analiza XRD confirma 189 faze minerale distincte. Sectorul analizat are o lungime de 92 metri. Am realizat 139 profile transversale ale galeriei. Cutele vizibile au amplitudini de 106 centimetri.', 'doc_existing_c28_3.txt', 726, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3947, 28, 'cave', 1688, 1775839975);
