INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1689, 'Document PeÈ™tera M4 din Piatra Lupului #4', 'Raport geologic - profil 142. Stratele de calcar apartin etajului 37. Grosimea medie a stratelor este de 476 centimetri. Fisurile tectonice au un azimut predominant de 228 grade. Am recoltat 94 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 277 procente. Concretii de aragonita au fost gasite la cota 407. Varsta estimata a speleothemelor: 402 mii de ani. Depozitele clastice au o grosime de 316 centimetri. Am identificat 50 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 445 metri. Analiza XRD confirma 389 faze minerale distincte. Sectorul analizat are o lungime de 227 metri. Am realizat 37 profile transversale ale galeriei. Cutele vizibile au amplitudini de 332 centimetri.', 'doc_existing_c28_4.txt', 726, NULL, 'text_document', 1775839975);
