INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1690, 'Document PeÈ™tera M4 din Piatra Lupului #5', 'Nota de mentenanta balize - traseul 4. Am verificat 19 balize reflectorizante. Dintre acestea, 223 au fost inlocuite. Am adaugat 411 balize noi in zonele nemarcate. Distanta medie intre balize: 106 metri. Am folosit 300 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 172 metri cu lampa frontala. Am eliminat 135 marcaje vechi si confuze. Traseul total balizat: 417 metri. Urmatoarea verificare: peste 338 luni. Materialul consumat: 80 benzi reflectorizante.', 'doc_existing_c28_5.txt', 481, NULL, 'text_document', 1775839975);
