INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1702, 'Document Avenul M5 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 37. Am evaluat starea a 289 inscriptii istorice. Dintre acestea, 47 necesita interventie urgenta. Am curatat 183 metri patrati de graffiti modern. Am instalat 184 panouri informative la intrare. Bariera de protectie acopera 229 metri liniari. Am documentat 125 urme de vandalism. Raportul a fost transmis autoritatilor locale in 475 exemplare. Am propus clasificarea a 36 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 152 persoane simultan. Am instruit 423 ghizi locali. Costul estimat al lucrarilor: 219 lei. Termenul de finalizare: 455 luni.', 'doc_existing_c29_1.txt', 603, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3979, 29, 'cave', 1702, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3980, 123, 'cave_area', 1702, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1703, 'Document Avenul M5 din Piatra Lupului #2', 'Raport climatologic subteran - statia 297. Senzorul a inregistrat 242 cicluri complete de temperatura. Temperatura medie anuala: 2 grade Celsius. Amplitudinea termica maxima: 473 grade. Umiditatea relativa medie: 3 procente. Concentratia de CO2: 284 ppm. Curentul de aer maxim masurat: 378 metri pe secunda. Directia predominanta a curentului: sector 461. Datalogerul a functionat 139 zile fara intrerupere. Am descarcat 430 megabytes de date brute. Presiunea barometrica la intrare: 57 mbar. Evaporarea masurata: 40 milimetri pe luna. Am comparat datele cu 148 statii meteorologice de suprafata. Raportul complet include 121 grafice si tabele. Monitorizarea continua de 320 luni confirma stabilitatea climatica.', 'doc_existing_c29_2.txt', 712, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3981, 29, 'cave', 1703, 1775839975);
