INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1705, 'Document Avenul M5 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 169. Am analizat 434 probe de calcar sub microscop. Varsta estimata a galeriei: 446 milioane de ani. Am identificat 92 faze de speleogeneza. Nivelul freatic actual este la 286 metri adancime. Am corelat cu 113 alte pesteri din zona. Porozitatea medie a rocii: 183 procente. Am realizat 340 sectiuni subtiri din probe. Studiul va fi publicat in volumul 86 al buletinului. Am colaborat cu 105 geologi specialisti.', 'doc_existing_c29_4.txt', 443, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3987, 29, 'cave', 1705, 1775839975);
