INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1709, 'Document Avenul M5 din Piatra Lupului #8', 'Nota de mentenanta balize - traseul 366. Am verificat 275 balize reflectorizante. Dintre acestea, 446 au fost inlocuite. Am adaugat 7 balize noi in zonele nemarcate. Distanta medie intre balize: 326 metri. Am folosit 483 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 399 metri cu lampa frontala. Am eliminat 165 marcaje vechi si confuze. Traseul total balizat: 127 metri. Urmatoarea verificare: peste 388 luni. Materialul consumat: 317 benzi reflectorizante.', 'doc_existing_c29_8.txt', 483, NULL, 'text_document', 1775839975);
