INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1728, 'Document Avenul X2 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 207. Am verificat 117 balize reflectorizante. Dintre acestea, 161 au fost inlocuite. Am adaugat 217 balize noi in zonele nemarcate. Distanta medie intre balize: 143 metri. Am folosit 358 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 178 metri cu lampa frontala. Am eliminat 320 marcaje vechi si confuze. Traseul total balizat: 113 metri. Urmatoarea verificare: peste 307 luni. Materialul consumat: 240 benzi reflectorizante.', 'doc_existing_c30_1.txt', 485, NULL, 'text_document', 1775839975);
