INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1729, 'Document Avenul X2 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 68. Am analizat 482 probe de calcar sub microscop. Varsta estimata a galeriei: 325 milioane de ani. Am identificat 375 faze de speleogeneza. Nivelul freatic actual este la 413 metri adancime. Am corelat cu 370 alte pesteri din zona. Porozitatea medie a rocii: 302 procente. Am realizat 93 sectiuni subtiri din probe. Studiul va fi publicat in volumul 456 al buletinului. Am colaborat cu 191 geologi specialisti.', 'doc_existing_c30_2.txt', 443, NULL, 'text_document', 1775839975);
