INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1732, 'Document Avenul X2 din Piatra Lupului #5', 'Raport climatologic subteran - statia 12. Senzorul a inregistrat 177 cicluri complete de temperatura. Temperatura medie anuala: 374 grade Celsius. Amplitudinea termica maxima: 477 grade. Umiditatea relativa medie: 461 procente. Concentratia de CO2: 85 ppm. Curentul de aer maxim masurat: 47 metri pe secunda. Directia predominanta a curentului: sector 269. Datalogerul a functionat 185 zile fara intrerupere. Am descarcat 177 megabytes de date brute. Presiunea barometrica la intrare: 347 mbar. Evaporarea masurata: 292 milimetri pe luna. Am comparat datele cu 24 statii meteorologice de suprafata. Raportul complet include 471 grafice si tabele. Monitorizarea continua de 69 luni confirma stabilitatea climatica.', 'doc_existing_c30_5.txt', 713, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4057, 30, 'cave', 1732, 1775839975);
