INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1739, 'Document PeÈ™tera X3 din Piatra Lupului #1', 'Evaluare risc - sectorul 364. Am identificat 131 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 492 centimetri. Nivelul apei poate creste cu 240 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 335 metri. Am instalat 476 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 267 minute. Echipamentul de prim ajutor este pozitionat la statia 434. Am testat comunicarea radio in 266 puncte critice. Semnalul radio este pierdut dupa 473 metri de la intrare. Am recomandat echipa minima de 269 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 229 ore. Protocoalele de securitate au fost revizuite de 460 ori anul acesta. Ultimul incident a avut loc cu 186 luni in urma. Am efectuat 190 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 236.', 'doc_existing_c31_1.txt', 891, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4075, 31, 'cave', 1739, 1775839976);
