INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1740, 'Document PeÈ™tera X3 din Piatra Lupului #2', 'Evaluare risc - sectorul 309. Am identificat 165 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 239 centimetri. Nivelul apei poate creste cu 481 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 454 metri. Am instalat 394 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 324 minute. Echipamentul de prim ajutor este pozitionat la statia 359. Am testat comunicarea radio in 272 puncte critice. Semnalul radio este pierdut dupa 92 metri de la intrare. Am recomandat echipa minima de 464 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 308 ore. Protocoalele de securitate au fost revizuite de 431 ori anul acesta. Ultimul incident a avut loc cu 319 luni in urma. Am efectuat 256 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 59.', 'doc_existing_c31_2.txt', 889, NULL, 'text_document', 1775839976);
