INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1743, 'Document PeÈ™tera X3 din Piatra Lupului #5', 'Evaluare risc - sectorul 35. Am identificat 436 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 186 centimetri. Nivelul apei poate creste cu 432 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 134 metri. Am instalat 428 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 9 minute. Echipamentul de prim ajutor este pozitionat la statia 327. Am testat comunicarea radio in 34 puncte critice. Semnalul radio este pierdut dupa 153 metri de la intrare. Am recomandat echipa minima de 42 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 9 ore. Protocoalele de securitate au fost revizuite de 468 ori anul acesta. Ultimul incident a avut loc cu 409 luni in urma. Am efectuat 297 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 213.', 'doc_existing_c31_5.txt', 884, NULL, 'text_document', 1775839976);
