INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1744, 'Document PeÈ™tera X3 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 407. Adancimea: 434 metri. Am instalat 489 spituri din otel inoxidabil. Distanta intre spituri: 273 metri. Lungimea corzii principale: 368 metri. Coarda de siguranta: 445 metri. Am montat 388 protectoare de franghie. Fractionarea se face la 202 metri de buza putului. Deviatia este la 345 metri sub fractionare. Am testat echiparea cu 250 coborari. Ultimul control al spiturilor: acum 380 luni.', 'doc_existing_c31_6.txt', 436, NULL, 'text_document', 1775839976);
