INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1748, 'Document PeÈ™tera X3 din Piatra Lupului #10', 'Nota de mentenanta balize - traseul 66. Am verificat 18 balize reflectorizante. Dintre acestea, 57 au fost inlocuite. Am adaugat 204 balize noi in zonele nemarcate. Distanta medie intre balize: 88 metri. Am folosit 90 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 449 metri cu lampa frontala. Am eliminat 418 marcaje vechi si confuze. Traseul total balizat: 12 metri. Urmatoarea verificare: peste 427 luni. Materialul consumat: 398 benzi reflectorizante.', 'doc_existing_c31_10.txt', 479, NULL, 'text_document', 1775839976);
