INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1750, 'Document PeÈ™tera X3 din Piatra Lupului #12', 'Evaluare risc - sectorul 275. Am identificat 6 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 100 centimetri. Nivelul apei poate creste cu 342 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 298 metri. Am instalat 235 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 118 minute. Echipamentul de prim ajutor este pozitionat la statia 180. Am testat comunicarea radio in 110 puncte critice. Semnalul radio este pierdut dupa 214 metri de la intrare. Am recomandat echipa minima de 153 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 297 ore. Protocoalele de securitate au fost revizuite de 128 ori anul acesta. Ultimul incident a avut loc cu 338 luni in urma. Am efectuat 477 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 437.', 'doc_existing_c31_12.txt', 889, NULL, 'text_document', 1775839976);
