INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1755, 'Document PeÈ™tera X3 din Piatra Lupului #17', 'Raport geologic - profil 408. Stratele de calcar apartin etajului 497. Grosimea medie a stratelor este de 427 centimetri. Fisurile tectonice au un azimut predominant de 89 grade. Am recoltat 247 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 373 procente. Concretii de aragonita au fost gasite la cota 160. Varsta estimata a speleothemelor: 23 mii de ani. Depozitele clastice au o grosime de 446 centimetri. Am identificat 137 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 108 metri. Analiza XRD confirma 381 faze minerale distincte. Sectorul analizat are o lungime de 178 metri. Am realizat 320 profile transversale ale galeriei. Cutele vizibile au amplitudini de 370 centimetri.', 'doc_existing_c31_17.txt', 728, NULL, 'text_document', 1775839976);
