INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1756, 'Document PeÈ™tera X3 din Piatra Lupului #18', 'Raport climatologic subteran - statia 198. Senzorul a inregistrat 324 cicluri complete de temperatura. Temperatura medie anuala: 416 grade Celsius. Amplitudinea termica maxima: 427 grade. Umiditatea relativa medie: 211 procente. Concentratia de CO2: 215 ppm. Curentul de aer maxim masurat: 473 metri pe secunda. Directia predominanta a curentului: sector 416. Datalogerul a functionat 482 zile fara intrerupere. Am descarcat 31 megabytes de date brute. Presiunea barometrica la intrare: 61 mbar. Evaporarea masurata: 59 milimetri pe luna. Am comparat datele cu 122 statii meteorologice de suprafata. Raportul complet include 17 grafice si tabele. Monitorizarea continua de 22 luni confirma stabilitatea climatica.', 'doc_existing_c31_18.txt', 713, NULL, 'text_document', 1775839976);
