INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1780, 'Document PeÈ™tera X6 din Piatra Lupului #1', 'Proces verbal intalnire club - sedinta nr. 119. Au participat 77 membri. Am discutat 200 puncte pe ordinea de zi. S-a aprobat bugetul de 205 lei pentru trimestrul urmator. Am planificat 446 expeditii in urmatoarele luni. S-au inscris 461 membri noi. Am evaluat 455 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 358 lei. Urmatoarea sedinta: peste 472 saptamani. Am desemnat 130 responsabili pentru proiecte.', 'doc_existing_c33_1.txt', 436, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4174, 33, 'cave', 1780, 1775839976);
