INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1781, 'Document PeÈ™tera X6 din Piatra Lupului #2', 'Raport conservare patrimoniu - obiectiv 376. Am evaluat starea a 142 inscriptii istorice. Dintre acestea, 276 necesita interventie urgenta. Am curatat 39 metri patrati de graffiti modern. Am instalat 47 panouri informative la intrare. Bariera de protectie acopera 160 metri liniari. Am documentat 179 urme de vandalism. Raportul a fost transmis autoritatilor locale in 123 exemplare. Am propus clasificarea a 50 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 91 persoane simultan. Am instruit 65 ghizi locali. Costul estimat al lucrarilor: 336 lei. Termenul de finalizare: 222 luni.', 'doc_existing_c33_2.txt', 601, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4176, 33, 'cave', 1781, 1775839976);
