INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1783, 'Document PeÈ™tera X6 din Piatra Lupului #4', 'Raport climatologic subteran - statia 464. Senzorul a inregistrat 291 cicluri complete de temperatura. Temperatura medie anuala: 229 grade Celsius. Amplitudinea termica maxima: 217 grade. Umiditatea relativa medie: 111 procente. Concentratia de CO2: 158 ppm. Curentul de aer maxim masurat: 226 metri pe secunda. Directia predominanta a curentului: sector 424. Datalogerul a functionat 383 zile fara intrerupere. Am descarcat 88 megabytes de date brute. Presiunea barometrica la intrare: 80 mbar. Evaporarea masurata: 273 milimetri pe luna. Am comparat datele cu 224 statii meteorologice de suprafata. Raportul complet include 208 grafice si tabele. Monitorizarea continua de 374 luni confirma stabilitatea climatica.', 'doc_existing_c33_4.txt', 716, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4182, 33, 'cave', 1783, 1775839976);
