INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1784, 'Document PeÈ™tera X6 din Piatra Lupului #5', 'Evidenta resurse hidrologice - punctul 441. Debitul mediu masurat: 22 litri pe secunda. Am efectuat 148 masuratori in perioade diferite. Temperatura apei: 354 grade Celsius, constanta. pH-ul masurat: 44 unitati. Conductivitatea electrica: 422 microsiemensi. Am injectat 448 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 271 ore. Distanta estimata: 496 metri de conducte carstice. Nivelul maxim in sezonul ploios: 372 centimetri peste normal. Am monitorizat 56 izvoare din bazin. Volumul estimat al lacului subteran: 329 metri cubi.', 'doc_existing_c33_5.txt', 546, NULL, 'text_document', 1775839976);
