INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1785, 'Document PeÈ™tera X6 din Piatra Lupului #6', 'Nota de mentenanta balize - traseul 108. Am verificat 286 balize reflectorizante. Dintre acestea, 131 au fost inlocuite. Am adaugat 155 balize noi in zonele nemarcate. Distanta medie intre balize: 163 metri. Am folosit 415 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 214 metri cu lampa frontala. Am eliminat 245 marcaje vechi si confuze. Traseul total balizat: 165 metri. Urmatoarea verificare: peste 417 luni. Materialul consumat: 433 benzi reflectorizante.', 'doc_existing_c33_6.txt', 485, NULL, 'text_document', 1775839976);
