INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1786, 'Document PeÈ™tera X6 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 216. Am analizat 109 probe de calcar sub microscop. Varsta estimata a galeriei: 46 milioane de ani. Am identificat 266 faze de speleogeneza. Nivelul freatic actual este la 49 metri adancime. Am corelat cu 409 alte pesteri din zona. Porozitatea medie a rocii: 360 procente. Am realizat 447 sectiuni subtiri din probe. Studiul va fi publicat in volumul 241 al buletinului. Am colaborat cu 305 geologi specialisti.', 'doc_existing_c33_7.txt', 443, NULL, 'text_document', 1775839976);
