INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1797, 'Document PeÈ™tera X8 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 35. Am analizat 225 probe de calcar sub microscop. Varsta estimata a galeriei: 132 milioane de ani. Am identificat 145 faze de speleogeneza. Nivelul freatic actual este la 49 metri adancime. Am corelat cu 451 alte pesteri din zona. Porozitatea medie a rocii: 208 procente. Am realizat 112 sectiuni subtiri din probe. Studiul va fi publicat in volumul 56 al buletinului. Am colaborat cu 224 geologi specialisti.', 'doc_existing_c35_1.txt', 442, NULL, 'text_document', 1775839976);
