INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1799, 'Document PeÈ™tera X8 din Piatra Lupului #3', 'Evaluare risc - sectorul 322. Am identificat 110 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 108 centimetri. Nivelul apei poate creste cu 209 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 212 metri. Am instalat 295 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 51 minute. Echipamentul de prim ajutor este pozitionat la statia 281. Am testat comunicarea radio in 392 puncte critice. Semnalul radio este pierdut dupa 148 metri de la intrare. Am recomandat echipa minima de 58 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 185 ore. Protocoalele de securitate au fost revizuite de 481 ori anul acesta. Ultimul incident a avut loc cu 241 luni in urma. Am efectuat 386 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 290.', 'doc_existing_c35_3.txt', 889, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4218, 35, 'cave', 1799, 1775839976);
