INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1804, 'Document PeÈ™tera X8 din Piatra Lupului #8', 'Evidenta resurse hidrologice - punctul 352. Debitul mediu masurat: 350 litri pe secunda. Am efectuat 108 masuratori in perioade diferite. Temperatura apei: 111 grade Celsius, constanta. pH-ul masurat: 489 unitati. Conductivitatea electrica: 75 microsiemensi. Am injectat 342 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 220 ore. Distanta estimata: 408 metri de conducte carstice. Nivelul maxim in sezonul ploios: 437 centimetri peste normal. Am monitorizat 412 izvoare din bazin. Volumul estimat al lacului subteran: 103 metri cubi.', 'doc_existing_c35_8.txt', 548, NULL, 'text_document', 1775839976);
