INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1806, 'Document PeÈ™tera X8 din Piatra Lupului #10', 'Raport conservare patrimoniu - obiectiv 474. Am evaluat starea a 391 inscriptii istorice. Dintre acestea, 283 necesita interventie urgenta. Am curatat 440 metri patrati de graffiti modern. Am instalat 36 panouri informative la intrare. Bariera de protectie acopera 86 metri liniari. Am documentat 336 urme de vandalism. Raportul a fost transmis autoritatilor locale in 455 exemplare. Am propus clasificarea a 77 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 193 persoane simultan. Am instruit 244 ghizi locali. Costul estimat al lucrarilor: 201 lei. Termenul de finalizare: 386 luni.', 'doc_existing_c35_10.txt', 603, NULL, 'text_document', 1775839976);
