INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1807, 'Document PeÈ™tera X8 din Piatra Lupului #11', 'Proces verbal intalnire club - sedinta nr. 432. Au participat 491 membri. Am discutat 442 puncte pe ordinea de zi. S-a aprobat bugetul de 254 lei pentru trimestrul urmator. Am planificat 25 expeditii in urmatoarele luni. S-au inscris 396 membri noi. Am evaluat 14 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 76 lei. Urmatoarea sedinta: peste 203 saptamani. Am desemnat 353 responsabili pentru proiecte.', 'doc_existing_c35_11.txt', 434, NULL, 'text_document', 1775839976);
