INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1845, 'Document PeÈ™tera E1 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 406. Debitul mediu masurat: 309 litri pe secunda. Am efectuat 437 masuratori in perioade diferite. Temperatura apei: 246 grade Celsius, constanta. pH-ul masurat: 19 unitati. Conductivitatea electrica: 344 microsiemensi. Am injectat 381 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 485 ore. Distanta estimata: 478 metri de conducte carstice. Nivelul maxim in sezonul ploios: 97 centimetri peste normal. Am monitorizat 389 izvoare din bazin. Volumul estimat al lacului subteran: 100 metri cubi.', 'doc_existing_c37_1.txt', 547, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4325, 37, 'cave', 1845, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4326, 2282, 'cave_place', 1845, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1846, 'Document PeÈ™tera E1 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 305. Adancimea: 152 metri. Am instalat 45 spituri din otel inoxidabil. Distanta intre spituri: 1 metri. Lungimea corzii principale: 73 metri. Coarda de siguranta: 455 metri. Am montat 68 protectoare de franghie. Fractionarea se face la 261 metri de buza putului. Deviatia este la 240 metri sub fractionare. Am testat echiparea cu 2 coborari. Ultimul control al spiturilor: acum 351 luni.', 'doc_existing_c37_2.txt', 429, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4327, 37, 'cave', 1846, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4328, 2283, 'cave_place', 1846, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1847, 'Document PeÈ™tera E1 din Piatra Lupului #3', 'Proces verbal intalnire club - sedinta nr. 159. Au participat 89 membri. Am discutat 111 puncte pe ordinea de zi. S-a aprobat bugetul de 491 lei pentru trimestrul urmator. Am planificat 477 expeditii in urmatoarele luni. S-au inscris 48 membri noi. Am evaluat 154 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 409 lei. Urmatoarea sedinta: peste 469 saptamani. Am desemnat 249 responsabili pentru proiecte.', 'doc_existing_c37_3.txt', 435, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4329, 37, 'cave', 1847, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4330, 164, 'cave_area', 1847, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4331, 2284, 'cave_place', 1847, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1848, 'Document PeÈ™tera E1 din Piatra Lupului #4', 'Raport geologic - profil 177. Stratele de calcar apartin etajului 133. Grosimea medie a stratelor este de 332 centimetri. Fisurile tectonice au un azimut predominant de 1 grade. Am recoltat 240 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 373 procente. Concretii de aragonita au fost gasite la cota 90. Varsta estimata a speleothemelor: 171 mii de ani. Depozitele clastice au o grosime de 158 centimetri. Am identificat 108 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 468 metri. Analiza XRD confirma 85 faze minerale distincte. Sectorul analizat are o lungime de 477 metri. Am realizat 52 profile transversale ale galeriei. Cutele vizibile au amplitudini de 285 centimetri.', 'doc_existing_c37_4.txt', 725, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4332, 37, 'cave', 1848, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4333, 162, 'cave_area', 1848, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4334, 2268, 'cave_place', 1848, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1849, 'Document PeÈ™tera E1 din Piatra Lupului #5', 'Raport climatologic subteran - statia 160. Senzorul a inregistrat 64 cicluri complete de temperatura. Temperatura medie anuala: 86 grade Celsius. Amplitudinea termica maxima: 380 grade. Umiditatea relativa medie: 276 procente. Concentratia de CO2: 206 ppm. Curentul de aer maxim masurat: 487 metri pe secunda. Directia predominanta a curentului: sector 92. Datalogerul a functionat 112 zile fara intrerupere. Am descarcat 378 megabytes de date brute. Presiunea barometrica la intrare: 23 mbar. Evaporarea masurata: 11 milimetri pe luna. Am comparat datele cu 20 statii meteorologice de suprafata. Raportul complet include 447 grafice si tabele. Monitorizarea continua de 83 luni confirma stabilitatea climatica.', 'doc_existing_c37_5.txt', 711, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4335, 37, 'cave', 1849, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4336, 162, 'cave_area', 1849, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4337, 2286, 'cave_place', 1849, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1850, 'Document PeÈ™tera E1 din Piatra Lupului #6', 'Studiu speleogenetic - sectorul 388. Am analizat 420 probe de calcar sub microscop. Varsta estimata a galeriei: 304 milioane de ani. Am identificat 449 faze de speleogeneza. Nivelul freatic actual este la 228 metri adancime. Am corelat cu 12 alte pesteri din zona. Porozitatea medie a rocii: 414 procente. Am realizat 185 sectiuni subtiri din probe. Studiul va fi publicat in volumul 41 al buletinului. Am colaborat cu 481 geologi specialisti.', 'doc_existing_c37_6.txt', 443, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4338, 37, 'cave', 1850, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4339, 2263, 'cave_place', 1850, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1851, 'Document PeÈ™tera E1 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 448. Am verificat 87 balize reflectorizante. Dintre acestea, 144 au fost inlocuite. Am adaugat 217 balize noi in zonele nemarcate. Distanta medie intre balize: 64 metri. Am folosit 307 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 262 metri cu lampa frontala. Am eliminat 49 marcaje vechi si confuze. Traseul total balizat: 187 metri. Urmatoarea verificare: peste 87 luni. Materialul consumat: 458 benzi reflectorizante.', 'doc_existing_c37_7.txt', 481, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4340, 37, 'cave', 1851, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4341, 167, 'cave_area', 1851, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4342, 2256, 'cave_place', 1851, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1852, 'Document PeÈ™tera E1 din Piatra Lupului #8', 'Evidenta resurse hidrologice - punctul 248. Debitul mediu masurat: 100 litri pe secunda. Am efectuat 155 masuratori in perioade diferite. Temperatura apei: 246 grade Celsius, constanta. pH-ul masurat: 38 unitati. Conductivitatea electrica: 258 microsiemensi. Am injectat 191 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 327 ore. Distanta estimata: 325 metri de conducte carstice. Nivelul maxim in sezonul ploios: 203 centimetri peste normal. Am monitorizat 451 izvoare din bazin. Volumul estimat al lacului subteran: 297 metri cubi.', 'doc_existing_c37_8.txt', 548, NULL, 'text_document', 1775839976);
