INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1854, 'Document PeÈ™tera E1 din Piatra Lupului #10', 'Raport conservare patrimoniu - obiectiv 22. Am evaluat starea a 67 inscriptii istorice. Dintre acestea, 382 necesita interventie urgenta. Am curatat 80 metri patrati de graffiti modern. Am instalat 315 panouri informative la intrare. Bariera de protectie acopera 433 metri liniari. Am documentat 419 urme de vandalism. Raportul a fost transmis autoritatilor locale in 408 exemplare. Am propus clasificarea a 104 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 413 persoane simultan. Am instruit 59 ghizi locali. Costul estimat al lucrarilor: 363 lei. Termenul de finalizare: 223 luni.', 'doc_existing_c37_10.txt', 602, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4348, 37, 'cave', 1854, 1775839976);
