INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1856, 'Document PeÈ™tera E1 din Piatra Lupului #12', 'Raport geologic - profil 451. Stratele de calcar apartin etajului 152. Grosimea medie a stratelor este de 376 centimetri. Fisurile tectonice au un azimut predominant de 215 grade. Am recoltat 63 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 288 procente. Concretii de aragonita au fost gasite la cota 169. Varsta estimata a speleothemelor: 308 mii de ani. Depozitele clastice au o grosime de 2 centimetri. Am identificat 498 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 107 metri. Analiza XRD confirma 324 faze minerale distincte. Sectorul analizat are o lungime de 198 metri. Am realizat 426 profile transversale ale galeriei. Cutele vizibile au amplitudini de 437 centimetri.', 'doc_existing_c37_12.txt', 727, NULL, 'text_document', 1775839976);
