INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1858, 'Document PeÈ™tera E1 din Piatra Lupului #14', 'Nota de mentenanta balize - traseul 253. Am verificat 500 balize reflectorizante. Dintre acestea, 239 au fost inlocuite. Am adaugat 314 balize noi in zonele nemarcate. Distanta medie intre balize: 224 metri. Am folosit 91 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 64 metri cu lampa frontala. Am eliminat 108 marcaje vechi si confuze. Traseul total balizat: 294 metri. Urmatoarea verificare: peste 230 luni. Materialul consumat: 6 benzi reflectorizante.', 'doc_existing_c37_14.txt', 481, NULL, 'text_document', 1775839976);
