INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1865, 'Document PeÈ™tera E3 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 46. Am analizat 253 probe de calcar sub microscop. Varsta estimata a galeriei: 78 milioane de ani. Am identificat 243 faze de speleogeneza. Nivelul freatic actual este la 422 metri adancime. Am corelat cu 297 alte pesteri din zona. Porozitatea medie a rocii: 327 procente. Am realizat 237 sectiuni subtiri din probe. Studiul va fi publicat in volumul 205 al buletinului. Am colaborat cu 307 geologi specialisti.', 'doc_existing_c38_2.txt', 443, NULL, 'text_document', 1775839976);
