INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1868, 'Document PeÈ™tera E3 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 407. Am evaluat starea a 294 inscriptii istorice. Dintre acestea, 298 necesita interventie urgenta. Am curatat 100 metri patrati de graffiti modern. Am instalat 181 panouri informative la intrare. Bariera de protectie acopera 295 metri liniari. Am documentat 428 urme de vandalism. Raportul a fost transmis autoritatilor locale in 4 exemplare. Am propus clasificarea a 207 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 283 persoane simultan. Am instruit 365 ghizi locali. Costul estimat al lucrarilor: 472 lei. Termenul de finalizare: 199 luni.', 'doc_existing_c38_5.txt', 604, NULL, 'text_document', 1775839976);
