INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1872, 'Document PeÈ™tera E3 din Piatra Lupului #9', 'Proces verbal intalnire club - sedinta nr. 34. Au participat 155 membri. Am discutat 433 puncte pe ordinea de zi. S-a aprobat bugetul de 160 lei pentru trimestrul urmator. Am planificat 265 expeditii in urmatoarele luni. S-au inscris 333 membri noi. Am evaluat 231 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 55 lei. Urmatoarea sedinta: peste 290 saptamani. Am desemnat 244 responsabili pentru proiecte.', 'doc_existing_c38_9.txt', 435, NULL, 'text_document', 1775839976);
