INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1879, 'Document PeÈ™tera E3 din Piatra Lupului #16', 'Raport geologic - profil 343. Stratele de calcar apartin etajului 332. Grosimea medie a stratelor este de 246 centimetri. Fisurile tectonice au un azimut predominant de 80 grade. Am recoltat 224 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 279 procente. Concretii de aragonita au fost gasite la cota 20. Varsta estimata a speleothemelor: 7 mii de ani. Depozitele clastice au o grosime de 442 centimetri. Am identificat 282 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 151 metri. Analiza XRD confirma 461 faze minerale distincte. Sectorul analizat are o lungime de 285 metri. Am realizat 64 profile transversale ale galeriei. Cutele vizibile au amplitudini de 324 centimetri.', 'doc_existing_c38_16.txt', 725, NULL, 'text_document', 1775839976);
