INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1899, 'Document PeÈ™tera E4 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 332. Am evaluat starea a 108 inscriptii istorice. Dintre acestea, 46 necesita interventie urgenta. Am curatat 150 metri patrati de graffiti modern. Am instalat 468 panouri informative la intrare. Bariera de protectie acopera 418 metri liniari. Am documentat 28 urme de vandalism. Raportul a fost transmis autoritatilor locale in 27 exemplare. Am propus clasificarea a 459 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 352 persoane simultan. Am instruit 406 ghizi locali. Costul estimat al lucrarilor: 240 lei. Termenul de finalizare: 83 luni.', 'doc_existing_c39_4.txt', 602, NULL, 'text_document', 1775839976);
