INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1900, 'Document PeÈ™tera E4 din Piatra Lupului #5', 'Raport geologic - profil 90. Stratele de calcar apartin etajului 253. Grosimea medie a stratelor este de 218 centimetri. Fisurile tectonice au un azimut predominant de 80 grade. Am recoltat 2 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 445 procente. Concretii de aragonita au fost gasite la cota 281. Varsta estimata a speleothemelor: 384 mii de ani. Depozitele clastice au o grosime de 135 centimetri. Am identificat 376 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 82 metri. Analiza XRD confirma 135 faze minerale distincte. Sectorul analizat are o lungime de 122 metri. Am realizat 25 profile transversale ale galeriei. Cutele vizibile au amplitudini de 377 centimetri.', 'doc_existing_c39_5.txt', 724, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4451, 39, 'cave', 1900, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4452, 2374, 'cave_place', 1900, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1901, 'Document PeÈ™tera E4 din Piatra Lupului #6', 'Nota de mentenanta balize - traseul 498. Am verificat 234 balize reflectorizante. Dintre acestea, 458 au fost inlocuite. Am adaugat 100 balize noi in zonele nemarcate. Distanta medie intre balize: 305 metri. Am folosit 257 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 191 metri cu lampa frontala. Am eliminat 402 marcaje vechi si confuze. Traseul total balizat: 57 metri. Urmatoarea verificare: peste 305 luni. Materialul consumat: 145 benzi reflectorizante.', 'doc_existing_c39_6.txt', 484, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4453, 39, 'cave', 1901, 1775839976);
