INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1902, 'Document PeÈ™tera E4 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 377. Am analizat 17 probe de calcar sub microscop. Varsta estimata a galeriei: 204 milioane de ani. Am identificat 116 faze de speleogeneza. Nivelul freatic actual este la 474 metri adancime. Am corelat cu 324 alte pesteri din zona. Porozitatea medie a rocii: 34 procente. Am realizat 245 sectiuni subtiri din probe. Studiul va fi publicat in volumul 224 al buletinului. Am colaborat cu 355 geologi specialisti.', 'doc_existing_c39_7.txt', 443, NULL, 'text_document', 1775839976);
