INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1909, 'Document PeÈ™tera E5 din Piatra Lupului #1', 'Evaluare risc - sectorul 208. Am identificat 7 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 373 centimetri. Nivelul apei poate creste cu 303 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 214 metri. Am instalat 308 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 19 minute. Echipamentul de prim ajutor este pozitionat la statia 249. Am testat comunicarea radio in 96 puncte critice. Semnalul radio este pierdut dupa 255 metri de la intrare. Am recomandat echipa minima de 457 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 373 ore. Protocoalele de securitate au fost revizuite de 60 ori anul acesta. Ultimul incident a avut loc cu 257 luni in urma. Am efectuat 151 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 193.', 'doc_existing_c40_1.txt', 886, NULL, 'text_document', 1775839976);
