INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1910, 'Document PeÈ™tera E5 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 271. Am analizat 187 probe de calcar sub microscop. Varsta estimata a galeriei: 304 milioane de ani. Am identificat 430 faze de speleogeneza. Nivelul freatic actual este la 157 metri adancime. Am corelat cu 267 alte pesteri din zona. Porozitatea medie a rocii: 236 procente. Am realizat 120 sectiuni subtiri din probe. Studiul va fi publicat in volumul 68 al buletinului. Am colaborat cu 392 geologi specialisti.', 'doc_existing_c40_2.txt', 444, NULL, 'text_document', 1775839976);
