INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1917, 'Document PeÈ™tera E6 din Piatra Lupului #1', 'Proces verbal intalnire club - sedinta nr. 350. Au participat 204 membri. Am discutat 38 puncte pe ordinea de zi. S-a aprobat bugetul de 111 lei pentru trimestrul urmator. Am planificat 7 expeditii in urmatoarele luni. S-au inscris 38 membri noi. Am evaluat 334 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 105 lei. Urmatoarea sedinta: peste 4 saptamani. Am desemnat 215 responsabili pentru proiecte.', 'doc_existing_c41_1.txt', 431, NULL, 'text_document', 1775839976);
