INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1919, 'Document PeÈ™tera E6 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 286. Am evaluat starea a 308 inscriptii istorice. Dintre acestea, 442 necesita interventie urgenta. Am curatat 136 metri patrati de graffiti modern. Am instalat 171 panouri informative la intrare. Bariera de protectie acopera 280 metri liniari. Am documentat 307 urme de vandalism. Raportul a fost transmis autoritatilor locale in 213 exemplare. Am propus clasificarea a 67 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 133 persoane simultan. Am instruit 68 ghizi locali. Costul estimat al lucrarilor: 98 lei. Termenul de finalizare: 358 luni.', 'doc_existing_c41_3.txt', 603, NULL, 'text_document', 1775839976);
