INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1929, 'Document PeÈ™tera F1 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 206. Am analizat 197 probe de calcar sub microscop. Varsta estimata a galeriei: 449 milioane de ani. Am identificat 429 faze de speleogeneza. Nivelul freatic actual este la 161 metri adancime. Am corelat cu 230 alte pesteri din zona. Porozitatea medie a rocii: 162 procente. Am realizat 494 sectiuni subtiri din probe. Studiul va fi publicat in volumul 427 al buletinului. Am colaborat cu 141 geologi specialisti.', 'doc_existing_c42_4.txt', 445, NULL, 'text_document', 1775839976);
