INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1930, 'Document PeÈ™tera F1 din Piatra Lupului #5', 'Evidenta resurse hidrologice - punctul 155. Debitul mediu masurat: 117 litri pe secunda. Am efectuat 98 masuratori in perioade diferite. Temperatura apei: 302 grade Celsius, constanta. pH-ul masurat: 428 unitati. Conductivitatea electrica: 333 microsiemensi. Am injectat 399 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 58 ore. Distanta estimata: 387 metri de conducte carstice. Nivelul maxim in sezonul ploios: 48 centimetri peste normal. Am monitorizat 409 izvoare din bazin. Volumul estimat al lacului subteran: 301 metri cubi.', 'doc_existing_c42_5.txt', 546, NULL, 'text_document', 1775839976);
