INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1931, 'Document PeÈ™tera F1 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 61. Adancimea: 6 metri. Am instalat 196 spituri din otel inoxidabil. Distanta intre spituri: 320 metri. Lungimea corzii principale: 274 metri. Coarda de siguranta: 237 metri. Am montat 132 protectoare de franghie. Fractionarea se face la 3 metri de buza putului. Deviatia este la 298 metri sub fractionare. Am testat echiparea cu 420 coborari. Ultimul control al spiturilor: acum 294 luni.', 'doc_existing_c42_6.txt', 431, NULL, 'text_document', 1775839976);
