INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1948, 'Document PeÈ™tera F2 din Piatra Lupului #6', 'Raport climatologic subteran - statia 271. Senzorul a inregistrat 132 cicluri complete de temperatura. Temperatura medie anuala: 342 grade Celsius. Amplitudinea termica maxima: 318 grade. Umiditatea relativa medie: 207 procente. Concentratia de CO2: 138 ppm. Curentul de aer maxim masurat: 376 metri pe secunda. Directia predominanta a curentului: sector 265. Datalogerul a functionat 133 zile fara intrerupere. Am descarcat 49 megabytes de date brute. Presiunea barometrica la intrare: 383 mbar. Evaporarea masurata: 259 milimetri pe luna. Am comparat datele cu 256 statii meteorologice de suprafata. Raportul complet include 19 grafice si tabele. Monitorizarea continua de 314 luni confirma stabilitatea climatica.', 'doc_existing_c43_6.txt', 716, NULL, 'text_document', 1775839976);
