INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1956, 'Document PeÈ™tera F3 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 374. Adancimea: 232 metri. Am instalat 28 spituri din otel inoxidabil. Distanta intre spituri: 155 metri. Lungimea corzii principale: 7 metri. Coarda de siguranta: 443 metri. Am montat 213 protectoare de franghie. Fractionarea se face la 339 metri de buza putului. Deviatia este la 78 metri sub fractionare. Am testat echiparea cu 10 coborari. Ultimul control al spiturilor: acum 104 luni.', 'doc_existing_c44_1.txt', 431, NULL, 'text_document', 1775839976);
