INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1957, 'Document PeÈ™tera F3 din Piatra Lupului #2', 'Raport conservare patrimoniu - obiectiv 311. Am evaluat starea a 346 inscriptii istorice. Dintre acestea, 120 necesita interventie urgenta. Am curatat 158 metri patrati de graffiti modern. Am instalat 403 panouri informative la intrare. Bariera de protectie acopera 457 metri liniari. Am documentat 175 urme de vandalism. Raportul a fost transmis autoritatilor locale in 370 exemplare. Am propus clasificarea a 378 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 152 persoane simultan. Am instruit 287 ghizi locali. Costul estimat al lucrarilor: 457 lei. Termenul de finalizare: 425 luni.', 'doc_existing_c44_2.txt', 606, NULL, 'text_document', 1775839976);
