INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1958, 'Document PeÈ™tera F3 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 132. Am verificat 445 balize reflectorizante. Dintre acestea, 20 au fost inlocuite. Am adaugat 68 balize noi in zonele nemarcate. Distanta medie intre balize: 24 metri. Am folosit 365 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 226 metri cu lampa frontala. Am eliminat 258 marcaje vechi si confuze. Traseul total balizat: 299 metri. Urmatoarea verificare: peste 99 luni. Materialul consumat: 148 benzi reflectorizante.', 'doc_existing_c44_3.txt', 481, NULL, 'text_document', 1775839976);
