INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1965, 'Document PeÈ™tera F4 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 400. Am verificat 53 balize reflectorizante. Dintre acestea, 210 au fost inlocuite. Am adaugat 174 balize noi in zonele nemarcate. Distanta medie intre balize: 101 metri. Am folosit 214 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 386 metri cu lampa frontala. Am eliminat 95 marcaje vechi si confuze. Traseul total balizat: 236 metri. Urmatoarea verificare: peste 88 luni. Materialul consumat: 426 benzi reflectorizante.', 'doc_existing_c45_3.txt', 482, NULL, 'text_document', 1775839977);
