INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1977, 'Document PeÈ™tera F5 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 92. Debitul mediu masurat: 46 litri pe secunda. Am efectuat 292 masuratori in perioade diferite. Temperatura apei: 22 grade Celsius, constanta. pH-ul masurat: 388 unitati. Conductivitatea electrica: 443 microsiemensi. Am injectat 264 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 391 ore. Distanta estimata: 209 metri de conducte carstice. Nivelul maxim in sezonul ploios: 494 centimetri peste normal. Am monitorizat 46 izvoare din bazin. Volumul estimat al lacului subteran: 332 metri cubi.', 'doc_existing_c46_1.txt', 545, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4635, 46, 'cave', 1977, 1775839977);
