INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1978, 'Document PeÈ™tera F5 din Piatra Lupului #2', 'Raport conservare patrimoniu - obiectiv 347. Am evaluat starea a 255 inscriptii istorice. Dintre acestea, 10 necesita interventie urgenta. Am curatat 499 metri patrati de graffiti modern. Am instalat 28 panouri informative la intrare. Bariera de protectie acopera 368 metri liniari. Am documentat 203 urme de vandalism. Raportul a fost transmis autoritatilor locale in 331 exemplare. Am propus clasificarea a 390 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 40 persoane simultan. Am instruit 225 ghizi locali. Costul estimat al lucrarilor: 108 lei. Termenul de finalizare: 8 luni.', 'doc_existing_c46_2.txt', 601, NULL, 'text_document', 1775839977);
