INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1980, 'Document PeÈ™tera F5 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 51. Am verificat 387 balize reflectorizante. Dintre acestea, 155 au fost inlocuite. Am adaugat 310 balize noi in zonele nemarcate. Distanta medie intre balize: 484 metri. Am folosit 141 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 223 metri cu lampa frontala. Am eliminat 158 marcaje vechi si confuze. Traseul total balizat: 233 metri. Urmatoarea verificare: peste 262 luni. Materialul consumat: 279 benzi reflectorizante.', 'doc_existing_c46_4.txt', 484, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4643, 46, 'cave', 1980, 1775839977);
