INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1981, 'Document PeÈ™tera F5 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 31. Am analizat 100 probe de calcar sub microscop. Varsta estimata a galeriei: 28 milioane de ani. Am identificat 130 faze de speleogeneza. Nivelul freatic actual este la 493 metri adancime. Am corelat cu 235 alte pesteri din zona. Porozitatea medie a rocii: 104 procente. Am realizat 89 sectiuni subtiri din probe. Studiul va fi publicat in volumul 272 al buletinului. Am colaborat cu 65 geologi specialisti.', 'doc_existing_c46_5.txt', 441, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4645, 46, 'cave', 1981, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4646, 208, 'cave_area', 1981, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1982, 'Document PeÈ™tera F5 din Piatra Lupului #6', 'Evaluare risc - sectorul 378. Am identificat 198 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 362 centimetri. Nivelul apei poate creste cu 386 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 326 metri. Am instalat 116 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 207 minute. Echipamentul de prim ajutor este pozitionat la statia 172. Am testat comunicarea radio in 217 puncte critice. Semnalul radio este pierdut dupa 361 metri de la intrare. Am recomandat echipa minima de 281 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 367 ore. Protocoalele de securitate au fost revizuite de 358 ori anul acesta. Ultimul incident a avut loc cu 212 luni in urma. Am efectuat 485 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 125.', 'doc_existing_c46_6.txt', 891, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4647, 46, 'cave', 1982, 1775839977);
