INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2014, 'Document PeÈ™tera G3 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 256. Am analizat 214 probe de calcar sub microscop. Varsta estimata a galeriei: 173 milioane de ani. Am identificat 368 faze de speleogeneza. Nivelul freatic actual este la 142 metri adancime. Am corelat cu 259 alte pesteri din zona. Porozitatea medie a rocii: 220 procente. Am realizat 299 sectiuni subtiri din probe. Studiul va fi publicat in volumul 129 al buletinului. Am colaborat cu 496 geologi specialisti.', 'doc_existing_c49_1.txt', 445, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4722, 49, 'cave', 2014, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4723, 224, 'cave_area', 2014, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4724, 3045, 'cave_place', 2014, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2015, 'Document PeÈ™tera G3 din Piatra Lupului #2', 'Raport geologic - profil 185. Stratele de calcar apartin etajului 449. Grosimea medie a stratelor este de 191 centimetri. Fisurile tectonice au un azimut predominant de 313 grade. Am recoltat 385 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 287 procente. Concretii de aragonita au fost gasite la cota 203. Varsta estimata a speleothemelor: 301 mii de ani. Depozitele clastice au o grosime de 356 centimetri. Am identificat 78 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 254 metri. Analiza XRD confirma 157 faze minerale distincte. Sectorul analizat are o lungime de 124 metri. Am realizat 156 profile transversale ale galeriei. Cutele vizibile au amplitudini de 483 centimetri.', 'doc_existing_c49_2.txt', 729, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4725, 49, 'cave', 2015, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4726, 224, 'cave_area', 2015, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4727, 3112, 'cave_place', 2015, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2016, 'Document PeÈ™tera G3 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 414. Am verificat 17 balize reflectorizante. Dintre acestea, 212 au fost inlocuite. Am adaugat 125 balize noi in zonele nemarcate. Distanta medie intre balize: 193 metri. Am folosit 341 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 315 metri cu lampa frontala. Am eliminat 384 marcaje vechi si confuze. Traseul total balizat: 70 metri. Urmatoarea verificare: peste 452 luni. Materialul consumat: 134 benzi reflectorizante.', 'doc_existing_c49_3.txt', 483, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4728, 49, 'cave', 2016, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4729, 3096, 'cave_place', 2016, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2017, 'Document PeÈ™tera G3 din Piatra Lupului #4', 'Evidenta resurse hidrologice - punctul 232. Debitul mediu masurat: 364 litri pe secunda. Am efectuat 282 masuratori in perioade diferite. Temperatura apei: 100 grade Celsius, constanta. pH-ul masurat: 425 unitati. Conductivitatea electrica: 32 microsiemensi. Am injectat 14 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 10 ore. Distanta estimata: 275 metri de conducte carstice. Nivelul maxim in sezonul ploios: 414 centimetri peste normal. Am monitorizat 365 izvoare din bazin. Volumul estimat al lacului subteran: 48 metri cubi.', 'doc_existing_c49_4.txt', 545, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4730, 49, 'cave', 2017, 1775839977);
