INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2027, 'Document PeÈ™tera G3 din Piatra Lupului #14', 'Proces verbal intalnire club - sedinta nr. 288. Au participat 146 membri. Am discutat 44 puncte pe ordinea de zi. S-a aprobat bugetul de 213 lei pentru trimestrul urmator. Am planificat 345 expeditii in urmatoarele luni. S-au inscris 49 membri noi. Am evaluat 496 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 494 lei. Urmatoarea sedinta: peste 189 saptamani. Am desemnat 197 responsabili pentru proiecte.', 'doc_existing_c49_14.txt', 435, NULL, 'text_document', 1775839977);
