INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2028, 'Document PeÈ™tera G3 din Piatra Lupului #15', 'Raport geologic - profil 70. Stratele de calcar apartin etajului 203. Grosimea medie a stratelor este de 55 centimetri. Fisurile tectonice au un azimut predominant de 185 grade. Am recoltat 82 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 236 procente. Concretii de aragonita au fost gasite la cota 43. Varsta estimata a speleothemelor: 68 mii de ani. Depozitele clastice au o grosime de 379 centimetri. Am identificat 305 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 93 metri. Analiza XRD confirma 213 faze minerale distincte. Sectorul analizat are o lungime de 286 metri. Am realizat 236 profile transversale ale galeriei. Cutele vizibile au amplitudini de 184 centimetri.', 'doc_existing_c49_15.txt', 724, NULL, 'text_document', 1775839977);
