INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2029, 'Document PeÈ™tera G3 din Piatra Lupului #16', 'Raport conservare patrimoniu - obiectiv 188. Am evaluat starea a 413 inscriptii istorice. Dintre acestea, 131 necesita interventie urgenta. Am curatat 336 metri patrati de graffiti modern. Am instalat 200 panouri informative la intrare. Bariera de protectie acopera 90 metri liniari. Am documentat 342 urme de vandalism. Raportul a fost transmis autoritatilor locale in 209 exemplare. Am propus clasificarea a 79 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 64 persoane simultan. Am instruit 444 ghizi locali. Costul estimat al lucrarilor: 68 lei. Termenul de finalizare: 110 luni.', 'doc_existing_c49_16.txt', 602, NULL, 'text_document', 1775839977);
