INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2044, 'Document PeÈ™tera H1 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 324. Debitul mediu masurat: 481 litri pe secunda. Am efectuat 47 masuratori in perioade diferite. Temperatura apei: 111 grade Celsius, constanta. pH-ul masurat: 302 unitati. Conductivitatea electrica: 92 microsiemensi. Am injectat 149 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 222 ore. Distanta estimata: 264 metri de conducte carstice. Nivelul maxim in sezonul ploios: 155 centimetri peste normal. Am monitorizat 6 izvoare din bazin. Volumul estimat al lacului subteran: 156 metri cubi.', 'doc_existing_c50_1.txt', 545, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4795, 50, 'cave', 2044, 1775839977);
