INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2048, 'Document PeÈ™tera H1 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 22. Am analizat 168 probe de calcar sub microscop. Varsta estimata a galeriei: 414 milioane de ani. Am identificat 258 faze de speleogeneza. Nivelul freatic actual este la 389 metri adancime. Am corelat cu 82 alte pesteri din zona. Porozitatea medie a rocii: 430 procente. Am realizat 182 sectiuni subtiri din probe. Studiul va fi publicat in volumul 273 al buletinului. Am colaborat cu 388 geologi specialisti.', 'doc_existing_c50_5.txt', 443, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4804, 50, 'cave', 2048, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2049, 'Document PeÈ™tera H1 din Piatra Lupului #6', 'Proces verbal intalnire club - sedinta nr. 82. Au participat 411 membri. Am discutat 487 puncte pe ordinea de zi. S-a aprobat bugetul de 412 lei pentru trimestrul urmator. Am planificat 481 expeditii in urmatoarele luni. S-au inscris 478 membri noi. Am evaluat 465 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 495 lei. Urmatoarea sedinta: peste 347 saptamani. Am desemnat 192 responsabili pentru proiecte.', 'doc_existing_c50_6.txt', 436, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4805, 50, 'cave', 2049, 1775839977);
