INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2066, 'Document PeÈ™tera H2 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 377. Am analizat 239 probe de calcar sub microscop. Varsta estimata a galeriei: 410 milioane de ani. Am identificat 76 faze de speleogeneza. Nivelul freatic actual este la 83 metri adancime. Am corelat cu 4 alte pesteri din zona. Porozitatea medie a rocii: 57 procente. Am realizat 256 sectiuni subtiri din probe. Studiul va fi publicat in volumul 294 al buletinului. Am colaborat cu 164 geologi specialisti.', 'doc_existing_c51_1.txt', 440, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4845, 51, 'cave', 2066, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4846, 235, 'cave_area', 2066, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4847, 3215, 'cave_place', 2066, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2067, 'Document PeÈ™tera H2 din Piatra Lupului #2', 'Raport climatologic subteran - statia 335. Senzorul a inregistrat 259 cicluri complete de temperatura. Temperatura medie anuala: 158 grade Celsius. Amplitudinea termica maxima: 44 grade. Umiditatea relativa medie: 125 procente. Concentratia de CO2: 200 ppm. Curentul de aer maxim masurat: 19 metri pe secunda. Directia predominanta a curentului: sector 479. Datalogerul a functionat 230 zile fara intrerupere. Am descarcat 195 megabytes de date brute. Presiunea barometrica la intrare: 96 mbar. Evaporarea masurata: 264 milimetri pe luna. Am comparat datele cu 480 statii meteorologice de suprafata. Raportul complet include 423 grafice si tabele. Monitorizarea continua de 447 luni confirma stabilitatea climatica.', 'doc_existing_c51_2.txt', 715, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4848, 51, 'cave', 2067, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4849, 3168, 'cave_place', 2067, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2068, 'Document PeÈ™tera H2 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 262. Am analizat 3 probe de calcar sub microscop. Varsta estimata a galeriei: 122 milioane de ani. Am identificat 41 faze de speleogeneza. Nivelul freatic actual este la 108 metri adancime. Am corelat cu 12 alte pesteri din zona. Porozitatea medie a rocii: 154 procente. Am realizat 121 sectiuni subtiri din probe. Studiul va fi publicat in volumul 244 al buletinului. Am colaborat cu 287 geologi specialisti.', 'doc_existing_c51_3.txt', 441, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4850, 51, 'cave', 2068, 1775839977);
