INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2069, 'Document PeÈ™tera H2 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 112. Am evaluat starea a 408 inscriptii istorice. Dintre acestea, 319 necesita interventie urgenta. Am curatat 196 metri patrati de graffiti modern. Am instalat 465 panouri informative la intrare. Bariera de protectie acopera 123 metri liniari. Am documentat 159 urme de vandalism. Raportul a fost transmis autoritatilor locale in 89 exemplare. Am propus clasificarea a 118 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 98 persoane simultan. Am instruit 238 ghizi locali. Costul estimat al lucrarilor: 396 lei. Termenul de finalizare: 415 luni.', 'doc_existing_c51_4.txt', 604, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4852, 51, 'cave', 2069, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4853, 3189, 'cave_place', 2069, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2070, 'Document PeÈ™tera H2 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 329. Am analizat 261 probe de calcar sub microscop. Varsta estimata a galeriei: 41 milioane de ani. Am identificat 399 faze de speleogeneza. Nivelul freatic actual este la 91 metri adancime. Am corelat cu 47 alte pesteri din zona. Porozitatea medie a rocii: 20 procente. Am realizat 201 sectiuni subtiri din probe. Studiul va fi publicat in volumul 497 al buletinului. Am colaborat cu 325 geologi specialisti.', 'doc_existing_c51_5.txt', 441, NULL, 'text_document', 1775839977);
