INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2071, 'Document PeÈ™tera H2 din Piatra Lupului #6', 'Evidenta resurse hidrologice - punctul 437. Debitul mediu masurat: 327 litri pe secunda. Am efectuat 138 masuratori in perioade diferite. Temperatura apei: 277 grade Celsius, constanta. pH-ul masurat: 323 unitati. Conductivitatea electrica: 60 microsiemensi. Am injectat 51 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 77 ore. Distanta estimata: 142 metri de conducte carstice. Nivelul maxim in sezonul ploios: 429 centimetri peste normal. Am monitorizat 457 izvoare din bazin. Volumul estimat al lacului subteran: 208 metri cubi.', 'doc_existing_c51_6.txt', 546, NULL, 'text_document', 1775839977);
