INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2073, 'Document PeÈ™tera H3 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 310. Adancimea: 333 metri. Am instalat 82 spituri din otel inoxidabil. Distanta intre spituri: 464 metri. Lungimea corzii principale: 359 metri. Coarda de siguranta: 188 metri. Am montat 395 protectoare de franghie. Fractionarea se face la 101 metri de buza putului. Deviatia este la 190 metri sub fractionare. Am testat echiparea cu 150 coborari. Ultimul control al spiturilor: acum 194 luni.', 'doc_existing_c52_1.txt', 435, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4863, 52, 'cave', 2073, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2074, 'Document PeÈ™tera H3 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 36. Am verificat 398 balize reflectorizante. Dintre acestea, 363 au fost inlocuite. Am adaugat 280 balize noi in zonele nemarcate. Distanta medie intre balize: 295 metri. Am folosit 497 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 485 metri cu lampa frontala. Am eliminat 310 marcaje vechi si confuze. Traseul total balizat: 245 metri. Urmatoarea verificare: peste 439 luni. Materialul consumat: 449 benzi reflectorizante.', 'doc_existing_c52_2.txt', 484, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4864, 52, 'cave', 2074, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4865, 3273, 'cave_place', 2074, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2075, 'Document PeÈ™tera H3 din Piatra Lupului #3', 'Proces verbal intalnire club - sedinta nr. 290. Au participat 487 membri. Am discutat 391 puncte pe ordinea de zi. S-a aprobat bugetul de 169 lei pentru trimestrul urmator. Am planificat 478 expeditii in urmatoarele luni. S-au inscris 74 membri noi. Am evaluat 271 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 382 lei. Urmatoarea sedinta: peste 494 saptamani. Am desemnat 89 responsabili pentru proiecte.', 'doc_existing_c52_3.txt', 435, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4866, 52, 'cave', 2075, 1775839977);
