INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2100, 'Document PeÈ™tera H4 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 180. Adancimea: 134 metri. Am instalat 255 spituri din otel inoxidabil. Distanta intre spituri: 79 metri. Lungimea corzii principale: 87 metri. Coarda de siguranta: 128 metri. Am montat 423 protectoare de franghie. Fractionarea se face la 10 metri de buza putului. Deviatia este la 248 metri sub fractionare. Am testat echiparea cu 4 coborari. Ultimul control al spiturilor: acum 287 luni.', 'doc_existing_c53_6.txt', 431, NULL, 'text_document', 1775839977);
