INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2101, 'Document PeÈ™tera H4 din Piatra Lupului #7', 'Evidenta resurse hidrologice - punctul 219. Debitul mediu masurat: 357 litri pe secunda. Am efectuat 473 masuratori in perioade diferite. Temperatura apei: 344 grade Celsius, constanta. pH-ul masurat: 12 unitati. Conductivitatea electrica: 498 microsiemensi. Am injectat 447 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 89 ore. Distanta estimata: 313 metri de conducte carstice. Nivelul maxim in sezonul ploios: 278 centimetri peste normal. Am monitorizat 289 izvoare din bazin. Volumul estimat al lacului subteran: 14 metri cubi.', 'doc_existing_c53_7.txt', 546, NULL, 'text_document', 1775839977);
