INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2103, 'Document PeÈ™tera H4 din Piatra Lupului #9', 'Fisa tehnica echipare put - verticala nr. 342. Adancimea: 146 metri. Am instalat 385 spituri din otel inoxidabil. Distanta intre spituri: 30 metri. Lungimea corzii principale: 71 metri. Coarda de siguranta: 332 metri. Am montat 237 protectoare de franghie. Fractionarea se face la 74 metri de buza putului. Deviatia este la 197 metri sub fractionare. Am testat echiparea cu 304 coborari. Ultimul control al spiturilor: acum 334 luni.', 'doc_existing_c53_9.txt', 433, NULL, 'text_document', 1775839977);
