INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2104, 'Document PeÈ™tera H4 din Piatra Lupului #10', 'Raport geologic - profil 4. Stratele de calcar apartin etajului 272. Grosimea medie a stratelor este de 91 centimetri. Fisurile tectonice au un azimut predominant de 273 grade. Am recoltat 31 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 449 procente. Concretii de aragonita au fost gasite la cota 149. Varsta estimata a speleothemelor: 5 mii de ani. Depozitele clastice au o grosime de 7 centimetri. Am identificat 391 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 309 metri. Analiza XRD confirma 350 faze minerale distincte. Sectorul analizat are o lungime de 35 metri. Am realizat 411 profile transversale ale galeriei. Cutele vizibile au amplitudini de 200 centimetri.', 'doc_existing_c53_10.txt', 721, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4932, 53, 'cave', 2104, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4933, 241, 'cave_area', 2104, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2105, 'Document PeÈ™tera H4 din Piatra Lupului #11', 'Evidenta resurse hidrologice - punctul 232. Debitul mediu masurat: 460 litri pe secunda. Am efectuat 224 masuratori in perioade diferite. Temperatura apei: 361 grade Celsius, constanta. pH-ul masurat: 473 unitati. Conductivitatea electrica: 279 microsiemensi. Am injectat 64 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 308 ore. Distanta estimata: 93 metri de conducte carstice. Nivelul maxim in sezonul ploios: 362 centimetri peste normal. Am monitorizat 3 izvoare din bazin. Volumul estimat al lacului subteran: 109 metri cubi.', 'doc_existing_c53_11.txt', 545, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4934, 53, 'cave', 2105, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4935, 242, 'cave_area', 2105, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2106, 'Document PeÈ™tera H4 din Piatra Lupului #12', 'Proces verbal intalnire club - sedinta nr. 139. Au participat 248 membri. Am discutat 414 puncte pe ordinea de zi. S-a aprobat bugetul de 125 lei pentru trimestrul urmator. Am planificat 117 expeditii in urmatoarele luni. S-au inscris 282 membri noi. Am evaluat 372 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 236 lei. Urmatoarea sedinta: peste 125 saptamani. Am desemnat 455 responsabili pentru proiecte.', 'doc_existing_c53_12.txt', 437, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4936, 53, 'cave', 2106, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4937, 241, 'cave_area', 2106, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4938, 3338, 'cave_place', 2106, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2107, 'Document PeÈ™tera H4 din Piatra Lupului #13', 'Evaluare risc - sectorul 343. Am identificat 195 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 341 centimetri. Nivelul apei poate creste cu 74 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 266 metri. Am instalat 344 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 465 minute. Echipamentul de prim ajutor este pozitionat la statia 345. Am testat comunicarea radio in 311 puncte critice. Semnalul radio este pierdut dupa 194 metri de la intrare. Am recomandat echipa minima de 104 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 50 ore. Protocoalele de securitate au fost revizuite de 184 ori anul acesta. Ultimul incident a avut loc cu 373 luni in urma. Am efectuat 3 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 289.', 'doc_existing_c53_13.txt', 887, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4939, 53, 'cave', 2107, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4940, 240, 'cave_area', 2107, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4941, 3314, 'cave_place', 2107, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2108, 'Document PeÈ™tera H4 din Piatra Lupului #14', 'Studiu speleogenetic - sectorul 136. Am analizat 167 probe de calcar sub microscop. Varsta estimata a galeriei: 411 milioane de ani. Am identificat 5 faze de speleogeneza. Nivelul freatic actual este la 316 metri adancime. Am corelat cu 162 alte pesteri din zona. Porozitatea medie a rocii: 286 procente. Am realizat 303 sectiuni subtiri din probe. Studiul va fi publicat in volumul 24 al buletinului. Am colaborat cu 293 geologi specialisti.', 'doc_existing_c53_14.txt', 442, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4942, 53, 'cave', 2108, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4943, 3347, 'cave_place', 2108, 1775839977);
