INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2135, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #1', 'Raport conservare patrimoniu - obiectiv 347. Am evaluat starea a 275 inscriptii istorice. Dintre acestea, 150 necesita interventie urgenta. Am curatat 275 metri patrati de graffiti modern. Am instalat 244 panouri informative la intrare. Bariera de protectie acopera 328 metri liniari. Am documentat 336 urme de vandalism. Raportul a fost transmis autoritatilor locale in 299 exemplare. Am propus clasificarea a 452 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 100 persoane simultan. Am instruit 463 ghizi locali. Costul estimat al lucrarilor: 1 lei. Termenul de finalizare: 87 luni.', 'doc_existing_c55_1.txt', 603, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5006, 55, 'cave', 2135, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5007, 3461, 'cave_place', 2135, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2136, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #2', 'Raport geologic - profil 489. Stratele de calcar apartin etajului 86. Grosimea medie a stratelor este de 494 centimetri. Fisurile tectonice au un azimut predominant de 280 grade. Am recoltat 458 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 417 procente. Concretii de aragonita au fost gasite la cota 112. Varsta estimata a speleothemelor: 114 mii de ani. Depozitele clastice au o grosime de 451 centimetri. Am identificat 152 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 353 metri. Analiza XRD confirma 269 faze minerale distincte. Sectorul analizat are o lungime de 126 metri. Am realizat 93 profile transversale ale galeriei. Cutele vizibile au amplitudini de 55 centimetri.', 'doc_existing_c55_2.txt', 727, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5008, 55, 'cave', 2136, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5009, 249, 'cave_area', 2136, 1775839977);
