INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2137, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #3', 'Evidenta resurse hidrologice - punctul 312. Debitul mediu masurat: 11 litri pe secunda. Am efectuat 386 masuratori in perioade diferite. Temperatura apei: 470 grade Celsius, constanta. pH-ul masurat: 162 unitati. Conductivitatea electrica: 337 microsiemensi. Am injectat 10 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 440 ore. Distanta estimata: 468 metri de conducte carstice. Nivelul maxim in sezonul ploios: 369 centimetri peste normal. Am monitorizat 24 izvoare din bazin. Volumul estimat al lacului subteran: 162 metri cubi.', 'doc_existing_c55_3.txt', 546, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5011, 55, 'cave', 2137, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2138, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #4', 'Raport conservare patrimoniu - obiectiv 26. Am evaluat starea a 253 inscriptii istorice. Dintre acestea, 412 necesita interventie urgenta. Am curatat 86 metri patrati de graffiti modern. Am instalat 376 panouri informative la intrare. Bariera de protectie acopera 9 metri liniari. Am documentat 496 urme de vandalism. Raportul a fost transmis autoritatilor locale in 349 exemplare. Am propus clasificarea a 231 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 279 persoane simultan. Am instruit 483 ghizi locali. Costul estimat al lucrarilor: 240 lei. Termenul de finalizare: 179 luni.', 'doc_existing_c55_4.txt', 602, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5012, 55, 'cave', 2138, 1775839977);
