INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2143, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #9', 'Raport climatologic subteran - statia 402. Senzorul a inregistrat 110 cicluri complete de temperatura. Temperatura medie anuala: 27 grade Celsius. Amplitudinea termica maxima: 466 grade. Umiditatea relativa medie: 258 procente. Concentratia de CO2: 473 ppm. Curentul de aer maxim masurat: 65 metri pe secunda. Directia predominanta a curentului: sector 436. Datalogerul a functionat 150 zile fara intrerupere. Am descarcat 50 megabytes de date brute. Presiunea barometrica la intrare: 223 mbar. Evaporarea masurata: 143 milimetri pe luna. Am comparat datele cu 306 statii meteorologice de suprafata. Raportul complet include 282 grafice si tabele. Monitorizarea continua de 33 luni confirma stabilitatea climatica.', 'doc_existing_c55_9.txt', 714, NULL, 'text_document', 1775839977);
