INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2145, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #11', 'Evaluare risc - sectorul 424. Am identificat 40 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 376 centimetri. Nivelul apei poate creste cu 384 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 492 metri. Am instalat 122 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 496 minute. Echipamentul de prim ajutor este pozitionat la statia 300. Am testat comunicarea radio in 64 puncte critice. Semnalul radio este pierdut dupa 416 metri de la intrare. Am recomandat echipa minima de 362 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 45 ore. Protocoalele de securitate au fost revizuite de 378 ori anul acesta. Ultimul incident a avut loc cu 213 luni in urma. Am efectuat 166 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 210.', 'doc_existing_c55_11.txt', 888, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5030, 55, 'cave', 2145, 1775839977);
