INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2150, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #16', 'Proces verbal intalnire club - sedinta nr. 287. Au participat 488 membri. Am discutat 126 puncte pe ordinea de zi. S-a aprobat bugetul de 260 lei pentru trimestrul urmator. Am planificat 177 expeditii in urmatoarele luni. S-au inscris 351 membri noi. Am evaluat 399 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 297 lei. Urmatoarea sedinta: peste 174 saptamani. Am desemnat 181 responsabili pentru proiecte.', 'doc_existing_c55_16.txt', 437, NULL, 'text_document', 1775839977);
