INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2159, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #1', 'Evidenta resurse hidrologice - punctul 474. Debitul mediu masurat: 283 litri pe secunda. Am efectuat 97 masuratori in perioade diferite. Temperatura apei: 110 grade Celsius, constanta. pH-ul masurat: 394 unitati. Conductivitatea electrica: 266 microsiemensi. Am injectat 203 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 342 ore. Distanta estimata: 47 metri de conducte carstice. Nivelul maxim in sezonul ploios: 120 centimetri peste normal. Am monitorizat 102 izvoare din bazin. Volumul estimat al lacului subteran: 221 metri cubi.', 'doc_existing_c56_1.txt', 547, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5064, 56, 'cave', 2159, 1775839977);
