INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2166, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #8', 'Nota de mentenanta balize - traseul 206. Am verificat 478 balize reflectorizante. Dintre acestea, 44 au fost inlocuite. Am adaugat 84 balize noi in zonele nemarcate. Distanta medie intre balize: 350 metri. Am folosit 111 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 248 metri cu lampa frontala. Am eliminat 58 marcaje vechi si confuze. Traseul total balizat: 323 metri. Urmatoarea verificare: peste 301 luni. Materialul consumat: 124 benzi reflectorizante.', 'doc_existing_c56_8.txt', 482, NULL, 'text_document', 1775839977);
