INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2168, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #10', 'Evaluare risc - sectorul 74. Am identificat 238 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 430 centimetri. Nivelul apei poate creste cu 62 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 416 metri. Am instalat 277 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 156 minute. Echipamentul de prim ajutor este pozitionat la statia 149. Am testat comunicarea radio in 280 puncte critice. Semnalul radio este pierdut dupa 123 metri de la intrare. Am recomandat echipa minima de 471 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 82 ore. Protocoalele de securitate au fost revizuite de 35 ori anul acesta. Ultimul incident a avut loc cu 122 luni in urma. Am efectuat 277 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 368.', 'doc_existing_c56_10.txt', 887, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5084, 56, 'cave', 2168, 1775839977);
