INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2192, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #1', 'Fisa tehnica echipare put - verticala nr. 377. Adancimea: 104 metri. Am instalat 317 spituri din otel inoxidabil. Distanta intre spituri: 23 metri. Lungimea corzii principale: 32 metri. Coarda de siguranta: 411 metri. Am montat 454 protectoare de franghie. Fractionarea se face la 145 metri de buza putului. Deviatia este la 231 metri sub fractionare. Am testat echiparea cu 270 coborari. Ultimul control al spiturilor: acum 390 luni.', 'doc_existing_c57_1.txt', 434, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5143, 57, 'cave', 2192, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5144, 3650, 'cave_place', 2192, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2193, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #2', 'Evaluare risc - sectorul 303. Am identificat 482 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 402 centimetri. Nivelul apei poate creste cu 368 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 173 metri. Am instalat 102 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 165 minute. Echipamentul de prim ajutor este pozitionat la statia 162. Am testat comunicarea radio in 351 puncte critice. Semnalul radio este pierdut dupa 391 metri de la intrare. Am recomandat echipa minima de 466 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 187 ore. Protocoalele de securitate au fost revizuite de 270 ori anul acesta. Ultimul incident a avut loc cu 10 luni in urma. Am efectuat 324 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 207.', 'doc_existing_c57_2.txt', 890, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5145, 57, 'cave', 2193, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5146, 256, 'cave_area', 2193, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5147, 3647, 'cave_place', 2193, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2194, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #3', 'Studiu speleogenetic - sectorul 196. Am analizat 166 probe de calcar sub microscop. Varsta estimata a galeriei: 199 milioane de ani. Am identificat 499 faze de speleogeneza. Nivelul freatic actual este la 343 metri adancime. Am corelat cu 1 alte pesteri din zona. Porozitatea medie a rocii: 198 procente. Am realizat 57 sectiuni subtiri din probe. Studiul va fi publicat in volumul 169 al buletinului. Am colaborat cu 23 geologi specialisti.', 'doc_existing_c57_3.txt', 441, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5148, 57, 'cave', 2194, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5149, 258, 'cave_area', 2194, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5150, 3599, 'cave_place', 2194, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2195, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #4', 'Studiu speleogenetic - sectorul 251. Am analizat 102 probe de calcar sub microscop. Varsta estimata a galeriei: 353 milioane de ani. Am identificat 464 faze de speleogeneza. Nivelul freatic actual este la 452 metri adancime. Am corelat cu 40 alte pesteri din zona. Porozitatea medie a rocii: 86 procente. Am realizat 463 sectiuni subtiri din probe. Studiul va fi publicat in volumul 358 al buletinului. Am colaborat cu 436 geologi specialisti.', 'doc_existing_c57_4.txt', 443, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5151, 57, 'cave', 2195, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5152, 261, 'cave_area', 2195, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5153, 3614, 'cave_place', 2195, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2196, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #5', 'Evaluare risc - sectorul 321. Am identificat 368 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 451 centimetri. Nivelul apei poate creste cu 278 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 51 metri. Am instalat 294 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 138 minute. Echipamentul de prim ajutor este pozitionat la statia 376. Am testat comunicarea radio in 76 puncte critice. Semnalul radio este pierdut dupa 79 metri de la intrare. Am recomandat echipa minima de 360 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 110 ore. Protocoalele de securitate au fost revizuite de 301 ori anul acesta. Ultimul incident a avut loc cu 65 luni in urma. Am efectuat 69 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 491.', 'doc_existing_c57_5.txt', 886, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5154, 57, 'cave', 2196, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5155, 3602, 'cave_place', 2196, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2197, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #6', 'Raport climatologic subteran - statia 147. Senzorul a inregistrat 173 cicluri complete de temperatura. Temperatura medie anuala: 488 grade Celsius. Amplitudinea termica maxima: 270 grade. Umiditatea relativa medie: 67 procente. Concentratia de CO2: 206 ppm. Curentul de aer maxim masurat: 33 metri pe secunda. Directia predominanta a curentului: sector 109. Datalogerul a functionat 457 zile fara intrerupere. Am descarcat 416 megabytes de date brute. Presiunea barometrica la intrare: 400 mbar. Evaporarea masurata: 227 milimetri pe luna. Am comparat datele cu 374 statii meteorologice de suprafata. Raportul complet include 140 grafice si tabele. Monitorizarea continua de 358 luni confirma stabilitatea climatica.', 'doc_existing_c57_6.txt', 716, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5156, 57, 'cave', 2197, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5157, 3621, 'cave_place', 2197, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2198, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #7', 'Studiu speleogenetic - sectorul 152. Am analizat 273 probe de calcar sub microscop. Varsta estimata a galeriei: 492 milioane de ani. Am identificat 80 faze de speleogeneza. Nivelul freatic actual este la 490 metri adancime. Am corelat cu 307 alte pesteri din zona. Porozitatea medie a rocii: 126 procente. Am realizat 183 sectiuni subtiri din probe. Studiul va fi publicat in volumul 13 al buletinului. Am colaborat cu 347 geologi specialisti.', 'doc_existing_c57_7.txt', 443, NULL, 'text_document', 1775839977);
