INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2218, 'Document PeÈ™tera CaroleÈ™tilor #1', 'Studiu speleogenetic - sectorul 436. Am analizat 488 probe de calcar sub microscop. Varsta estimata a galeriei: 164 milioane de ani. Am identificat 145 faze de speleogeneza. Nivelul freatic actual este la 415 metri adancime. Am corelat cu 285 alte pesteri din zona. Porozitatea medie a rocii: 237 procente. Am realizat 332 sectiuni subtiri din probe. Studiul va fi publicat in volumul 355 al buletinului. Am colaborat cu 73 geologi specialisti.', 'doc_existing_c58_1.txt', 444, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5204, 58, 'cave', 2218, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5205, 263, 'cave_area', 2218, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2219, 'Document PeÈ™tera CaroleÈ™tilor #2', 'Fisa tehnica echipare put - verticala nr. 408. Adancimea: 461 metri. Am instalat 346 spituri din otel inoxidabil. Distanta intre spituri: 209 metri. Lungimea corzii principale: 216 metri. Coarda de siguranta: 485 metri. Am montat 32 protectoare de franghie. Fractionarea se face la 175 metri de buza putului. Deviatia este la 82 metri sub fractionare. Am testat echiparea cu 195 coborari. Ultimul control al spiturilor: acum 361 luni.', 'doc_existing_c58_2.txt', 434, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5206, 58, 'cave', 2219, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5207, 263, 'cave_area', 2219, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5208, 3668, 'cave_place', 2219, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2220, 'Document PeÈ™tera CaroleÈ™tilor #3', 'Fisa tehnica echipare put - verticala nr. 286. Adancimea: 149 metri. Am instalat 282 spituri din otel inoxidabil. Distanta intre spituri: 175 metri. Lungimea corzii principale: 41 metri. Coarda de siguranta: 151 metri. Am montat 184 protectoare de franghie. Fractionarea se face la 127 metri de buza putului. Deviatia este la 19 metri sub fractionare. Am testat echiparea cu 247 coborari. Ultimul control al spiturilor: acum 343 luni.', 'doc_existing_c58_3.txt', 434, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5209, 58, 'cave', 2220, 1775839978);
