INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2221, 'Document PeÈ™tera CaroleÈ™tilor #4', 'Studiu speleogenetic - sectorul 57. Am analizat 13 probe de calcar sub microscop. Varsta estimata a galeriei: 230 milioane de ani. Am identificat 492 faze de speleogeneza. Nivelul freatic actual este la 306 metri adancime. Am corelat cu 314 alte pesteri din zona. Porozitatea medie a rocii: 2 procente. Am realizat 328 sectiuni subtiri din probe. Studiul va fi publicat in volumul 339 al buletinului. Am colaborat cu 335 geologi specialisti.', 'doc_existing_c58_4.txt', 441, NULL, 'text_document', 1775839978);
