INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2236, 'Document PeÈ™tera nr. 2 din Dealul Bulz #1', 'Nota de mentenanta balize - traseul 249. Am verificat 274 balize reflectorizante. Dintre acestea, 92 au fost inlocuite. Am adaugat 375 balize noi in zonele nemarcate. Distanta medie intre balize: 350 metri. Am folosit 53 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 458 metri cu lampa frontala. Am eliminat 274 marcaje vechi si confuze. Traseul total balizat: 116 metri. Urmatoarea verificare: peste 134 luni. Materialul consumat: 247 benzi reflectorizante.', 'doc_existing_c59_1.txt', 483, NULL, 'text_document', 1775839978);
