INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2238, 'Document PeÈ™tera nr. 2 din Dealul Bulz #3', 'Studiu speleogenetic - sectorul 252. Am analizat 288 probe de calcar sub microscop. Varsta estimata a galeriei: 350 milioane de ani. Am identificat 404 faze de speleogeneza. Nivelul freatic actual este la 175 metri adancime. Am corelat cu 129 alte pesteri din zona. Porozitatea medie a rocii: 364 procente. Am realizat 435 sectiuni subtiri din probe. Studiul va fi publicat in volumul 413 al buletinului. Am colaborat cu 328 geologi specialisti.', 'doc_existing_c59_3.txt', 445, NULL, 'text_document', 1775839978);
