INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2246, 'Document PeÈ™tera nr. 2 din Dealul Bulz #11', 'Raport conservare patrimoniu - obiectiv 200. Am evaluat starea a 457 inscriptii istorice. Dintre acestea, 68 necesita interventie urgenta. Am curatat 273 metri patrati de graffiti modern. Am instalat 249 panouri informative la intrare. Bariera de protectie acopera 222 metri liniari. Am documentat 227 urme de vandalism. Raportul a fost transmis autoritatilor locale in 90 exemplare. Am propus clasificarea a 134 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 433 persoane simultan. Am instruit 326 ghizi locali. Costul estimat al lucrarilor: 47 lei. Termenul de finalizare: 57 luni.', 'doc_existing_c59_11.txt', 602, NULL, 'text_document', 1775839978);
