INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2272, 'Document PeÈ™tera "Hotel" #5', 'Studiu speleogenetic - sectorul 212. Am analizat 321 probe de calcar sub microscop. Varsta estimata a galeriei: 94 milioane de ani. Am identificat 379 faze de speleogeneza. Nivelul freatic actual este la 278 metri adancime. Am corelat cu 302 alte pesteri din zona. Porozitatea medie a rocii: 146 procente. Am realizat 8 sectiuni subtiri din probe. Studiul va fi publicat in volumul 262 al buletinului. Am colaborat cu 57 geologi specialisti.', 'doc_existing_c60_5.txt', 441, NULL, 'text_document', 1775839978);
