INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2291, 'Document PeÈ™tera nr. 1 din Bulz #1', 'Raport conservare patrimoniu - obiectiv 218. Am evaluat starea a 96 inscriptii istorice. Dintre acestea, 447 necesita interventie urgenta. Am curatat 5 metri patrati de graffiti modern. Am instalat 397 panouri informative la intrare. Bariera de protectie acopera 306 metri liniari. Am documentat 206 urme de vandalism. Raportul a fost transmis autoritatilor locale in 434 exemplare. Am propus clasificarea a 147 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 353 persoane simultan. Am instruit 25 ghizi locali. Costul estimat al lucrarilor: 424 lei. Termenul de finalizare: 106 luni.', 'doc_existing_c62_1.txt', 602, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5375, 62, 'cave', 2291, 1775839978);
