INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2292, 'Document PeÈ™tera nr. 1 din Bulz #2', 'Raport conservare patrimoniu - obiectiv 448. Am evaluat starea a 26 inscriptii istorice. Dintre acestea, 319 necesita interventie urgenta. Am curatat 359 metri patrati de graffiti modern. Am instalat 104 panouri informative la intrare. Bariera de protectie acopera 305 metri liniari. Am documentat 217 urme de vandalism. Raportul a fost transmis autoritatilor locale in 110 exemplare. Am propus clasificarea a 369 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 188 persoane simultan. Am instruit 499 ghizi locali. Costul estimat al lucrarilor: 314 lei. Termenul de finalizare: 400 luni.', 'doc_existing_c62_2.txt', 605, NULL, 'text_document', 1775839978);
